import React, { useState, useEffect } from 'react';
import { Toaster, toast } from 'react-hot-toast';
import { GameArena } from './components/GameArena';
import { WordInput } from './components/WordInput';
import { Dashboard } from './components/Dashboard';
import { QuizSession } from './components/QuizSession';
import { WordData, AppState, StoredData } from './types';
import { streamVocabularyEnrichment } from './services/geminiService';

const STORAGE_KEY = 'lexiweek_data';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT);
  const [words, setWords] = useState<WordData[]>([]);
  const [cycleStart, setCycleStart] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Load Data on Mount
  useEffect(() => {
    const loadData = () => {
      try {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
          const data: StoredData = JSON.parse(stored);

          // Check for Saturday 18:00 Reset Logic
          // Calculate the next Saturday 18:00 relative to the stored cycleStart
          const start = new Date(data.cycleStart);
          const nextReset = new Date(start);
          // Move to Saturday (Day 6)
          nextReset.setDate(start.getDate() + ((6 - start.getDay() + 7) % 7));
          nextReset.setHours(18, 0, 0, 0);

          // If we are currently past the reset time of the stored cycle, verify if it's actually a new week
          // Logic: If Date.now() is past the reset time derived from cycleStart, we should probably reset IF cycleStart was last week.
          // Simplification: If the data is more than 7 days old, reset.
          const now = Date.now();
          const sevenDays = 7 * 24 * 60 * 60 * 1000;

          if (now - data.cycleStart > sevenDays) {
             // Expired
             setAppState(AppState.INPUT);
          } else {
             setWords(data.words);
             setCycleStart(data.cycleStart);
             if (data.words.length > 0) {
               setAppState(AppState.DASHBOARD);
             } else {
               setAppState(AppState.INPUT);
             }
          }
        } else {
          setAppState(AppState.INPUT);
        }
      } catch (e) {
        console.error("Failed to load data", e);
        setAppState(AppState.INPUT);
      }
    };
    loadData();
  }, []);

  // Save Data whenever words change
  useEffect(() => {
    if (words.length > 0 && cycleStart > 0) {
      const data: StoredData = { cycleStart, words };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    }
  }, [words, cycleStart]);

  const handleWordsSubmit = async (rawWords: string[]) => {
    setIsLoading(true);
    // Set cycle start to now if it's a fresh start
    const newCycleStart = Date.now();
    setCycleStart(newCycleStart);
    setWords([]); // Clear previous if any

    try {
      await streamVocabularyEnrichment(rawWords, (newWord) => {
        setWords(prev => {
          // Avoid duplicates if needed, but stream should be unique
          return [...prev, newWord];
        });
      });
      setAppState(AppState.DASHBOARD);
      toast.success('词库生成完毕！');
    } catch (error) {
      toast.error('生成失败，请检查网络或 Key 配置');
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetWeek = () => {
    if (window.confirm("确定要开始新的一周吗？这将清空当前进度。")) {
      setWords([]);
      setCycleStart(0);
      localStorage.removeItem(STORAGE_KEY);
      setAppState(AppState.INPUT);
    }
  };

  const handleUpdateWord = (id: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  };

  // Gamepad Polling for Dashboard
  useEffect(() => {
    if (appState !== AppState.DASHBOARD) return;

    let rafId: number;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Button 0 (A) -> Start Game
        if (gp.buttons[0]?.pressed && !lastButtonState) {
          setAppState(AppState.GAME);
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }
      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [appState]);

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative">
      <div className="absolute inset-0 bg-pattern opacity-10 pointer-events-none"></div>

      <div className="relative z-10 w-full h-full overflow-y-auto">
        {appState === AppState.INPUT && (
          <div className="min-h-full flex items-center justify-center p-4">
             <div className="w-full max-w-2xl">
               <WordInput 
                 onSubmit={handleWordsSubmit} 
                 isLoading={isLoading} 
                 hasExistingData={words.length > 0}
                 onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
               />
             </div>
          </div>
        )}

        {appState === AppState.DASHBOARD && (
          <div className="min-h-full flex items-center justify-center p-4">
             <div className="w-full max-w-4xl">
               <Dashboard 
                 words={words}
                 cycleStart={cycleStart}
                 onStartGame={() => setAppState(AppState.GAME)}
                 onStartQuiz={() => setAppState(AppState.QUIZ)}
                 onNewWeek={handleResetWeek}
               />
             </div>
          </div>
        )}

        {appState === AppState.GAME && (
          <GameArena 
            words={words} 
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}

        {appState === AppState.QUIZ && (
          <div className="min-h-full flex items-center justify-center bg-slate-100 text-slate-900">
             <QuizSession 
               words={words}
               onUpdateWord={handleUpdateWord}
               onComplete={() => setAppState(AppState.DASHBOARD)}
               onExit={() => setAppState(AppState.DASHBOARD)}
             />
          </div>
        )}
      </div>

      <Toaster position="top-center" toastOptions={{ style: { background: '#333', color: '#fff' } }} />
    </div>
  );
};

export default App;

