import React, { useState } from 'react';

interface WordInputProps {
  onSubmit: (words: string[]) => void;
  isLoading: boolean;
  hasExistingData: boolean;
  onCancel?: () => void;
}

const DEMO_WORDS = [
  "ephemeral", "serendipity", "resilient", "oblivion", "solitude", 
  "eloquent", "ineffable", "sonder", "limerence", "ethereal"
];

export const WordInput: React.FC<WordInputProps> = ({ onSubmit, isLoading, hasExistingData, onCancel }) => {
  const [inputText, setInputText] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    processAndSubmit(inputText);
  };

  const processAndSubmit = (text: string) => {
    const words = text
      .split(/[\n,，]+/)
      .map(w => w.trim())
      .filter(w => w.length > 0);

    if (words.length > 0) {
      onSubmit(words);
    }
  };

  const handleUseDemo = () => {
      setInputText(DEMO_WORDS.join('\n'));
      // Optional: Auto submit or just fill
      // processAndSubmit(DEMO_WORDS.join('\n')); 
  };

  return (
    <div className="bg-white/90 backdrop-blur-md shadow-2xl rounded-2xl p-6 sm:p-10 border border-white/50 animate-fade-in-up">
      <div className="text-center mb-8">
        <h1 className="text-3xl font-black text-slate-800 mb-3">每周词汇挑战</h1>
        <p className="text-slate-600">
          输入你本周想要掌握的单词。AI 将为你生成释义、例句和游戏资产。
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="relative">
          <div className="absolute top-3 right-3 z-10">
              <button 
                type="button"
                onClick={handleUseDemo}
                className="text-xs bg-slate-100 text-slate-500 hover:text-indigo-600 px-2 py-1 rounded border border-slate-200 transition-colors"
              >
                  试用 Demo 列表
              </button>
          </div>
          <textarea
            id="words"
            rows={8}
            className="w-full px-5 py-4 rounded-xl border-2 border-slate-200 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-slate-700 placeholder-slate-400 bg-white font-mono text-lg leading-relaxed resize-none"
            placeholder={`粘贴单词，例如：\n\nserendipity\nephemeral\nresilient`}
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={isLoading}
          />
        </div>

        <div className="flex flex-col sm:flex-row gap-4 pt-2">
          {hasExistingData && onCancel && (
            <button
              type="button"
              onClick={onCancel}
              className="w-full sm:flex-1 px-6 py-4 rounded-xl border-2 border-slate-200 text-slate-600 font-bold hover:bg-slate-50 transition-colors order-2 sm:order-1"
              disabled={isLoading}
            >
              返回 Dashboard
            </button>
          )}
          <button
            type="submit"
            disabled={isLoading || !inputText.trim()}
            className={`w-full sm:flex-1 px-6 py-4 rounded-xl text-white font-bold text-lg shadow-xl shadow-indigo-500/30 transition-all transform active:scale-95 order-1 sm:order-2 flex justify-center items-center
              ${isLoading || !inputText.trim() 
                ? 'bg-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:-translate-y-1'}`}
          >
            {isLoading ? (
              <>
                <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                AI 正在构建世界...
              </>
            ) : '生成本周挑战'}
          </button>
        </div>
      </form>
    </div>
  );
};

