// Queue system to process assets sequentially to avoid 429 errors
const processAssets = async (prompts: Record<string, string>, onAssetLoaded: (key: string, url: string) => void) => {
  const keys = Object.keys(prompts);

  for (const key of keys) {
    const prompt = prompts[key];

    // 1. If it's a data URI (SVG), load immediately
    if (prompt.startsWith('data:image')) {
      onAssetLoaded(key, prompt);
      continue;
    }

    // 2. Otherwise generate via API with delay
    try {
      // console.log(`Generating asset: ${key}`);
      const base64 = await generateGameAsset(prompt);
      if (base64) {
        onAssetLoaded(key, base64);
      }
    } catch (error) {
      console.error(`Failed to generate asset for ${key}`, error);
    }

    // 3. Wait 1.5 seconds between requests to be safe
    await new Promise(resolve => setTimeout(resolve, 1500));
  }
};

export const loadBasicAssets = (onAssetLoaded: (key: string, url: string) => void) => {
  // Fire and forget, but internal logic is sequential
  processAssets(BasicPrompts, onAssetLoaded);
};

export const loadAdvancedAssets = (onAssetLoaded: (key: string, url: string) => void) => {
  processAssets(AdvancedPrompts, onAssetLoaded);
};

