import React, { useState, useEffect, useRef } from 'react';
import { WordData } from '../types';
import { speakText, playSuccessSound, playErrorSound } from '../services/audioService';

interface GameQuizModalProps {
  word: WordData;
  allWords: WordData[];
  onResult: (correct: boolean) => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const GameQuizModal: React.FC<GameQuizModalProps> = ({ word, allWords, onResult }) => {
  const [mode, setMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [input, setInput] = useState('');
  const [choices, setChoices] = useState<WordData[]>([]);
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [focusedChoiceIndex, setFocusedChoiceIndex] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);

  // Track input method to prevent mouse hover from fighting with gamepad
  const lastInputMethod = useRef<'MOUSE' | 'KEYBOARD'>('KEYBOARD');

  // Input Method Tracking
  useEffect(() => {
      const handleMouseMove = () => { lastInputMethod.current = 'MOUSE'; };
      const handleKeyDown = () => { lastInputMethod.current = 'KEYBOARD'; };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('keydown', handleKeyDown);
      return () => {
          window.removeEventListener('mousemove', handleMouseMove);
          window.removeEventListener('keydown', handleKeyDown);
      };
  }, []);

  // Setup
  useEffect(() => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const selectedMode = modes[Math.floor(Math.random() * modes.length)];
    setMode(selectedMode);

    if (selectedMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (selectedMode === 'SPELL_FROM_AUDIO') {
      setTimeout(() => speakText(word.word), 300);
    }

    // Auto focus
    setTimeout(() => inputRef.current?.focus(), 100);
  }, [word, allWords]);

  // Keyboard Support for Choices
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (mode === 'MEANING_FROM_WORD' && status === 'idle') {
            if (['ArrowUp', 'ArrowLeft', 'ArrowDown', 'ArrowRight', 'Enter', ' '].includes(e.key)) {
                lastInputMethod.current = 'KEYBOARD';
            }

            if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
                 setFocusedChoiceIndex(prev => Math.max(0, prev - 1));
            }
            if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
                 setFocusedChoiceIndex(prev => Math.min(choices.length - 1, prev + 1));
            }
            if (e.key === 'Enter' || e.key === ' ') {
                if (choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [mode, status, choices, focusedChoiceIndex]);

  // Gamepad Polling for Multiple Choice
  useEffect(() => {
    if (mode !== 'MEANING_FROM_WORD' || status !== 'idle') return;

    let lastAxisY = 0;
    let lastAxisX = 0;
    let lastButtonState = false;
    let rafId: number;

    const pollGamepad = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            // Check for activity to switch input method
            const hasActivity = Math.abs(gp.axes[0]) > 0.5 || Math.abs(gp.axes[1]) > 0.5 || gp.buttons.some(b => b.pressed);
            if (hasActivity) {
                lastInputMethod.current = 'KEYBOARD'; // Gamepad counts as keyboard logic
            }

            const axisX = gp.axes[0];
            const axisY = gp.axes[1];

            // Grid is 2x2. 0,1 top row. 2,3 bottom row.

            // Left/Right
            if ((axisX < -0.5 || gp.buttons[14]?.pressed) && lastAxisX >= -0.5) { // Left
                setFocusedChoiceIndex(prev => (prev % 2 === 1) ? prev - 1 : prev); 
            }
            if ((axisX > 0.5 || gp.buttons[15]?.pressed) && lastAxisX <= 0.5) { // Right
                setFocusedChoiceIndex(prev => (prev % 2 === 0) ? Math.min(3, prev + 1) : prev);
            }

            // Up/Down
            if ((axisY < -0.5 || gp.buttons[12]?.pressed) && lastAxisY >= -0.5) { // Up
                setFocusedChoiceIndex(prev => (prev >= 2) ? prev - 2 : prev);
            }
            if ((axisY > 0.5 || gp.buttons[13]?.pressed) && lastAxisY <= 0.5) { // Down
                setFocusedChoiceIndex(prev => (prev < 2) ? prev + 2 : prev);
            }

            lastAxisX = axisX;
            lastAxisY = axisY;

            // Select (Button 0 = A / Cross)
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                // Ensure choices exists and index is valid
                if (choices && choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }

        rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [mode, status, focusedChoiceIndex, choices]);


  const handleCorrect = () => {
    setStatus('correct');
    playSuccessSound();
    speakText(word.word);
    setTimeout(() => onResult(true), 1200);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    speakText(word.word); // Teach them
    setTimeout(() => onResult(false), 2000); // Longer delay to see answer
  };

  const checkSpelling = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim().toLowerCase() === word.word.toLowerCase()) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const checkChoice = (selectedId: string) => {
    if (selectedId === word.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm pointer-events-auto">
      <div className={`bg-white rounded-2xl p-8 w-full max-w-2xl shadow-2xl border-4 transform transition-all ${status === 'correct' ? 'border-green-500 scale-105' : status === 'incorrect' ? 'border-red-500 animate-shake' : 'border-indigo-500'}`}>

        {/* Header */}
        <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-widest mb-1">升级挑战</h2>
          <div className="text-slate-500 text-sm">回答正确获得强力属性提升！</div>
        </div>

        {/* Content */}
        <div className="mb-8 min-h-[150px] flex flex-col justify-center items-center">
          {mode === 'SPELL_FROM_DEF' && (
             <>
               <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold mb-4">看义拼词</span>
               <p className="text-2xl font-bold text-slate-800 text-center">{word.definition}</p>
             </>
          )}

          {mode === 'SPELL_FROM_AUDIO' && (
            <>
              <span className="bg-pink-100 text-pink-700 px-3 py-1 rounded-full text-xs font-bold mb-4">听音拼词</span>
              <button 
                onClick={() => speakText(word.word)}
                className="w-20 h-20 bg-indigo-500 rounded-full flex items-center justify-center text-white shadow-lg hover:bg-indigo-600 active:scale-95 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
              </button>
            </>
          )}

          {mode === 'MEANING_FROM_WORD' && (
             <h1 className="text-5xl font-black text-slate-800 mb-4">{word.word}</h1>
          )}
        </div>

        {/* Inputs */}
        <div className="w-full">
          {mode === 'MEANING_FROM_WORD' ? (
            <div className="grid grid-cols-2 gap-4">
              {choices.map((choice, index) => (
                <button
                  key={choice.id}
                  onClick={() => checkChoice(choice.id)}
                  onMouseEnter={() => {
                      // Only change focus on mouse hover if the user is actually using the mouse.
                      // This prevents the hidden cursor from hijacking selection when using gamepad/keyboard.
                      if (lastInputMethod.current === 'MOUSE') {
                          setFocusedChoiceIndex(index);
                      }
                  }}
                  disabled={status !== 'idle'}
                  className={`p-4 rounded-xl font-bold text-lg text-left transition-all border-b-4 active:border-b-0 active:translate-y-1 relative
                    ${status === 'correct' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : // Show correct answer
                      status === 'incorrect' && choice.id !== word.id ? 'bg-red-100 text-red-400 border-red-200' :
                      focusedChoiceIndex === index ? 'bg-indigo-50 border-indigo-500 ring-2 ring-indigo-300 text-indigo-700 scale-105 z-10' :
                      'bg-slate-100 border-slate-300 hover:bg-indigo-50 hover:border-indigo-300 text-slate-700'}`}
                >
                  {choice.definition}
                  {focusedChoiceIndex === index && status === 'idle' && (
                      <div className="absolute top-1 right-2 text-indigo-400 text-xs font-bold">[A]</div>
                  )}
                </button>
              ))}
            </div>
          ) : (
            <form onSubmit={checkSpelling}>
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={(e) => e.stopPropagation()} // Stop W/A/S/D from moving character
                onKeyUp={(e) => e.stopPropagation()}
                disabled={status !== 'idle'}
                placeholder="输入单词..."
                className={`w-full text-center text-4xl font-mono font-bold py-4 border-b-4 bg-transparent outline-none transition-colors
                  ${status === 'correct' ? 'border-green-500 text-green-600' : 
                    status === 'incorrect' ? 'border-red-500 text-red-500' : 'border-slate-300 focus:border-indigo-500 text-slate-800'}`}
                autoComplete="off"
              />
              {status === 'incorrect' && (
                <div className="text-center mt-2 text-red-500 font-bold animate-fade-in">
                  正确答案: {word.word}
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, loadBasicAssets, loadAdvancedAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { playShootSound, playHitSound, playVictorySound } from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100;
const BASE_XP_REQUIREMENT = 10; // Initial XP requirement

// Fixed Logical Resolution (16:9 FHD)
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    // Fix: Floor the cooldown to ensure it stays an integer for modulo checks
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.85)) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30 (当前+30)', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.hp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: GAME_WIDTH / 2, 
    y: GAME_HEIGHT / 2, 
    width: 64, height: 64, // Scaled up for 1080p
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, 
    speed: 4, // REDUCED FROM 6 to 4
    damage: 10, attackSpeed: 30, 
    projectileSpeed: 4, // Reduced speed from 6 to 4
    pickupRange: 120,
    projectileCount: 1, 
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  // Mouse Ref removed as mouse is disabled
  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  const quizCooldownRef = useRef(0); 
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // Logic Refs
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  // UI Sync Refs (To avoid stale closures in game loop)
  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);
  const isGamepadActiveRef = useRef(false);
  const lastInputMethod = useRef<'MOUSE' | 'KEYBOARD'>('KEYBOARD');

  // -- REACT STATE --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);
  const [isGamepadActive, setIsGamepadActive] = useState(false);

  // Sync Refs with State
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { isGamepadActiveRef.current = isGamepadActive; }, [isGamepadActive]);

  const toggleFullscreen = () => {
      if (!document.fullscreenElement) {
          document.documentElement.requestFullscreen().catch(() => {});
      } else {
          document.exitFullscreen().catch(() => {});
      }
  };

  // 1. INITIALIZE GAME DATA (Run Once)
  useEffect(() => {
    // FORCE CURSOR HIDING GLOBALLY
    const style = document.createElement('style');
    style.innerHTML = `* { cursor: none !important; }`;
    document.head.appendChild(style);

    // Shuffle words for this session ONCE.
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);

    // LOAD ASSETS STRATEGY
    const handleAssetLoad = (key: string, url: string) => {
        const img = new Image();
        img.src = url;
        // Pre-decode for smoother rendering
        img.decode().then(() => { spritesRef.current[key] = img; }).catch(() => { spritesRef.current[key] = img; });
    };

    // 1. Load Mobs & Hero IMMEDIATELY
    loadBasicAssets(handleAssetLoad);

    // 2. Load Elites & Bosses LATER (e.g. 5 seconds after start)
    const eliteTimer = setTimeout(() => {
        loadAdvancedAssets(handleAssetLoad);
    }, 5000);

    // Input Tracking for Upgrade Menu interference
    const handleMouseMove = () => { lastInputMethod.current = 'MOUSE'; };
    const handleKeyDown = () => { lastInputMethod.current = 'KEYBOARD'; };
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('keydown', handleKeyDown);

    return () => {
        document.head.removeChild(style);
        clearTimeout(eliteTimer);
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('keydown', handleKeyDown);
    };
  }, []); // Empty dependency array is critical here!

  // 2. INPUT HANDLERS & LOOP (Run Once)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { 
        if (isPausedRef.current) return;
        keysRef.current[e.key.toLowerCase()] = true; 

        if (isGamepadActiveRef.current) {
            setIsGamepadActive(false); 
        }
    };
    const handleKeyUp = (e: KeyboardEvent) => { 
        keysRef.current[e.key.toLowerCase()] = false; 
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []); // Run once. Using Refs for mutable state access.

  // 3. SYSTEM GAMEPAD POLLING (Fullscreen Toggle - Button B)
  useEffect(() => {
    let rafId: number;
    let lastButtonState = false;

    const pollSystemButtons = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Button 1: B (Xbox), Circle (PS), A (Nintendo) -> Toggle Fullscreen
        if (gp.buttons[1]?.pressed && !lastButtonState) {
          toggleFullscreen();
        }
        lastButtonState = gp.buttons[1]?.pressed;
      }
      rafId = requestAnimationFrame(pollSystemButtons);
    };

    rafId = requestAnimationFrame(pollSystemButtons);
    return () => cancelAnimationFrame(rafId);
  }, []);

  // Gamepad & Keyboard Polling for Upgrade Menu
  useEffect(() => {
    if (!showUpgrades) return;

    let lastAxisX = 0;
    let lastButtonState = false;
    let rafId: number;

    // Keyboard Handler for Menu
    const handleMenuKey = (e: KeyboardEvent) => {
        lastInputMethod.current = 'KEYBOARD';
        if (e.key === 'ArrowLeft') setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        if (e.key === 'ArrowRight') setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        if (e.key === 'Enter' || e.key === ' ') {
             const selected = showUpgrades[upgradeFocusedIndex];
             if (selected) applyUpgrade(selected);
        }
    };
    window.addEventListener('keydown', handleMenuKey);

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        const hasActivity = Math.abs(gp.axes[0]) > 0.5 || gp.buttons.some(b => b.pressed);
        if (hasActivity) {
            if (!isGamepadActive) setIsGamepadActive(true);
            lastInputMethod.current = 'KEYBOARD'; // Gamepad acts as keyboard-like input
        }

        const axisX = gp.axes[0];
        const isLeft = axisX < -0.5 || gp.buttons[14]?.pressed;
        const isRight = axisX > 0.5 || gp.buttons[15]?.pressed;

        if (isLeft && lastAxisX >= -0.5) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        } else if (isRight && lastAxisX <= 0.5) {
            setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        }
        lastAxisX = axisX;

        if (gp.buttons[0]?.pressed && !lastButtonState) {
             const selected = showUpgrades[upgradeFocusedIndex];
             // Allow selecting any upgrade, including HP
             if (selected) {
                 applyUpgrade(selected);
             }
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }

      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => {
        cancelAnimationFrame(rafId);
        window.removeEventListener('keydown', handleMenuKey);
    };
  }, [showUpgrades, upgradeFocusedIndex, isGamepadActive]);


  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameResult !== 'PLAYING') return;
    if (!isPausedRef.current) update();
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    // SECURITY CHECK: If UI is open, FORCE pause.
    // Must use REFS here because closure might be stale
    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    const player = playerRef.current;
    const stats = statsRef.current;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0];
    if (gp) {
        const deadzone = 0.2;
        let hasInput = false;

        if (Math.abs(gp.axes[0]) > deadzone) { dx += gp.axes[0]; hasInput = true; }
        if (Math.abs(gp.axes[1]) > deadzone) { dy += gp.axes[1]; hasInput = true; }
        if (gp.buttons[12]?.pressed) { dy -= 1; hasInput = true; }
        if (gp.buttons[13]?.pressed) { dy += 1; hasInput = true; }
        if (gp.buttons[14]?.pressed) { dx -= 1; hasInput = true; }
        if (gp.buttons[15]?.pressed) { dx += 1; hasInput = true; }

        if (hasInput && !isGamepadActiveRef.current) {
            setIsGamepadActive(true);
        }
    }

    // Direction & Animation Logic
    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        // Prioritize direction update
        if (Math.abs(dx) > Math.abs(dy)) {
            player.direction = dx > 0 ? 'RIGHT' : 'LEFT';
        } else {
            player.direction = dy > 0 ? 'DOWN' : 'UP';
        }

        const length = Math.sqrt(dx * dx + dy * dy);
        const normalizedFactor = length > 1 ? 1 / length : 1;
        player.x += (dx * normalizedFactor) * stats.speed;
        player.y += (dy * normalizedFactor) * stats.speed;
    } else {
        player.isMoving = false;
    }

    // Always animate frames (for Idle animation)
    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 120) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }

    // Boundary check with padding (half width) to prevent visual sticking/clipping
    const halfW = player.width / 2;
    const halfH = player.height / 2;
    player.x = Math.max(halfW, Math.min(GAME_WIDTH - halfW, player.x));
    player.y = Math.max(halfH, Math.min(GAME_HEIGHT - halfH, player.y));

    // 2. Spawning & Logic
    spawnEnemies();

    enemiesRef.current.forEach(enemy => {
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);

      // REDUCED ENEMY SPEEDS
      const speed = enemy.type.includes('ELITE') ? 2.0 
                  : enemy.type === 'BOSS' ? 1.2 
                  : 1.5;

      enemy.vx = Math.cos(angle) * speed;
      enemy.vy = Math.sin(angle) * speed;
      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) spawnBossBullets(enemy);
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) spawnEnemyBullet(enemy, player);

      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(enemy.damage);
      }
    });

    // 4. Combat
    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 15)) {
              enemy.hp -= p.damage;
              hit = true;
              try { playHitSound(); } catch(e) {} // Safe audio call
              break;
            }
          }
      } else {
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 15)) {
               takeDamage(p.damage);
               hit = true;
           }
      }
      const oob = p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT;
      return !oob && !hit;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        // Stats Tracking
        if (e.type === 'BOSS') {
            killCountsRef.current.bosses++;
            setGameResult('VICTORY');
            playVictorySound();
            isPausedRef.current = true;
        } else if (e.type.includes('ELITE')) {
            killCountsRef.current.elites++;
        } else {
            killCountsRef.current.mobs++;
        }

        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 24, height: 24, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        gem.x += (player.x - gem.x) * 0.15;
        gem.y += (player.y - gem.y) * 0.15;
        if (dist < 30) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  // === HELPERS ===

  const calculateScore = () => {
    return (killCountsRef.current.mobs * 1) + 
           (killCountsRef.current.elites * 10) + 
           (killCountsRef.current.bosses * 100);
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const spawnRate = Math.max(20, SPAWN_RATE_INITIAL - Math.floor(time / 2)); 

      // BOSS SPAWN LOGIC: Spawn only if all words are done and no boss exists
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS');
          bossSpawnedRef.current = true;
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = 'MOB';

          // ELITE SPAWN CONDITION: Only after Level 1 (i.e., Level 2+)
          const canSpawnElite = statsRef.current.level > 1;

          if (canSpawnElite && time > 30 && r > 0.9) type = 'ELITE';
          if (canSpawnElite && time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      // Default Entity
      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 50, height: 50, // Default size
          hp: 2, maxHp: 2, damage: 1 // Mob damage = 1
      };

      if (category === 'BOSS') {
          // BOSS HP DOUBLED TO 1000
          entity = { ...entity, type: 'BOSS', width: 250, height: 250, hp: 1000, maxHp: 1000, damage: 10, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          // Elite HP DOUBLED TO 40
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 40, maxHp: 40, damage: 5, width: 90, height: 90 }; 
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED', spriteUrl: AssetTypes.ELITE_RANGED, hp: 40, maxHp: 40, damage: 5, width: 80, height: 80 }; 
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 40, maxHp: 40, damage: 5, width: 100, height: 100 }; 
          }
      } else {
          // Mob HP = 2
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 2, maxHp: 2 };
      }
      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // CHAOTIC RANDOM DIRECTION AND POSITION LOGIC
    try { playShootSound(); } catch(e) {}

    const p = playerRef.current;
    const count = statsRef.current.projectileCount || 1;

    for (let i = 0; i < count; i++) {
            // Random Direction (0 - 360 degrees)
            const angle = Math.random() * Math.PI * 2;

            // Random Start Position on Body (random offset from center)
            // p.width/2 is radius approx. Multiplying by 0.5 keeps it somewhat central but chaotic.
            const offsetX = (Math.random() - 0.5) * p.width * 0.8;
            const offsetY = (Math.random() - 0.5) * p.height * 0.8;

            projectilesRef.current.push({
            id: Math.random().toString(),
            x: p.x + offsetX,
            y: p.y + offsetY,
            width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(angle) * statsRef.current.projectileSpeed,
            vy: Math.sin(angle) * statsRef.current.projectileSpeed,
            hp: 1, maxHp: 1, damage: statsRef.current.damage
        });
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 20, height: 20, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 5, vy: Math.sin(angle) * 5, hp: 1, maxHp: 1, damage: 5
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      for (let i = 0; i < 12; i++) {
          const angle = (Math.PI * 2 / 12) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 24, height: 24, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 6, vy: Math.sin(angle) * 6, hp: 1, maxHp: 1, damage: 10
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp();
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      keysRef.current = {}; 

      // Pull from remaining words
      if (remainingWordsRef.current.length > 0) {
          const nextWord = remainingWordsRef.current.pop();
          if (nextWord) {
              setQuizWord(nextWord);
              return;
          }
      } 

      // If no words left or failed to pop, just show upgrade
      showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true; // FORCE PAUSE
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
      setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) { 
          showUpgradeMenu(); 
      } else {
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = statsRef.current.xpToNextLevel + 2;
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.projectileCount += 1;

      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = statsRef.current.xpToNextLevel + 2;
      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background - Dark Slate #0f172a
    ctx.fillStyle = '#0f172a'; 
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    // Grid - Slate 800 #1e293b
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < GAME_WIDTH; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke();
    }
    for (let y = 0; y < GAME_HEIGHT; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke();
    }

    const drawSprite = (e: Entity, fallbackColor: string) => {
        let spriteKey: string = e.type;

        // --- HERO ANIMATION SELECTOR ---
        if (e.type === 'HERO') {
            const dir = e.direction || 'DOWN';

            // IF IDLE and we have an Idle sprite, use it
            if (!e.isMoving && spritesRef.current['HERO_IDLE']) {
                spriteKey = 'HERO_IDLE';
            } 
            // OTHERWISE use directional sprites if available
            else if (spritesRef.current[`HERO_${dir}`]) {
                spriteKey = `HERO_${dir}`;
            }
        } else if (e.spriteUrl) {
            spriteKey = e.spriteUrl;
        }

        const sprite = spritesRef.current[spriteKey];

        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            // Check if image is a sprite strip (Width > Height)
            // Assuming square frames
            const isStrip = sprite.naturalWidth > sprite.naturalHeight;

            if (isStrip && e.type === 'HERO') {
                // ANIMATED DRAW
                const frameCount = Math.round(sprite.naturalWidth / sprite.naturalHeight);
                const frameIndex = (e.animFrame || 0) % frameCount;
                const fw = sprite.naturalWidth / frameCount;
                const fh = sprite.naturalHeight;

                ctx.drawImage(
                    sprite, 
                    frameIndex * fw, 0, fw, fh, 
                    e.x - e.width/2, e.y - e.height/2, e.width, e.height
                );
            } else {
                // STATIC DRAW
                ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        } else {
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2); ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    xpGemsRef.current.forEach(gem => drawSprite(gem, '#fbbf24'));
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // Health bar drawing code REMOVED per request
    });

    // Draw Player (Floating health bar removed)
    const p = playerRef.current;
    drawSprite(p, '#6366f1');

    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill();
    });
  };

  return (
    <div 
      className={`fixed inset-0 w-full h-full bg-black flex items-center justify-center`}
      style={{ cursor: 'none' }}
    >
      <canvas 
        ref={canvasRef} 
        width={GAME_WIDTH} 
        height={GAME_HEIGHT}
        className="bg-slate-900 shadow-2xl pointer-events-none"
        style={{
            maxWidth: '100%',
            maxHeight: '100%',
            objectFit: 'contain',
            aspectRatio: '16/9',
            cursor: 'none' 
        }}
      />

      {/* Fullscreen Toggle */}
      <button 
        onClick={toggleFullscreen}
        className="fixed top-4 right-4 z-50 bg-white/20 hover:bg-white/40 text-white p-2 rounded-lg backdrop-blur-sm transition-all pointer-events-auto"
        title="Toggle Fullscreen"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg>
      </button>

      {/* HUD Container */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level} (Bullets: {uiStats.projectileCount})
             </span>
        </div>
      </div>

      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}

      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in pointer-events-auto">
              <div className="w-[90vw] max-w-7xl p-8">
                  <h2 className="text-5xl font-black text-yellow-400 text-center mb-4 uppercase tracking-widest drop-shadow-md">Level Up!</h2>
                  <p className="text-center text-yellow-200 text-2xl mb-12 font-bold">+1 额外子弹 (被动获取)</p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                      {showUpgrades.map((opt, index) => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            onMouseEnter={() => {
                                if (lastInputMethod.current === 'MOUSE') {
                                    setUpgradeFocusedIndex(index);
                                }
                            }}
                            className={`p-10 rounded-3xl flex flex-col items-center gap-8 transition-all group border-4 relative overflow-hidden min-h-[400px] justify-center
                                ${upgradeFocusedIndex === index 
                                    ? 'bg-slate-700 border-yellow-400 scale-105 shadow-2xl shadow-yellow-500/30 z-10' 
                                    : 'bg-slate-800 border-slate-600 hover:border-yellow-400 hover:bg-slate-700'
                                }`}
                          >
                              <div className={`text-8xl ${upgradeFocusedIndex === index ? 'animate-bounce' : 'group-hover:animate-bounce'}`}>{opt.icon}</div>
                              <div className="text-4xl font-black text-white">{opt.name}</div>
                              <div className="text-xl text-slate-300 text-center leading-relaxed font-medium">{opt.description}</div>
                              {upgradeFocusedIndex === index && (
                                  <div className="text-yellow-400 text-xl font-bold mt-4 animate-pulse tracking-widest border-2 border-yellow-400 px-4 py-1 rounded-full">
                                      [ A ] SELECT
                                  </div>
                              )}
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className={`fixed inset-0 z-50 flex items-center justify-center backdrop-blur-md ${gameResult === 'VICTORY' ? 'bg-yellow-900/90' : 'bg-red-900/90'} pointer-events-auto`}>
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className={`text-5xl font-black mb-2 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'YOU DIED'}
                  </h1>

                  <div className="text-6xl font-black text-slate-800 mb-8 drop-shadow-md">
                      {calculateScore()} <span className="text-2xl font-bold text-slate-500">PTS</span>
                  </div>

                  <div className="grid grid-cols-3 gap-4 mb-8 mt-6">
                      <div className="bg-slate-100 p-3 rounded-lg flex flex-col items-center">
                          <span className="text-2xl font-bold text-slate-700">{killCountsRef.current.mobs}</span>
                          <span className="text-xs text-slate-500 uppercase font-bold">小怪 (1pt)</span>
                      </div>
                      <div className="bg-slate-100 p-3 rounded-lg flex flex-col items-center">
                          <span className="text-2xl font-bold text-slate-700">{killCountsRef.current.elites}</span>
                          <span className="text-xs text-slate-500 uppercase font-bold">精英 (10pts)</span>
                      </div>
                      <div className="bg-slate-100 p-3 rounded-lg flex flex-col items-center border-2 border-yellow-400">
                          <span className="text-2xl font-bold text-yellow-600">{killCountsRef.current.bosses}</span>
                          <span className="text-xs text-slate-500 uppercase font-bold">BOSS (100pts)</span>
                      </div>
                  </div>

                  <p className="text-indigo-600 font-bold mb-8">最终等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData } from '../types';
import { speakText, playSuccessSound, playErrorSound } from '../services/audioService';

interface GameQuizModalProps {
  word: WordData;
  allWords: WordData[];
  onResult: (correct: boolean) => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const GameQuizModal: React.FC<GameQuizModalProps> = ({ word, allWords, onResult }) => {
  const [mode, setMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [input, setInput] = useState('');
  const [choices, setChoices] = useState<WordData[]>([]);
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [focusedChoiceIndex, setFocusedChoiceIndex] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);

  // Track input method State to drive UI pointer-events
  const [inputMethod, setInputMethod] = useState<'MOUSE' | 'GAMEPAD'>('GAMEPAD');
  const lastMousePos = useRef({ x: 0, y: 0 });

  // Input Method Tracking
  useEffect(() => {
      const handleMouseMove = (e: MouseEvent) => { 
          // Filter out jitter/phantom moves
          const dist = Math.abs(e.clientX - lastMousePos.current.x) + Math.abs(e.clientY - lastMousePos.current.y);
          if (dist > 5) {
             lastMousePos.current = { x: e.clientX, y: e.clientY };
             setInputMethod('MOUSE');
          }
      };
      const handleKeyDown = () => { setInputMethod('GAMEPAD'); };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('keydown', handleKeyDown);
      return () => {
          window.removeEventListener('mousemove', handleMouseMove);
          window.removeEventListener('keydown', handleKeyDown);
      };
  }, []);

  // Setup
  useEffect(() => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const selectedMode = modes[Math.floor(Math.random() * modes.length)];
    setMode(selectedMode);

    if (selectedMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (selectedMode === 'SPELL_FROM_AUDIO') {
      setTimeout(() => speakText(word.word), 300);
    }

    // Auto focus
    setTimeout(() => inputRef.current?.focus(), 100);
  }, [word, allWords]);

  // Keyboard Support for Choices
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (mode === 'MEANING_FROM_WORD' && status === 'idle') {
            if (['ArrowUp', 'ArrowLeft', 'ArrowDown', 'ArrowRight', 'Enter', ' '].includes(e.key)) {
                setInputMethod('GAMEPAD');
            }

            if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
                 setFocusedChoiceIndex(prev => Math.max(0, prev - 1));
            }
            if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
                 setFocusedChoiceIndex(prev => Math.min(choices.length - 1, prev + 1));
            }
            if (e.key === 'Enter' || e.key === ' ') {
                if (choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [mode, status, choices, focusedChoiceIndex]);

  // Gamepad Polling for Multiple Choice
  useEffect(() => {
    if (mode !== 'MEANING_FROM_WORD' || status !== 'idle') return;

    let lastAxisY = 0;
    let lastAxisX = 0;
    let lastButtonState = false;
    let rafId: number;

    const pollGamepad = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            // Check for activity to switch input method
            const hasActivity = Math.abs(gp.axes[0]) > 0.5 || Math.abs(gp.axes[1]) > 0.5 || gp.buttons.some(b => b.pressed);
            if (hasActivity) {
                 if (inputMethod !== 'GAMEPAD') setInputMethod('GAMEPAD');
            }

            const axisX = gp.axes[0];
            const axisY = gp.axes[1];

            // Grid is 2x2. 0,1 top row. 2,3 bottom row.

            // Left/Right
            if ((axisX < -0.5 || gp.buttons[14]?.pressed) && lastAxisX >= -0.5) { // Left
                setFocusedChoiceIndex(prev => (prev % 2 === 1) ? prev - 1 : prev); 
            }
            if ((axisX > 0.5 || gp.buttons[15]?.pressed) && lastAxisX <= 0.5) { // Right
                setFocusedChoiceIndex(prev => (prev % 2 === 0) ? Math.min(3, prev + 1) : prev);
            }

            // Up/Down
            if ((axisY < -0.5 || gp.buttons[12]?.pressed) && lastAxisY >= -0.5) { // Up
                setFocusedChoiceIndex(prev => (prev >= 2) ? prev - 2 : prev);
            }
            if ((axisY > 0.5 || gp.buttons[13]?.pressed) && lastAxisY <= 0.5) { // Down
                setFocusedChoiceIndex(prev => (prev < 2) ? prev + 2 : prev);
            }

            lastAxisX = axisX;
            lastAxisY = axisY;

            // Select (Button 0 = A / Cross)
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                // Ensure choices exists and index is valid
                if (choices && choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }

        rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [mode, status, focusedChoiceIndex, choices, inputMethod]);


  const handleCorrect = () => {
    setStatus('correct');
    playSuccessSound();
    speakText(word.word);
    setTimeout(() => onResult(true), 1200);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    speakText(word.word); // Teach them
    setTimeout(() => onResult(false), 2000); // Longer delay to see answer
  };

  const checkSpelling = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim().toLowerCase() === word.word.toLowerCase()) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const checkChoice = (selectedId: string) => {
    if (selectedId === word.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm pointer-events-auto">
      <div className={`bg-white rounded-2xl p-8 w-full max-w-2xl shadow-2xl border-4 transform transition-all ${status === 'correct' ? 'border-green-500 scale-105' : status === 'incorrect' ? 'border-red-500 animate-shake' : 'border-indigo-500'}`}>

        {/* Header */}
        <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-widest mb-1">升级挑战</h2>
          <div className="text-slate-500 text-sm">回答正确获得强力属性提升！</div>
        </div>

        {/* Content */}
        <div className="mb-8 min-h-[150px] flex flex-col justify-center items-center">
          {mode === 'SPELL_FROM_DEF' && (
             <>
               <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold mb-4">看义拼词</span>
               <p className="text-2xl font-bold text-slate-800 text-center">{word.definition}</p>
             </>
          )}

          {mode === 'SPELL_FROM_AUDIO' && (
            <>
              <span className="bg-pink-100 text-pink-700 px-3 py-1 rounded-full text-xs font-bold mb-4">听音拼词</span>
              <button 
                onClick={() => speakText(word.word)}
                className="w-20 h-20 bg-indigo-500 rounded-full flex items-center justify-center text-white shadow-lg hover:bg-indigo-600 active:scale-95 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
              </button>
            </>
          )}

          {mode === 'MEANING_FROM_WORD' && (
             <h1 className="text-5xl font-black text-slate-800 mb-4">{word.word}</h1>
          )}
        </div>

        {/* Inputs */}
        <div className="w-full">
          {mode === 'MEANING_FROM_WORD' ? (
            <div className="grid grid-cols-2 gap-4">
              {choices.map((choice, index) => (
                <button
                  key={choice.id}
                  onClick={() => checkChoice(choice.id)}
                  onMouseEnter={() => {
                      if (inputMethod === 'MOUSE') {
                          setFocusedChoiceIndex(index);
                      }
                  }}
                  disabled={status !== 'idle'}
                  className={`p-4 rounded-xl font-bold text-lg text-left transition-all border-b-4 active:border-b-0 active:translate-y-1 relative
                    ${inputMethod === 'GAMEPAD' ? 'pointer-events-none' : ''} 
                    ${status === 'correct' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id !== word.id ? 'bg-red-100 text-red-400 border-red-200' :
                      focusedChoiceIndex === index ? 'bg-indigo-50 border-indigo-500 ring-2 ring-indigo-300 text-indigo-700 scale-105 z-10' :
                      'bg-slate-100 border-slate-300 hover:bg-indigo-50 hover:border-indigo-300 text-slate-700'}`}
                >
                  {choice.definition}
                  {focusedChoiceIndex === index && status === 'idle' && (
                      <div className="absolute top-1 right-2 text-indigo-400 text-xs font-bold">
                          {inputMethod === 'GAMEPAD' ? '[A]' : ''}
                      </div>
                  )}
                </button>
              ))}
            </div>
          ) : (
            <form onSubmit={checkSpelling}>
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={(e) => e.stopPropagation()} // Stop W/A/S/D from moving character
                onKeyUp={(e) => e.stopPropagation()}
                disabled={status !== 'idle'}
                placeholder="输入单词..."
                className={`w-full text-center text-4xl font-mono font-bold py-4 border-b-4 bg-transparent outline-none transition-colors
                  ${status === 'correct' ? 'border-green-500 text-green-600' : 
                    status === 'incorrect' ? 'border-red-500 text-red-500' : 'border-slate-300 focus:border-indigo-500 text-slate-800'}`}
                autoComplete="off"
              />
              {status === 'incorrect' && (
                <div className="text-center mt-2 text-red-500 font-bold animate-fade-in">
                  正确答案: {word.word}
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, loadBasicAssets, loadAdvancedAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { playShootSound, playHitSound, playVictorySound } from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100;
const BASE_XP_REQUIREMENT = 10; // Initial XP requirement

// Fixed Logical Resolution (16:9 FHD)
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    // Fix: Floor the cooldown to ensure it stays an integer for modulo checks
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.85)) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30 (当前+30)', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.hp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: GAME_WIDTH / 2, 
    y: GAME_HEIGHT / 2, 
    width: 64, height: 64, // Scaled up for 1080p
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, 
    speed: 4, // REDUCED FROM 6 to 4
    damage: 10, attackSpeed: 30, 
    projectileSpeed: 4, // Reduced speed from 6 to 4
    pickupRange: 120,
    projectileCount: 1, 
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  // Mouse Ref removed as mouse is disabled
  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  const quizCooldownRef = useRef(0); 
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // Logic Refs
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  // UI Sync Refs (To avoid stale closures in game loop)
  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);
  const isGamepadActiveRef = useRef(false);

  // -- REACT STATE --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);
  const [isGamepadActive, setIsGamepadActive] = useState(false);

  // Track input method State to drive UI pointer-events
  const [inputMethod, setInputMethod] = useState<'MOUSE' | 'GAMEPAD'>('GAMEPAD');
  const lastMousePos = useRef({ x: 0, y: 0 });

  // Sync Refs with State
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { isGamepadActiveRef.current = isGamepadActive; }, [isGamepadActive]);

  const toggleFullscreen = () => {
      if (!document.fullscreenElement) {
          document.documentElement.requestFullscreen().catch(() => {});
      } else {
          document.exitFullscreen().catch(() => {});
      }
  };

  // 1. INITIALIZE GAME DATA (Run Once)
  useEffect(() => {
    // FORCE CURSOR HIDING GLOBALLY
    const style = document.createElement('style');
    style.innerHTML = `* { cursor: none !important; }`;
    document.head.appendChild(style);

    // Shuffle words for this session ONCE.
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);

    // LOAD ASSETS STRATEGY
    const handleAssetLoad = (key: string, url: string) => {
        const img = new Image();
        img.src = url;
        // Pre-decode for smoother rendering
        img.decode().then(() => { spritesRef.current[key] = img; }).catch(() => { spritesRef.current[key] = img; });
    };

    // 1. Load Mobs & Hero IMMEDIATELY
    loadBasicAssets(handleAssetLoad);

    // 2. Load Elites & Bosses LATER (e.g. 5 seconds after start)
    const eliteTimer = setTimeout(() => {
        loadAdvancedAssets(handleAssetLoad);
    }, 5000);

    // Input Tracking for Upgrade Menu interference
    const handleMouseMove = (e: MouseEvent) => { 
        // Filter out jitter/phantom moves
        const dist = Math.abs(e.clientX - lastMousePos.current.x) + Math.abs(e.clientY - lastMousePos.current.y);
        if (dist > 5) {
            lastMousePos.current = { x: e.clientX, y: e.clientY };
            setInputMethod('MOUSE');
        }
    };
    const handleKeyDown = () => { setInputMethod('GAMEPAD'); };
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('keydown', handleKeyDown);

    return () => {
        document.head.removeChild(style);
        clearTimeout(eliteTimer);
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('keydown', handleKeyDown);
    };
  }, []); // Empty dependency array is critical here!

  // 2. INPUT HANDLERS & LOOP (Run Once)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { 
        if (isPausedRef.current) return;
        keysRef.current[e.key.toLowerCase()] = true; 

        if (isGamepadActiveRef.current) {
            setIsGamepadActive(false); 
        }
    };
    const handleKeyUp = (e: KeyboardEvent) => { 
        keysRef.current[e.key.toLowerCase()] = false; 
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []); // Run once. Using Refs for mutable state access.

  // 3. SYSTEM GAMEPAD POLLING (Fullscreen Toggle - Button B)
  useEffect(() => {
    let rafId: number;
    let lastButtonState = false;

    const pollSystemButtons = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Button 1: B (Xbox), Circle (PS), A (Nintendo) -> Toggle Fullscreen
        if (gp.buttons[1]?.pressed && !lastButtonState) {
          toggleFullscreen();
        }
        lastButtonState = gp.buttons[1]?.pressed;
      }
      rafId = requestAnimationFrame(pollSystemButtons);
    };

    rafId = requestAnimationFrame(pollSystemButtons);
    return () => cancelAnimationFrame(rafId);
  }, []);

  // Gamepad & Keyboard Polling for Upgrade Menu
  useEffect(() => {
    if (!showUpgrades) return;

    let lastAxisX = 0;
    let lastButtonState = false;
    let rafId: number;

    // Keyboard Handler for Menu
    const handleMenuKey = (e: KeyboardEvent) => {
        setInputMethod('GAMEPAD');
        if (e.key === 'ArrowLeft') setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        if (e.key === 'ArrowRight') setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        if (e.key === 'Enter' || e.key === ' ') {
             const selected = showUpgrades[upgradeFocusedIndex];
             if (selected) applyUpgrade(selected);
        }
    };
    window.addEventListener('keydown', handleMenuKey);

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        const hasActivity = Math.abs(gp.axes[0]) > 0.5 || gp.buttons.some(b => b.pressed);
        if (hasActivity) {
            if (!isGamepadActive) setIsGamepadActive(true);
            if (inputMethod !== 'GAMEPAD') setInputMethod('GAMEPAD');
        }

        const axisX = gp.axes[0];
        const isLeft = axisX < -0.5 || gp.buttons[14]?.pressed;
        const isRight = axisX > 0.5 || gp.buttons[15]?.pressed;

        if (isLeft && lastAxisX >= -0.5) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        } else if (isRight && lastAxisX <= 0.5) {
            setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        }
        lastAxisX = axisX;

        if (gp.buttons[0]?.pressed && !lastButtonState) {
             const selected = showUpgrades[upgradeFocusedIndex];
             // Allow selecting any upgrade, including HP
             if (selected) {
                 applyUpgrade(selected);
             }
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }

      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => {
        cancelAnimationFrame(rafId);
        window.removeEventListener('keydown', handleMenuKey);
    };
  }, [showUpgrades, upgradeFocusedIndex, isGamepadActive, inputMethod]);


  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameResult !== 'PLAYING') return;
    if (!isPausedRef.current) update();
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    // SECURITY CHECK: If UI is open, FORCE pause.
    // Must use REFS here because closure might be stale
    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    const player = playerRef.current;
    const stats = statsRef.current;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0];
    if (gp) {
        const deadzone = 0.2;
        let hasInput = false;

        if (Math.abs(gp.axes[0]) > deadzone) { dx += gp.axes[0]; hasInput = true; }
        if (Math.abs(gp.axes[1]) > deadzone) { dy += gp.axes[1]; hasInput = true; }
        if (gp.buttons[12]?.pressed) { dy -= 1; hasInput = true; }
        if (gp.buttons[13]?.pressed) { dy += 1; hasInput = true; }
        if (gp.buttons[14]?.pressed) { dx -= 1; hasInput = true; }
        if (gp.buttons[15]?.pressed) { dx += 1; hasInput = true; }

        if (hasInput && !isGamepadActiveRef.current) {
            setIsGamepadActive(true);
        }
    }

    // Direction & Animation Logic
    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        // Prioritize direction update
        if (Math.abs(dx) > Math.abs(dy)) {
            player.direction = dx > 0 ? 'RIGHT' : 'LEFT';
        } else {
            player.direction = dy > 0 ? 'DOWN' : 'UP';
        }

        const length = Math.sqrt(dx * dx + dy * dy);
        const normalizedFactor = length > 1 ? 1 / length : 1;
        player.x += (dx * normalizedFactor) * stats.speed;
        player.y += (dy * normalizedFactor) * stats.speed;
    } else {
        player.isMoving = false;
    }

    // Always animate frames (for Idle animation)
    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 120) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }

    // Boundary check with padding (half width) to prevent visual sticking/clipping
    const halfW = player.width / 2;
    const halfH = player.height / 2;
    player.x = Math.max(halfW, Math.min(GAME_WIDTH - halfW, player.x));
    player.y = Math.max(halfH, Math.min(GAME_HEIGHT - halfH, player.y));

    // 2. Spawning & Logic
    spawnEnemies();

    enemiesRef.current.forEach(enemy => {
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);

      // REDUCED ENEMY SPEEDS
      const speed = enemy.type.includes('ELITE') ? 2.0 
                  : enemy.type === 'BOSS' ? 1.2 
                  : 1.5;

      enemy.vx = Math.cos(angle) * speed;
      enemy.vy = Math.sin(angle) * speed;
      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) spawnBossBullets(enemy);
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) spawnEnemyBullet(enemy, player);

      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(enemy.damage);
      }
    });

    // 4. Combat
    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 15)) {
              enemy.hp -= p.damage;
              hit = true;
              try { playHitSound(); } catch(e) {} // Safe audio call
              break;
            }
          }
      } else {
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 15)) {
               takeDamage(p.damage);
               hit = true;
           }
      }
      const oob = p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT;
      return !oob && !hit;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        // Stats Tracking
        if (e.type === 'BOSS') {
            killCountsRef.current.bosses++;
            setGameResult('VICTORY');
            playVictorySound();
            isPausedRef.current = true;
        } else if (e.type.includes('ELITE')) {
            killCountsRef.current.elites++;
        } else {
            killCountsRef.current.mobs++;
        }

        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 24, height: 24, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        gem.x += (player.x - gem.x) * 0.15;
        gem.y += (player.y - gem.y) * 0.15;
        if (dist < 30) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  // === HELPERS ===

  const calculateScore = () => {
    return (killCountsRef.current.mobs * 1) + 
           (killCountsRef.current.elites * 10) + 
           (killCountsRef.current.bosses * 100);
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const spawnRate = Math.max(20, SPAWN_RATE_INITIAL - Math.floor(time / 2)); 

      // BOSS SPAWN LOGIC: Spawn only if all words are done and no boss exists
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS');
          bossSpawnedRef.current = true;
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = 'MOB';

          // ELITE SPAWN CONDITION: Only after Level 1 (i.e., Level 2+)
          const canSpawnElite = statsRef.current.level > 1;

          if (canSpawnElite && time > 30 && r > 0.9) type = 'ELITE';
          if (canSpawnElite && time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      // Default Entity
      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 50, height: 50, // Default size
          hp: 2, maxHp: 2, damage: 1 // Mob damage = 1
      };

      if (category === 'BOSS') {
          // BOSS HP DOUBLED TO 1000
          entity = { ...entity, type: 'BOSS', width: 250, height: 250, hp: 1000, maxHp: 1000, damage: 10, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          // Elite HP DOUBLED TO 40
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 40, maxHp: 40, damage: 5, width: 90, height: 90 }; 
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED', spriteUrl: AssetTypes.ELITE_RANGED, hp: 40, maxHp: 40, damage: 5, width: 80, height: 80 }; 
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 40, maxHp: 40, damage: 5, width: 100, height: 100 }; 
          }
      } else {
          // Mob HP = 2
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 2, maxHp: 2 };
      }
      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // CHAOTIC RANDOM DIRECTION AND POSITION LOGIC
    try { playShootSound(); } catch(e) {}

    const p = playerRef.current;
    const count = statsRef.current.projectileCount || 1;

    for (let i = 0; i < count; i++) {
            // Random Direction (0 - 360 degrees)
            const angle = Math.random() * Math.PI * 2;

            // Random Start Position on Body (random offset from center)
            // p.width/2 is radius approx. Multiplying by 0.5 keeps it somewhat central but chaotic.
            const offsetX = (Math.random() - 0.5) * p.width * 0.8;
            const offsetY = (Math.random() - 0.5) * p.height * 0.8;

            projectilesRef.current.push({
            id: Math.random().toString(),
            x: p.x + offsetX,
            y: p.y + offsetY,
            width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(angle) * statsRef.current.projectileSpeed,
            vy: Math.sin(angle) * statsRef.current.projectileSpeed,
            hp: 1, maxHp: 1, damage: statsRef.current.damage
        });
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 20, height: 20, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 5, vy: Math.sin(angle) * 5, hp: 1, maxHp: 1, damage: 5
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      for (let i = 0; i < 12; i++) {
          const angle = (Math.PI * 2 / 12) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 24, height: 24, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 6, vy: Math.sin(angle) * 6, hp: 1, maxHp: 1, damage: 10
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp();
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      keysRef.current = {}; 

      // Pull from remaining words
      if (remainingWordsRef.current.length > 0) {
          const nextWord = remainingWordsRef.current.pop();
          if (nextWord) {
              setQuizWord(nextWord);
              return;
          }
      } 

      // If no words left or failed to pop, just show upgrade
      showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true; // FORCE PAUSE
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
      setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) { 
          showUpgradeMenu(); 
      } else {
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = statsRef.current.xpToNextLevel + 2;
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.projectileCount += 1;

      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = statsRef.current.xpToNextLevel + 2;
      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background - Dark Slate #0f172a
    ctx.fillStyle = '#0f172a'; 
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    // Grid - Slate 800 #1e293b
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < GAME_WIDTH; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke();
    }
    for (let y = 0; y < GAME_HEIGHT; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke();
    }

    const drawSprite = (e: Entity, fallbackColor: string) => {
        let spriteKey: string = e.type;

        // --- HERO ANIMATION SELECTOR ---
        if (e.type === 'HERO') {
            const dir = e.direction || 'DOWN';

            // IF IDLE and we have an Idle sprite, use it
            if (!e.isMoving && spritesRef.current['HERO_IDLE']) {
                spriteKey = 'HERO_IDLE';
            } 
            // OTHERWISE use directional sprites if available
            else if (spritesRef.current[`HERO_${dir}`]) {
                spriteKey = `HERO_${dir}`;
            }
        } else if (e.spriteUrl) {
            spriteKey = e.spriteUrl;
        }

        const sprite = spritesRef.current[spriteKey];

        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            // Check if image is a sprite strip (Width > Height)
            // Assuming square frames
            const isStrip = sprite.naturalWidth > sprite.naturalHeight;

            if (isStrip && e.type === 'HERO') {
                // ANIMATED DRAW
                const frameCount = Math.round(sprite.naturalWidth / sprite.naturalHeight);
                const frameIndex = (e.animFrame || 0) % frameCount;
                const fw = sprite.naturalWidth / frameCount;
                const fh = sprite.naturalHeight;

                ctx.drawImage(
                    sprite, 
                    frameIndex * fw, 0, fw, fh, 
                    e.x - e.width/2, e.y - e.height/2, e.width, e.height
                );
            } else {
                // STATIC DRAW
                ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        } else {
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2); ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    xpGemsRef.current.forEach(gem => drawSprite(gem, '#fbbf24'));
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // Health bar drawing code REMOVED per request
    });

    // Draw Player (Floating health bar removed)
    const p = playerRef.current;
    drawSprite(p, '#6366f1');

    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill();
    });
  };

  return (
    <div 
      className={`fixed inset-0 w-full h-full bg-black flex items-center justify-center`}
      style={{ cursor: 'none' }}
    >
      <canvas 
        ref={canvasRef} 
        width={GAME_WIDTH} 
        height={GAME_HEIGHT}
        className="bg-slate-900 shadow-2xl pointer-events-none"
        style={{
            maxWidth: '100%',
            maxHeight: '100%',
            objectFit: 'contain',
            aspectRatio: '16/9',
            cursor: 'none' 
        }}
      />

      {/* Fullscreen Toggle */}
      <button 
        onClick={toggleFullscreen}
        className="fixed top-4 right-4 z-50 bg-white/20 hover:bg-white/40 text-white p-2 rounded-lg backdrop-blur-sm transition-all pointer-events-auto"
        title="Toggle Fullscreen"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg>
      </button>

      {/* HUD Container */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level} (Bullets: {uiStats.projectileCount})
             </span>
        </div>
      </div>

      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}

      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in pointer-events-auto">
              <div className="w-[90vw] max-w-7xl p-8">
                  <h2 className="text-5xl font-black text-yellow-400 text-center mb-4 uppercase tracking-widest drop-shadow-md">Level Up!</h2>
                  <p className="text-center text-yellow-200 text-2xl mb-12 font-bold">+1 额外子弹 (被动获取)</p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                      {showUpgrades.map((opt, index) => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            onMouseEnter={() => {
                                if (inputMethod === 'MOUSE') {
                                    setUpgradeFocusedIndex(index);
                                }
                            }}
                            className={`p-10 rounded-3xl flex flex-col items-center gap-8 transition-all group border-4 relative overflow-hidden min-h-[400px] justify-center
                                ${inputMethod === 'GAMEPAD' ? 'pointer-events-none' : ''}
                                ${upgradeFocusedIndex === index 
                                    ? 'bg-slate-700 border-yellow-400 scale-105 shadow-2xl shadow-yellow-500/30 z-10' 
                                    : 'bg-slate-800 border-slate-600 hover:border-yellow-400 hover:bg-slate-700'
                                }`}
                          >
                              <div className={`text-8xl ${upgradeFocusedIndex === index ? 'animate-bounce' : 'group-hover:animate-bounce'}`}>{opt.icon}</div>
                              <div className="text-4xl font-black text-white">{opt.name}</div>
                              <div className="text-xl text-slate-300 text-center leading-relaxed font-medium">{opt.description}</div>
                              {upgradeFocusedIndex === index && (
                                  <div className="text-yellow-400 text-xl font-bold mt-4 animate-pulse tracking-widest border-2 border-yellow-400 px-4 py-1 rounded-full">
                                      [ A ] SELECT
                                  </div>
                              )}
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className={`fixed inset-0 z-50 flex items-center justify-center backdrop-blur-md ${gameResult === 'VICTORY' ? 'bg-yellow-900/90' : 'bg-red-900/90'} pointer-events-auto`}>
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className={`text-5xl font-black mb-2 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'YOU DIED'}
                  </h1>

                  <div className="text-6xl font-black text-slate-800 mb-8 drop-shadow-md">
                      {calculateScore()} <span className="text-2xl font-bold text-slate-500">PTS</span>
                  </div>

                  <div className="grid grid-cols-3 gap-4 mb-8 mt-6">
                      <div className="bg-slate-100 p-3 rounded-lg flex flex-col items-center">
                          <span className="text-2xl font-bold text-slate-700">{killCountsRef.current.mobs}</span>
                          <span className="text-xs text-slate-500 uppercase font-bold">小怪 (1pt)</span>
                      </div>
                      <div className="bg-slate-100 p-3 rounded-lg flex flex-col items-center">
                          <span className="text-2xl font-bold text-slate-700">{killCountsRef.current.elites}</span>
                          <span className="text-xs text-slate-500 uppercase font-bold">精英 (10pts)</span>
                      </div>
                      <div className="bg-slate-100 p-3 rounded-lg flex flex-col items-center border-2 border-yellow-400">
                          <span className="text-2xl font-bold text-yellow-600">{killCountsRef.current.bosses}</span>
                          <span className="text-xs text-slate-500 uppercase font-bold">BOSS (100pts)</span>
                      </div>
                  </div>

                  <p className="text-indigo-600 font-bold mb-8">最终等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

