// ==========================================
// SPRITE SHEET LOGIC
// ==========================================

// Assuming the sprite sheet is roughly a grid.
// Based on the provided image, we'll estimate grid locations.
// We assume a base tile size of 32x32 for standard mobs.
// We will return pixel coordinates {x, y, w, h}

const getRandomCoord = (row: number, cols: number, width = 32, height = 32): SpriteSource => {
  const col = Math.floor(Math.random() * cols);
  return {
    x: col * width,
    y: row * height,
    w: width,
    h: height
  };
};

export const getRandomSprite = (type: 'MOB' | 'ELITE' | 'BOSS'): SpriteSource => {
  // These rows are estimated based on the visual description of the sprite sheet.
  // Assuming a consistent grid for simplicity. 
  // If the sheet is irregular, these might need tuning.

  if (type === 'BOSS') {
    // Large monsters from bottom rows (Dragons, etc)
    // Assuming 64x64 or larger for these rows
    const row = Math.random() > 0.5 ? 9 : 11; // Rows 9 and 11
    return getRandomCoord(row, 4, 32, 32); // Scaling happens in rendering
  } 
  else if (type === 'ELITE') {
    // Medium monsters (Ogres, Wraiths, Bears)
    const rows = [1, 5, 10]; 
    const row = rows[Math.floor(Math.random() * rows.length)];
    return getRandomCoord(row, 4, 32, 32);
  } 
  else {
    // Small monsters (Goblins, Slimes, Skeletons, Insects)
    const rows = [0, 2, 3, 4, 6, 7];
    const row = rows[Math.floor(Math.random() * rows.length)];
    return getRandomCoord(row, 5, 32, 32);
  }
};

