// Singleton AudioContext to avoid hitting mobile browser limits
let audioCtx: AudioContext | null = null;
let bgmInterval: any = null;
let nextNoteTime = 0;
let beatCount = 0;
const TEMPO = 130;
const LOOKAHEAD = 25.0; // How frequently to call scheduling function (in milliseconds)
const SCHEDULE_AHEAD_TIME = 0.1; // How far ahead to schedule audio (sec)

const getAudioContext = () => {
  if (!audioCtx) {
    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    if (Ctx) {
      audioCtx = new Ctx();
    }
  }
  return audioCtx;
};

// Call this on user interaction (e.g. click) to unlock audio on iOS
export const resumeAudioContext = () => {
  const ctx = getAudioContext();
  if (ctx && ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Audio resume failed", e));
  }
};

// ==========================================
// BGM SEQUENCER (8-BIT ROCK)
// ==========================================

// Instruments
const playKick = (time: number) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.connect(gain);
    gain.connect(audioCtx.destination);

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(0.01, time + 0.5);
    gain.gain.setValueAtTime(0.5, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.5);

    osc.start(time);
    osc.stop(time + 0.5);
};

const playSnare = (time: number) => {
    if (!audioCtx) return;
    const bufferSize = audioCtx.sampleRate * 0.2; // 200ms
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1000;

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.4, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.2);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    noise.start(time);
};

const playHiHat = (time: number) => {
    if (!audioCtx) return;
    const bufferSize = audioCtx.sampleRate * 0.05; // 50ms
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 5000;

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.15, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    noise.start(time);
};

const playBass = (freq: number, time: number, duration: number) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.value = freq;

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.2, time);
    gain.gain.linearRampToValueAtTime(0.1, time + duration * 0.8);
    gain.gain.linearRampToValueAtTime(0, time + duration);

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(800, time);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    osc.start(time);
    osc.stop(time + duration);
};

const playLead = (freq: number, time: number, duration: number) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    osc.type = 'square';
    osc.frequency.value = freq;

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.1, time);
    gain.gain.linearRampToValueAtTime(0.05, time + duration * 0.9);
    gain.gain.linearRampToValueAtTime(0, time + duration);

    osc.connect(gain);
    gain.connect(audioCtx.destination);
    osc.start(time);
    osc.stop(time + duration);
};

// Scheduler
const scheduler = () => {
    if (!audioCtx) return;
    while (nextNoteTime < audioCtx.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(beatCount, nextNoteTime);
        nextNoteTime += 60.0 / TEMPO / 4; // 16th notes
        beatCount = (beatCount + 1) % 64; // 4 bars of 16th notes = 64 steps
    }
};

const scheduleNote = (beat: number, time: number) => {
    // 16th note duration
    const noteLen = 60.0 / TEMPO / 4;

    // --- DRUMS ---
    // Kick: 1, 5, 9, 13 (quarter notes approx)
    if (beat % 8 === 0) playKick(time);
    if (beat % 8 === 4) playSnare(time); // Backbeat
    if (beat % 2 === 0) playHiHat(time); // 8th note hi-hats

    // --- BASS (Driving E string) ---
    // Simple driving bassline on E2 (82.41Hz) changing to A2 (110Hz)
    const bassNote = beat < 32 ? 82.41 : 110.0; // 2 bars E, 2 bars A
    if (beat % 2 === 0) { // 8th notes
        playBass(bassNote, time, noteLen * 2);
    }

    // --- LEAD MELODY (Pentatonic Riff) ---
    // Only play on certain 16th notes
    // E Minor Pentatonic: E(329), G(392), A(440), B(493), D(587)
    const melodyPattern = [
        { step: 0, note: 329.63 }, // E4
        { step: 3, note: 392.00 }, // G4
        { step: 6, note: 440.00 }, // A4
        { step: 8, note: 329.63 }, // E4
        { step: 12, note: 293.66 }, // D4
        { step: 14, note: 329.63 }, // E4

        { step: 16, note: 440.00 }, // A4
        { step: 19, note: 493.88 }, // B4
        { step: 22, note: 587.33 }, // D5
        { step: 24, note: 440.00 }, // A4
        { step: 28, note: 392.00 }, // G4
        { step: 30, note: 440.00 }, // A4

        // Repeat or Variation for second half
        { step: 32, note: 440.00 }, // A4
        { step: 35, note: 493.88 }, // B4
        { step: 38, note: 587.33 }, // D5
        { step: 40, note: 659.25 }, // E5
        { step: 44, note: 587.33 }, // D5
        { step: 46, note: 493.88 }, // B4

        { step: 48, note: 659.25 }, // E5
        { step: 51, note: 587.33 }, // D5
        { step: 54, note: 493.88 }, // B4
        { step: 56, note: 440.00 }, // A4
        { step: 60, note: 392.00 }, // G4
        { step: 62, note: 329.63 }, // E4
    ];

    const hit = melodyPattern.find(p => p.step === beat);
    if (hit) {
        playLead(hit.note, time, noteLen * 1.5);
    }
};

export const startRockBGM = () => {
    resumeAudioContext();
    const ctx = getAudioContext();
    if (!ctx) return;

    if (bgmInterval) clearInterval(bgmInterval);

    // Reset timer
    nextNoteTime = ctx.currentTime + 0.1;
    beatCount = 0;

    bgmInterval = setInterval(scheduler, LOOKAHEAD);
};

export const stopBGM = () => {
    if (bgmInterval) {
        clearInterval(bgmInterval);
        bgmInterval = null;
    }
};

// ==========================================
// SFX (Existing)
// ==========================================

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  // Helper to play a bell-like note
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; // Sine wave for a pure bell tone
    osc.frequency.setValueAtTime(freq, startTime);

    // Envelope for bell sound: fast attack, exponential decay
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02); // Quick attack
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration); // Long decay

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // Play "Ding" (High Note, e.g., E5)
  playNote(659.25, now, 0.8);

  // Play "Dong" (Lower Note, e.g., C5) slightly later
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

export const playVictorySound = () => {
  stopBGM(); // Stop music on victory
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  const playNote = (freq: number, startTime: number, duration: number, type: OscillatorType = 'triangle') => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, startTime);

    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
    gain.gain.linearRampToValueAtTime(0, startTime + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // C Major Arpeggio fanfare
  playNote(523.25, now, 0.2);       // C5
  playNote(659.25, now + 0.15, 0.2); // E5
  playNote(783.99, now + 0.30, 0.2); // G5
  playNote(1046.50, now + 0.45, 0.8, 'sine'); // C6 (Long)

  // Confetti sound (noise burst)
  const bufferSize = ctx.sampleRate * 1; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;
  const noiseGain = ctx.createGain();
  noiseGain.gain.setValueAtTime(0.1, now + 0.45);
  noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  noise.connect(noiseGain);
  noiseGain.connect(ctx.destination);
  noise.start(now + 0.45);
};

export const playShootSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // Retro "Pew" sound: Square wave with fast frequency drop
  osc.type = 'square';
  osc.frequency.setValueAtTime(800, now);
  osc.frequency.exponentialRampToValueAtTime(100, now + 0.1);

  // Short, punchy envelope
  gain.gain.setValueAtTime(0.05, now);
  gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start(now);
  osc.stop(now + 0.1);
};

export const playHitSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const t = ctx.currentTime;

  // Impact noise (thud/splat)
  const bufferSize = ctx.sampleRate * 0.1; // 100ms
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;

  // Lowpass filter to make it sound like a solid hit rather than hiss
  const filter = ctx.createBiquadFilter();
  filter.type = 'lowpass';
  filter.frequency.setValueAtTime(1000, t);
  filter.frequency.linearRampToValueAtTime(100, t + 0.1);

  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0.2, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);

  noise.connect(filter);
  filter.connect(gain);
  gain.connect(ctx.destination);

  noise.start(t);
};

export const speakText = (text: string, rate: number = 1.0) => {
  if (!('speechSynthesis' in window)) return;

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US';
  utterance.rate = rate; 

  // Adjust pitch slightly higher to sound "younger"
  utterance.pitch = 1.15; 

  const voices = window.speechSynthesis.getVoices();

  // Priority list for female-sounding voices
  // 'Samantha' (iOS/Mac), 'Google US English' (Android/Chrome), 'Microsoft Zira' (Windows), 'Jenny'
  const preferredNames = ['Samantha', 'Google US English', 'Zira', 'Jenny', 'Susan', 'Vicki', 'Kathy'];

  const femaleVoice = voices.find(v => 
    preferredNames.some(name => v.name.includes(name)) && v.lang.startsWith('en')
  );

  // Fallback: try to find any English voice
  const fallbackVoice = voices.find(v => v.lang.startsWith('en'));

  if (femaleVoice) {
    utterance.voice = femaleVoice;
  } else if (fallbackVoice) {
    utterance.voice = fallbackVoice;
  }

  window.speechSynthesis.speak(utterance);
};

