  english: string;
  chinese: string;
}

export interface WordData {
  id: string;
  word: string;
  definition: string;
  exampleSentence: string;
  partOfSpeech: string;
  correctCount: number;
  lastPracticed?: string;
  imageUrl?: string;
  quote?: QuoteData; 
}

export interface QuizResult {
  wordId: string;
  correct: boolean;
}

export interface StoredData {
  cycleStart: number;
  words: WordData[];
}

// GAME SPECIFIC TYPES
export interface PlayerStats {
  hp: number;
  maxHp: number;
  speed: number;
  damage: number;
  attackSpeed: number; // Cooldown in frames
  projectileSpeed: number;
  pickupRange: number;
  projectileCount: number; // New: Number of bullets per shot
  level: number;
  xp: number;
  xpToNextLevel: number;
  // Elemental Upgrades
  hasFire?: boolean;
  hasIce?: boolean;
  hasLightning?: boolean;
  hasWind?: boolean;
}

export interface SpriteSource {
  x: number;
  y: number;
  w: number;
  h: number;
}

export interface Entity {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
