             {/* Glint effect */}
             <div className="absolute top-0 left-0 w-full h-1/2 bg-white/20"></div>

             <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md tracking-wider">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
