        </div>

        {/* XP BAR */}
        <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
             <div 
               className="h-full bg-gradient-to-r from-blue-600 to-blue-400 transition-all duration-300" 
               style={{ width: `${Math.min(100, (uiStats.xp / uiStats.xpToNextLevel) * 100)}%` }}
             ></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white drop-shadow-md tracking-wide">
                 LVL {uiStats.level}
             </span>
        </div>

        {/* STATS ROW */}
        <div className="flex items-center gap-4 mt-1">
            {/* Damage Stat */}
            <div className="flex items-center gap-2 bg-slate-800/80 backdrop-blur-sm px-4 py-2 rounded-xl border-2 border-slate-600 shadow-lg text-white">
                <span className="text-2xl">⚔️</span>
                <div className="flex flex-col">
                    <span className="text-[10px] text-slate-400 font-bold uppercase leading-none">Damage</span>
                    <span className="text-xl font-black text-yellow-400 leading-none">{uiStats.damage}</span>
                </div>
            </div>

            {/* Bullet Count */}
             <div className="flex items-center gap-2 bg-slate-800/80 backdrop-blur-sm px-4 py-2 rounded-xl border-2 border-slate-600 shadow-lg text-white">
                <span className="text-xl">✨</span>
                <div className="flex flex-col">
                    <span className="text-[10px] text-slate-400 font-bold uppercase leading-none">Bullets</span>
                    <span className="text-xl font-black text-cyan-400 leading-none">{uiStats.projectileCount}</span>
                </div>
            </div>
        </div>
      </div>

      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}

      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in pointer-events-auto">
              <div className="w-[90vw] max-w-7xl p-8">
                  <h2 className="text-5xl font-black text-yellow-400 text-center mb-4 uppercase tracking-widest drop-shadow-md">Level Up!</h2>
                  <p className="text-center text-yellow-200 text-2xl mb-12 font-bold">+1 额外子弹 (被动获取)</p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                      {showUpgrades.map((opt, index) => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            onMouseEnter={() => {
                                if (inputMethod === 'MOUSE') {
