export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: GAME_WIDTH / 2, 
    y: GAME_HEIGHT / 2, 
    width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, 
    speed: 4, 
    damage: 10, attackSpeed: 30, 
    projectileSpeed: 6, // Reduced speed
    pickupRange: 120,
    projectileCount: 1, 
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    hasFire: false, hasIce: false, hasLightning: false, hasWind: false
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]); // Ref for visual lightning effects
  const stormEffectsRef = useRef<StormEffect[]>([]); // Ref for visual storm effects
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  // Asset Refs
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);

  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);

  // Logic Refs
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  // UI Sync Refs
  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);
  const isGamepadActiveRef = useRef(false);

  // Input Method State
  const [inputMethod, setInputMethod] = useState<'MOUSE' | 'GAMEPAD'>('GAMEPAD');
  const lastMousePos = useRef({ x: 0, y: 0 });

  // -- REACT STATE --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  // Game Result Ref for Loop access
  const gameResultRef = useRef(gameResult);

  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);
  const [isGamepadActive, setIsGamepadActive] = useState(false);

  // Sync Refs with State
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { isGamepadActiveRef.current = isGamepadActive; }, [isGamepadActive]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
      if (!document.fullscreenElement) {
          document.documentElement.requestFullscreen().catch(() => {});
      } else {
          document.exitFullscreen().catch(() => {});
      }
  };

  // 1. INITIALIZE GAME DATA (Run Once)
  useEffect(() => {
    const style = document.createElement('style');
    style.innerHTML = `* { cursor: none !important; }`;
    document.head.appendChild(style);

    // START BGM
    startRockBGM();

    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);

    // GENERATE SPRITE SHEET IN MEMORY
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => {
        spriteSheetRef.current = sheet;
        areResourcesLoadedRef.current = true;
        setAreResourcesLoaded(true); // Trigger effect to start loop
    };
    sheet.onerror = () => {
        areResourcesLoadedRef.current = true;
        setAreResourcesLoaded(true); // Start anyway with fallback
    };

    // LOAD BASIC ASSETS (Hero, XP)
    const handleAssetLoad = (key: string, url: string) => {
        const img = new Image();
        img.src = url;
        spritesRef.current[key] = img;
    };
    loadBasicAssets(handleAssetLoad);

    // Input Tracking
    const handleMouseMove = (e: MouseEvent) => { 
        const dist = Math.abs(e.clientX - lastMousePos.current.x) + Math.abs(e.clientY - lastMousePos.current.y);
        if (dist > 5) {
            lastMousePos.current = { x: e.clientX, y: e.clientY };
            setInputMethod('MOUSE');
        }
    };
    const handleKeyDown = () => { setInputMethod('GAMEPAD'); };
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('keydown', handleKeyDown);

    return () => {
        stopBGM();
        document.head.removeChild(style);
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('keydown', handleKeyDown);
        cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // 2. INPUT HANDLERS
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { 
        if (isPausedRef.current) return;
        keysRef.current[e.key.toLowerCase()] = true; 

        if (isGamepadActiveRef.current) {
            setIsGamepadActive(false); 
        }
    };
    const handleKeyUp = (e: KeyboardEvent) => { 
        keysRef.current[e.key.toLowerCase()] = false; 
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // 3. SYSTEM GAMEPAD POLLING
  useEffect(() => {
    let rafId: number;
    let lastButtonState = false;

    const pollSystemButtons = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        if (gp.buttons[1]?.pressed && !lastButtonState) {
          toggleFullscreen();
        }
        lastButtonState = gp.buttons[1]?.pressed;
      }
      rafId = requestAnimationFrame(pollSystemButtons);
    };

    rafId = requestAnimationFrame(pollSystemButtons);
    return () => cancelAnimationFrame(rafId);
  }, []);

  // Gamepad Polling for Upgrade Menu
  useEffect(() => {
    if (!showUpgrades) return;

    let lastAxisX = 0;
    let lastButtonState = false;
    let rafId: number;

    // Keyboard Handler
    const handleMenuKey = (e: KeyboardEvent) => {
        setInputMethod('GAMEPAD');
        if (e.key === 'ArrowLeft') setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        if (e.key === 'ArrowRight') setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        if (e.key === 'Enter' || e.key === ' ') {
             const selected = showUpgrades[upgradeFocusedIndex];
             if (selected) applyUpgrade(selected);
        }
    };
    window.addEventListener('keydown', handleMenuKey);

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        const hasActivity = Math.abs(gp.axes[0]) > 0.5 || gp.buttons.some(b => b.pressed);
        if (hasActivity) {
            if (!isGamepadActive) setIsGamepadActive(true);
            if (inputMethod !== 'GAMEPAD') setInputMethod('GAMEPAD');
        }

        const axisX = gp.axes[0];
        const isLeft = axisX < -0.5 || gp.buttons[14]?.pressed;
        const isRight = axisX > 0.5 || gp.buttons[15]?.pressed;

        if (isLeft && lastAxisX >= -0.5) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        } else if (isRight && lastAxisX <= 0.5) {
            setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        }
        lastAxisX = axisX;

        if (gp.buttons[0]?.pressed && !lastButtonState) {
             const selected = showUpgrades[upgradeFocusedIndex];
             if (selected) applyUpgrade(selected);
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }

      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => {
        cancelAnimationFrame(rafId);
        window.removeEventListener('keydown', handleMenuKey);
    };
  }, [showUpgrades, upgradeFocusedIndex, isGamepadActive, inputMethod]);


  // === GAME LOOP SETUP ===
  useEffect(() => {
    if (!areResourcesLoaded) return;

    const loop = () => {
        if (gameResultRef.current !== 'PLAYING' || !areResourcesLoadedRef.current) return;

        if (!isPausedRef.current) update();
        draw();
        animationFrameId.current = requestAnimationFrame(loop);
    };

    animationFrameId.current = requestAnimationFrame(loop);

    return () => {
        cancelAnimationFrame(animationFrameId.current);
    };
  }, [areResourcesLoaded]);

  // === UPDATE LOGIC ===
  const update = () => {
    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    const player = playerRef.current;
    const stats = statsRef.current;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0; let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0];
    if (gp) {
        const deadzone = 0.2;
        let hasInput = false;

        if (Math.abs(gp.axes[0]) > deadzone) { dx += gp.axes[0]; hasInput = true; }
        if (Math.abs(gp.axes[1]) > deadzone) { dy += gp.axes[1]; hasInput = true; }
        if (gp.buttons[12]?.pressed) { dy -= 1; hasInput = true; }
        if (gp.buttons[13]?.pressed) { dy += 1; hasInput = true; }
        if (gp.buttons[14]?.pressed) { dx -= 1; hasInput = true; }
        if (gp.buttons[15]?.pressed) { dx += 1; hasInput = true; }

        if (hasInput && !isGamepadActiveRef.current) {
            setIsGamepadActive(true);
        }
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        if (Math.abs(dx) > Math.abs(dy)) {
            player.direction = dx > 0 ? 'RIGHT' : 'LEFT';
        } else {
            player.direction = dy > 0 ? 'DOWN' : 'UP';
        }

        const length = Math.sqrt(dx * dx + dy * dy);
        const normalizedFactor = length > 1 ? 1 / length : 1;
        player.x += (dx * normalizedFactor) * stats.speed;
        player.y += (dy * normalizedFactor) * stats.speed;
    } else {
        player.isMoving = false;
    }

    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 120) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }

    const halfW = player.width / 2;
    const halfH = player.height / 2;
    player.x = Math.max(halfW, Math.min(GAME_WIDTH - halfW, player.x));
    player.y = Math.max(halfH, Math.min(GAME_HEIGHT - halfH, player.y));

    spawnEnemies();

    // 2. Enemy Logic
    enemiesRef.current.forEach(enemy => {
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);

      // Calculate Base Speed
      let speed = enemy.type.includes('ELITE') ? 2.0 
                  : enemy.type === 'BOSS' ? 1.2 
                  : 1.5;

      // ICE STATUS: Slow down by 50%
      if (enemy.freezeTimer && enemy.freezeTimer > 0) {
          speed *= 0.5;
          enemy.freezeTimer--;
      }

      // BURN STATUS: DoT
      if (enemy.burnTimer && enemy.burnTimer > 0) {
          enemy.burnTimer--;
          // Tick damage every 30 frames (0.5s)
          if (frameCountRef.current % 30 === 0) {
              enemy.hp -= 1; // 1 damage per tick
              // Visual feedback for burn tick could go here
          }
      }

      enemy.vx = Math.cos(angle) * speed;
      enemy.vy = Math.sin(angle) * speed;
      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) spawnBossBullets(enemy);
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) spawnEnemyBullet(enemy, player);

      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(enemy.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    // 3. Projectile Logic
    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;

      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 15)) {
              enemy.hp -= p.damage;

              // APPLY STATUS EFFECTS AND SOUNDS
              if (p.element === 'ICE') {
                  enemy.freezeTimer = 180; // 3 seconds at 60fps
                  try { playIceHitSound(); } catch(e) {}
              } else if (p.element === 'FIRE') {
                  enemy.burnTimer = 300; // 5 seconds burn
                  try { playFireHitSound(); } catch(e) {}
              } else if (p.element === 'LIGHTNING') {
                  // CHAIN LIGHTNING LOGIC
                  // Find nearest 5 enemies
                  const neighbors = enemiesRef.current
                    .filter(e => e !== enemy && Math.hypot(e.x - enemy.x, e.y - enemy.y) < 400) // 400px range
                    .sort((a, b) => {
                        const d1 = Math.hypot(a.x - enemy.x, a.y - enemy.y);
                        const d2 = Math.hypot(b.x - enemy.x, b.y - enemy.y);
                        return d1 - d2;
                    })
                    .slice(0, 5);

                  // Deal half damage to them
                  neighbors.forEach(n => {
                      n.hp -= Math.ceil(p.damage / 2);
                      // VISUAL: Create lightning chains (Doubled duration to 10)
                      lightningChainsRef.current.push({
                          x1: enemy.x, y1: enemy.y,
                          x2: n.x, y2: n.y,
                          life: 10 
                      });
                  });
                  try { playLightningHitSound(); } catch(e) {}
              } else if (p.element === 'WIND') {
                  // WIND PULL LOGIC
                  // Pull nearby enemies towards the hit target
                  const pullRadius = 250;
                  const pullForce = 20;

                  enemiesRef.current.forEach(other => {
                      if (other !== enemy) {
                          const dist = Math.hypot(other.x - enemy.x, other.y - enemy.y);
                          if (dist < pullRadius) {
                              const angle = Math.atan2(enemy.y - other.y, enemy.x - other.x);
                              other.x += Math.cos(angle) * pullForce;
                              other.y += Math.sin(angle) * pullForce;
                          }
                      }
                  });

                  // VISUAL: Add Storm Effect
                  stormEffectsRef.current.push({
                      x: enemy.x,
                      y: enemy.y,
                      life: 30, // 0.5 seconds
                      maxLife: 30,
                      angle: Math.random() * Math.PI * 2
                  });
                  try { playWindHitSound(); } catch(e) {}
              } else {
                  try { playHitSound(); } catch(e) {}
              }

              hit = true;
              break;
            }
          }
      } else {
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 15)) {
               takeDamage(p.damage);
               hit = true;
           }
      }
      const oob = p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT;
      return !oob && !hit;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') {
            killCountsRef.current.bosses++;
            setGameResult('VICTORY');
            playVictorySound();
            isPausedRef.current = true;
        } else if (e.type.includes('ELITE')) {
            killCountsRef.current.elites++;
        } else {
            killCountsRef.current.mobs++;
        }

        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 24, height: 24, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        gem.x += (player.x - gem.x) * 0.15;
        gem.y += (player.y - gem.y) * 0.15;
        if (dist < 30) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const calculateScore = () => {
    return (killCountsRef.current.mobs * 1) + 
           (killCountsRef.current.elites * 10) + 
           (killCountsRef.current.bosses * 100);
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;

      // Changed Logic: 1.5x increase instead of 2x
      let spawnRate = Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1));
      spawnRate = Math.max(5, spawnRate);

      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS');
          bossSpawnedRef.current = true;
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = 'MOB';

          const canSpawnElite = statsRef.current.level > 1;
          if (canSpawnElite && time > 30 && r > 0.9) type = 'ELITE';
          if (canSpawnElite && time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      const spriteSource = getRandomSprite(category);

      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: category === 'ELITE' && Math.random() > 0.5 ? 'ELITE_RANGED' : category as any,
          width: 50, height: 50, 
          hp: 2, maxHp: 2, damage: 1,
          spriteSource: spriteSource,
          freezeTimer: 0,
          burnTimer: 0
      };

      if (category === 'BOSS') {
          entity = { ...entity, width: 250, height: 250, hp: 1000, maxHp: 1000, damage: 10 };
      } else if (category === 'ELITE') {
          entity = { ...entity, hp: 40, maxHp: 40, damage: 5, width: 90, height: 90 }; 
      } else {
          entity = { ...entity, hp: 2, maxHp: 2 };
      }
      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    try { playShootSound(); } catch(e) {}
    const p = playerRef.current;
    const s = statsRef.current;
    const count = s.projectileCount || 1;

    // Determine Element
    let element: 'NORMAL' | 'FIRE' | 'ICE' | 'LIGHTNING' | 'WIND' = 'NORMAL';
    if (s.hasLightning) element = 'LIGHTNING';
    else if (s.hasFire) element = 'FIRE';
    else if (s.hasIce) element = 'ICE';
    else if (s.hasWind) element = 'WIND';

    for (let i = 0; i < count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const offsetX = (Math.random() - 0.5) * p.width * 0.8;
            const offsetY = (Math.random() - 0.5) * p.height * 0.8;

            projectilesRef.current.push({
            id: Math.random().toString(),
            x: p.x + offsetX,
            y: p.y + offsetY,
            width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(angle) * s.projectileSpeed,
            vy: Math.sin(angle) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage,
            element: element
        });
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 20, height: 20, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 5, vy: Math.sin(angle) * 5, hp: 1, maxHp: 1, damage: 5
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      for (let i = 0; i < 12; i++) {
          const angle = (Math.PI * 2 / 12) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 24, height: 24, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 6, vy: Math.sin(angle) * 6, hp: 1, maxHp: 1, damage: 10
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp();
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      keysRef.current = {}; 
      if (remainingWordsRef.current.length > 0) {
          const nextWord = remainingWordsRef.current.pop();
          if (nextWord) {
              setQuizWord(nextWord);
              return;
          }
      } 
      showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true; 

      const currentStats = statsRef.current;
      const hasElementalUpgrade = currentStats.hasFire || currentStats.hasIce || currentStats.hasLightning || currentStats.hasWind;

      // 1. Filter Available Upgrades
      // If player already has an element, hide all elemental upgrades to prevent switching/stacking bugs
      let availableOptions = UPGRADES.filter(option => {
          if (hasElementalUpgrade && ['fire_shot', 'ice_shot', 'lightning_shot', 'wind_shot'].includes(option.id)) {
              return false;
          }
          return true;
      });

      // 2. Weighted Random Selection
      // We want to pick 3 options.
      // Multishot has weight 0.2 (20% relative to normal 1.0)
      const selectedOptions: UpgradeOption[] = [];
      const countToSelect = Math.min(3, availableOptions.length);

      for (let i = 0; i < countToSelect; i++) {
          // Calculate total weight of currently available options
          const totalWeight = availableOptions.reduce((sum, opt) => {
              const weight = opt.id === 'multishot' ? 0.2 : 1.0;
              return sum + weight;
          }, 0);

          let randomVal = Math.random() * totalWeight;
          let selectedIndex = -1;

          // Find which item corresponds to the random value
          for (let j = 0; j < availableOptions.length; j++) {
              const opt = availableOptions[j];
              const weight = opt.id === 'multishot' ? 0.2 : 1.0;
              randomVal -= weight;
              if (randomVal <= 0) {
                  selectedIndex = j;
                  break;
              }
          }

          // Fallback if float rounding errors occur
          if (selectedIndex === -1) selectedIndex = availableOptions.length - 1;

          selectedOptions.push(availableOptions[selectedIndex]);

          // Remove selected from pool so we don't pick it again this round
          availableOptions.splice(selectedIndex, 1);
      }

      setShowUpgrades(selectedOptions);
      setUpgradeFocusedIndex(1); // Reset focus to middle
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) { 
          showUpgradeMenu(); 
      } else {
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = statsRef.current.xpToNextLevel + 2;
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.projectileCount += 1; // Passive +1 bullet every level

      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = statsRef.current.xpToNextLevel * 2;

      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.fillStyle = '#0f172a'; 
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < GAME_WIDTH; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke();
    }
    for (let y = 0; y < GAME_HEIGHT; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke();
    }

    // DRAW ENTITY HELPER
    const drawSprite = (e: Entity, fallbackColor: string) => {
        // Visual indicators for Status Effects
        if (e.freezeTimer && e.freezeTimer > 0) {
             ctx.globalAlpha = 0.8;
             ctx.fillStyle = '#93c5fd'; // Light blue aura
             ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2 + 5, 0, Math.PI * 2); ctx.fill();
             ctx.globalAlpha = 1.0;

             // FLASH WHITE effect for frozen enemies
             // Flash every 200ms approx
             if (Math.floor(Date.now() / 100) % 2 === 0) {
                 ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
                 ctx.beginPath(); 
                 ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2); 
                 ctx.fill();
             }
        }
        if (e.burnTimer && e.burnTimer > 0) {
             // Flickering fire effect
             if (Math.random() > 0.5) {
                ctx.fillStyle = '#ef4444'; 
                ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2 + 3, 0, Math.PI * 2); ctx.fill();
             }
        }

        // 1. If it has a Sprite Source (from sheet) AND Sheet is loaded
        if (e.spriteSource && spriteSheetRef.current && spriteSheetRef.current.complete && spriteSheetRef.current.naturalWidth > 0) {
            ctx.imageSmoothingEnabled = false; // Pixel art look
            ctx.drawImage(
                spriteSheetRef.current,
                e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, // Source
                e.x - e.width / 2, e.y - e.height / 2, e.width, e.height // Dest
            );
            return;
        }

        // 2. If it has a dedicated asset URL (Hero, XP, or legacy assets)
        let spriteKey: string = e.type;
        if (e.type === 'HERO') {
            const dir = e.direction || 'DOWN';
            if (!e.isMoving && spritesRef.current['HERO_IDLE']) {
                spriteKey = 'HERO_IDLE';
            } else if (spritesRef.current[`HERO_${dir}`]) {
                spriteKey = `HERO_${dir}`;
            }
        } else if (e.spriteUrl) {
            spriteKey = e.spriteUrl;
        }

        const sprite = spritesRef.current[spriteKey];
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            const isStrip = sprite.naturalWidth > sprite.naturalHeight;
            if (isStrip && e.type === 'HERO') {
                const frameCount = Math.round(sprite.naturalWidth / sprite.naturalHeight);
                const frameIndex = (e.animFrame || 0) % frameCount;
                const fw = sprite.naturalWidth / frameCount;
                const fh = sprite.naturalHeight;

                ctx.drawImage(
                    sprite, 
                    frameIndex * fw, 0, fw, fh, 
                    e.x - e.width/2, e.y - e.height/2, e.width, e.height
                );
            } else {
                ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        } else {
            // Fallback Circle/Rect
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2); ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    xpGemsRef.current.forEach(gem => drawSprite(gem, '#fbbf24'));
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
    });

    // Draw Lightning Chains
    lightningChainsRef.current = lightningChainsRef.current.filter(chain => {
        if (chain.life <= 0) return false;

        ctx.strokeStyle = `rgba(180, 230, 255, ${chain.life / 5})`; // Fade out
        ctx.lineWidth = 3;
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#00ffff';

        ctx.beginPath();
        ctx.moveTo(chain.x1, chain.y1);

        // Add a midpoint jitter for lightning look
        const midX = (chain.x1 + chain.x2) / 2 + (Math.random() - 0.5) * 40;
        const midY = (chain.y1 + chain.y2) / 2 + (Math.random() - 0.5) * 40;

        ctx.lineTo(midX, midY);
        ctx.lineTo(chain.x2, chain.y2);
        ctx.stroke();

        ctx.shadowBlur = 0; // Reset

        chain.life--;
        return true;
    });

    // Draw Storm Effects
    stormEffectsRef.current = stormEffectsRef.current.filter(storm => {
        if (storm.life <= 0) return false;

        const alpha = storm.life / storm.maxLife;

        ctx.save();
        ctx.translate(storm.x, storm.y);
        ctx.rotate(storm.angle);

        ctx.strokeStyle = `rgba(165, 243, 252, ${alpha})`; // Cyan-200
        ctx.lineWidth = 3;

        // Draw 3 spiral arms
        for(let i=0; i<3; i++) {
            ctx.beginPath();
            // Spiral shape logic
            ctx.arc(0, 0, 30 + Math.sin(storm.life * 0.2) * 10, i * (Math.PI*2/3), i * (Math.PI*2/3) + Math.PI/2);
            ctx.stroke();
        }

        // Center eye
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha * 0.5})`;
        ctx.beginPath();
        ctx.arc(0, 0, 10, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();

        storm.life--;
        storm.angle += 0.2; // Spin speed
        return true;
    });

    const p = playerRef.current;
    drawSprite(p, '#6366f1');

    projectilesRef.current.forEach(p => {
        if (p.type === 'PROJECTILE') {
            // ELEMENTAL COLORS
            if (p.element === 'FIRE') ctx.fillStyle = '#ef4444'; // Red
            else if (p.element === 'ICE') ctx.fillStyle = '#ffffff'; // White
            else if (p.element === 'LIGHTNING') ctx.fillStyle = '#3b82f6'; // Blue
            else if (p.element === 'WIND') ctx.fillStyle = '#22d3ee'; // Cyan
            else ctx.fillStyle = '#94a3b8'; // Default Gray (New)
        } else {
            ctx.fillStyle = '#ef4444'; // Enemy Projectile Red
        }
        ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill();

        // Add glow for elements
        if (p.type === 'PROJECTILE' && p.element !== 'NORMAL') {
             ctx.globalAlpha = 0.3;
             ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2 + 4, 0, Math.PI*2); ctx.fill();
             ctx.globalAlpha = 1.0;
        }
    });
  };

  return (
    <div 
      className={`fixed inset-0 w-full h-full bg-black flex items-center justify-center`}
      style={{ cursor: 'none' }}
    >
      <canvas 
        ref={canvasRef} 
        width={GAME_WIDTH} 
        height={GAME_HEIGHT}
        className="bg-slate-900 shadow-2xl pointer-events-none"
        style={{
            maxWidth: '100%',
            maxHeight: '100%',
            objectFit: 'contain',
            aspectRatio: '16/9',
            cursor: 'none' 
        }}
      />

      <button 
        onClick={toggleFullscreen}
        className="fixed top-4 right-4 z-50 bg-white/20 hover:bg-white/40 text-white p-2 rounded-lg backdrop-blur-sm transition-all pointer-events-auto"
        title="Toggle Fullscreen"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg>
      </button>

      <div className="fixed top-6 left-6 flex flex-col gap-3 pointer-events-none z-10 font-mono">
        {/* HP BAR */}
        <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-[0_4px_0_#00000040]">
             <div 
               className="h-full bg-gradient-to-r from-red-600 to-red-500 transition-all duration-300" 
               style={{ width: `${Math.max(0, (uiStats.hp / uiStats.maxHp) * 100)}%` }}
             ></div>
             {/* Glint effect */}
             <div className="absolute top-0 left-0 w-full h-1/2 bg-white/20"></div>

             <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md tracking-wider">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>

        {/* XP BAR */}
        <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
             <div 
               className="h-full bg-gradient-to-r from-blue-600 to-blue-400 transition-all duration-300" 
               style={{ width: `${Math.min(100, (uiStats.xp / uiStats.xpToNextLevel) * 100)}%` }}
             ></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white drop-shadow-md tracking-wide">
                 LVL {uiStats.level}
             </span>
        </div>

        {/* STATS ROW */}
        <div className="flex items-center gap-4 mt-1">
            {/* Damage Stat */}
            <div className="flex items-center gap-2 bg-slate-800/80 backdrop-blur-sm px-4 py-2 rounded-xl border-2 border-slate-600 shadow-lg text-white">
                <span className="text-2xl">⚔️</span>
                <div className="flex flex-col">
                    <span className="text-[10px] text-slate-400 font-bold uppercase leading-none">Damage</span>
                    <span className="text-xl font-black text-yellow-400 leading-none">{uiStats.damage}</span>
                </div>
            </div>

            {/* Bullet Count */}
             <div className="flex items-center gap-2 bg-slate-800/80 backdrop-blur-sm px-4 py-2 rounded-xl border-2 border-slate-600 shadow-lg text-white">
                <span className="text-xl">✨</span>
                <div className="flex flex-col">
                    <span className="text-[10px] text-slate-400 font-bold uppercase leading-none">Bullets</span>
                    <span className="text-xl font-black text-cyan-400 leading-none">{uiStats.projectileCount}</span>
                </div>
            </div>
        </div>
      </div>

