// ELEMENTAL HIT SOUNDS
// ==========================================

export const playFireHitSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;
  const t = ctx.currentTime;

  // Explosion/Burn noise: Low pitched, heavy decay
  const bufferSize = ctx.sampleRate * 0.3;
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;

  const filter = ctx.createBiquadFilter();
  filter.type = 'lowpass';
  filter.frequency.setValueAtTime(800, t);
  filter.frequency.exponentialRampToValueAtTime(50, t + 0.25);

  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0.4, t);
  gain.gain.exponentialRampToValueAtTime(0.01, t + 0.25);

  noise.connect(filter);
  filter.connect(gain);
  gain.connect(ctx.destination);
  noise.start(t);
};

export const playIceHitSound = () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    const t = ctx.currentTime;

    // Glass shatter / Crystal ping: High pitch sine/triangle
    const osc = ctx.createOscillator();
    osc.type = 'triangle'; // Clearer than sine, less harsh than saw
    osc.frequency.setValueAtTime(2200, t);
    osc.frequency.exponentialRampToValueAtTime(1500, t + 0.15);

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.2, t);
    gain.gain.exponentialRampToValueAtTime(0.01, t + 0.15);

    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(t);
    osc.stop(t + 0.15);

    // Optional secondary high chime for sparkle
    const osc2 = ctx.createOscillator();
    osc2.type = 'sine';
    osc2.frequency.setValueAtTime(3500, t);
    const gain2 = ctx.createGain();
    gain2.gain.setValueAtTime(0.1, t);
    gain2.gain.exponentialRampToValueAtTime(0.01, t + 0.1);
    osc2.connect(gain2);
    gain2.connect(ctx.destination);
    osc2.start(t);
    osc2.stop(t + 0.1);
};

export const playLightningHitSound = () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    const t = ctx.currentTime;

    // Zap: Sawtooth with very fast frequency drop + noise
    const osc = ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(1200, t);
    osc.frequency.exponentialRampToValueAtTime(100, t + 0.15);

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.15, t);
    gain.gain.exponentialRampToValueAtTime(0.01, t + 0.15);

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 800;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);
    osc.start(t);
    osc.stop(t + 0.15);
};

export const playWindHitSound = () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    const t = ctx.currentTime;

    // Whoosh: White noise with bandpass sweep
    const bufferSize = ctx.sampleRate * 0.4;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    const noise = ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(300, t);
    filter.frequency.linearRampToValueAtTime(1200, t + 0.2); // Sweep up
    filter.Q.value = 2; // Resonance for 'whistling' wind sound

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.3, t);
    gain.gain.exponentialRampToValueAtTime(0.01, t + 0.3);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);
    noise.start(t);
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number;
}

const UPGRADES: UpgradeOption[] = [
  { id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) },
  { id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', apply: (s) => ({ ...s, speed: s.speed * 1.2 }) },
  { id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫', apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.85)) }) },
  { id: 'hp_up', name: '坚韧', description: '最大生命 +30 (当前+30)', icon: '❤️', apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.hp + 30 }) },
  { id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨', apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) },
  { id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲', apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) },
  { id: 'fire_shot', name: '火焰弹', description: '灼烧伤害', icon: '🔥', apply: (s) => ({ ...s, hasFire: true, hasIce: false, hasLightning: false, hasWind: false }) },
  { id: 'ice_shot', name: '冰冻弹', description: '减速敌人', icon: '❄️', apply: (s) => ({ ...s, hasFire: false, hasIce: true, hasLightning: false, hasWind: false }) },
  { id: 'lightning_shot', name: '闪电弹', description: '弹射伤害', icon: '⚡', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: true, hasWind: false }) },
  { id: 'wind_shot', name: '风暴弹', description: '聚拢敌人', icon: '🌀', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: false, hasWind: true }) }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    hasFire: false, hasIce: false, hasLightning: false, hasWind: false
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const touchVectorRef = useRef({ x: 0, y: 0 }); // For Mobile D-Pad

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    const style = document.createElement('style');
    style.innerHTML = `* { cursor: none !important; touch-action: none; }`;
    document.head.appendChild(style);
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); document.head.removeChild(style); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { if (!isPausedRef.current) keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (gameResultRef.current !== 'PLAYING' || !areResourcesLoadedRef.current) return;
        if (!isPausedRef.current) update();
        draw();
        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded]);

  const update = () => {
    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }
    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Mobile D-Pad Input
    if (touchVectorRef.current.x !== 0 || touchVectorRef.current.y !== 0) {
        dx += touchVectorRef.current.x;
        dy += touchVectorRef.current.y;
    }

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 120) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }
      if (e.burnTimer && e.burnTimer > 0) { e.burnTimer--; if (frameCountRef.current % 30 === 0) e.hp -= 1; }
      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { enemy.freezeTimer = 180; playIceHitSound(); }
              else if (p.element === 'FIRE') { enemy.burnTimer = 300; playFireHitSound(); }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, 5);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  enemiesRef.current.forEach(other => { if(other!==enemy && Math.hypot(other.x-enemy.x, other.y-enemy.y) < 250) { const a = Math.atan2(enemy.y-other.y, enemy.x-other.x); other.x += Math.cos(a)*20; other.y += Math.sin(a)*20; } });
                  stormEffectsRef.current.push({x:enemy.x, y:enemy.y, life:30, maxLife:30, angle:Math.random()*Math.PI*2});
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.hasLightning ? 'LIGHTNING' : (s.hasFire ? 'FIRE' : (s.hasIce ? 'ICE' : (s.hasWind ? 'WIND' : 'NORMAL')));
    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const opts = UPGRADES.filter(o => !(statsRef.current.hasFire || statsRef.current.hasIce || statsRef.current.hasLightning || statsRef.current.hasWind) || !['fire_shot', 'ice_shot', 'lightning_shot', 'wind_shot'].includes(o.id)).sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(opts); setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { statsRef.current = o.apply(statsRef.current); statsRef.current.level++; statsRef.current.xp = 0; statsRef.current.xpToNextLevel *= 2; setShowUpgrades(null); isPausedRef.current = false; };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });
    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  // --- MOBILE TOUCH HANDLING ---
  const handleTouch = (dir: 'UP' | 'DOWN' | 'LEFT' | 'RIGHT' | null) => {
      const v = touchVectorRef.current;
      if (!dir) { v.x = 0; v.y = 0; return; }
      if (dir === 'UP') v.y = -1;
      if (dir === 'DOWN') v.y = 1;
      if (dir === 'LEFT') v.x = -1;
      if (dir === 'RIGHT') v.x = 1;
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex flex-col items-center justify-center overflow-hidden touch-none">
      <div className="relative w-full h-full flex items-center justify-center p-[env(safe-area-inset-top)_env(safe-area-inset-right)_env(safe-area-inset-bottom)_env(safe-area-inset-left)]">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl max-w-full max-h-full object-contain aspect-video"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-4 left-4 sm:top-8 sm:left-8 flex flex-col gap-2 pointer-events-none scale-75 sm:scale-100 origin-top-left">
            <div className="w-64 sm:w-96 h-8 sm:h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-sm sm:text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-64 sm:w-96 h-4 sm:h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-4 right-4 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>

          {/* VIRTUAL D-PAD (Bottom Left) */}
          <div className="absolute bottom-8 left-8 flex items-center justify-center sm:hidden z-20">
              <div className="relative w-40 h-40 grid grid-cols-3 grid-rows-3 gap-1 opacity-50">
                  <div className="col-start-2 bg-slate-700/50 rounded-lg flex items-center justify-center active:bg-slate-500 active:scale-95"
                       onTouchStart={() => handleTouch('UP')} onTouchEnd={() => handleTouch(null)}>🔼</div>
                  <div className="row-start-2 col-start-1 bg-slate-700/50 rounded-lg flex items-center justify-center active:bg-slate-500 active:scale-95"
                       onTouchStart={() => handleTouch('LEFT')} onTouchEnd={() => handleTouch(null)}>◀️</div>
                  <div className="row-start-2 col-start-3 bg-slate-700/50 rounded-lg flex items-center justify-center active:bg-slate-500 active:scale-95"
                       onTouchStart={() => handleTouch('RIGHT')} onTouchEnd={() => handleTouch(null)}>▶️</div>
                  <div className="row-start-3 col-start-2 bg-slate-700/50 rounded-lg flex items-center justify-center active:bg-slate-500 active:scale-95"
                       onTouchStart={() => handleTouch('DOWN')} onTouchEnd={() => handleTouch(null)}>🔽</div>
              </div>
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map(o => (
                          <button key={o.id} onClick={() => applyUpgrade(o)} className="p-6 bg-slate-800 border-4 border-slate-600 rounded-2xl hover:border-yellow-400 text-white flex flex-col items-center gap-2">
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>
                  <button onClick={() => window.location.reload()} className="w-full py-4 bg-slate-800 text-white font-bold rounded-xl mb-3">RETRY</button>
                  <button onClick={onExit} className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl">EXIT</button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { GameArena } from './components/GameArena';
import { WordInput } from './components/WordInput';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState, StoredData } from './types';
import { streamVocabularyEnrichment, fetchMediaForWord } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexisurvivor_data';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT); 
  const [words, setWords] = useState<WordData[]>([]);
  const [cycleStart, setCycleStart] = useState<number>(Date.now());
  const [isGenerating, setIsGenerating] = useState(false);
  const [view, setView] = useState<'IDLE' | 'GAME'>('IDLE');

  // 1. Load Data from Storage
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed: StoredData = JSON.parse(saved);
        setWords(parsed.words);
        setCycleStart(parsed.cycleStart);
        // If we have words, show the dashboard (which is under INPUT state in the original design)
      } catch (e) {
        console.error("Failed to parse storage", e);
      }
    }
  }, []);

  // 2. Handle Manual Input Submission
  const handleWordSubmit = async (inputWords: string[]) => {
    setIsGenerating(true);
    const newWords: WordData[] = [];

    try {
      await streamVocabularyEnrichment(inputWords, (word) => {
        newWords.push(word);
        setWords(prev => [...prev, word]);
      });

      // Save to storage
      const data: StoredData = {
        cycleStart: Date.now(),
        words: newWords
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      setCycleStart(data.cycleStart);
      toast.success(`成功生成 ${newWords.length} 个单词！`);
    } catch (error: any) {
      toast.error(error.message || "生成失败，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleClearData = () => {
    if (window.confirm("确定要清除本周词库并重新输入吗？")) {
      setWords([]);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const updateWord = (id: string, updates: Partial<WordData>) => {
    setWords(prev => {
      const next = prev.map(w => w.id === id ? { ...w, ...updates } : w);
      // Persist updates (like correct count)
      const data: StoredData = { cycleStart, words: next };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      return next;
    });
  };

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative">

      {view === 'IDLE' && (
        <div className="w-full h-full flex flex-col items-center justify-center p-4 bg-pattern overflow-y-auto">
             <div className="absolute inset-0 bg-slate-900 opacity-90 z-0 pointer-events-none"></div>

             <div className="relative z-10 w-full max-w-4xl py-12">
                 {words.length === 0 ? (
                    <WordInput 
                        onSubmit={handleWordSubmit} 
                        isLoading={isGenerating} 
                        hasExistingData={false} 
                    />
                 ) : (
                    <div className="animate-fade-in">
                        <div className="text-center mb-10">
                            <h1 className="text-5xl font-black text-white mb-2 tracking-tighter uppercase transform -rotate-1 italic">
                                英语<span className="text-indigo-500">幸存者</span>
                            </h1>
                            <p className="text-slate-400 font-bold tracking-widest uppercase text-xs">Vocabulary Survival</p>
                        </div>

                        <Dashboard 
                            words={words} 
                            onStartQuiz={() => setView('GAME')} 
                            onNewWeek={handleClearData} 
                            cycleStart={cycleStart} 
                        />
                    </div>
                 )}
             </div>
        </div>
      )}

      {view === 'GAME' && (
        <GameArena 
          words={words} 
          onExit={() => setView('IDLE')}
        />
      )}

      <Toaster position="top-center" />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { WordData } from '../types';
import { speakText, playSuccessSound, playErrorSound } from '../services/audioService';

interface GameQuizModalProps {
  word: WordData;
  allWords: WordData[];
  onResult: (correct: boolean) => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const GameQuizModal: React.FC<GameQuizModalProps> = ({ word, allWords, onResult }) => {
  const [mode, setMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [input, setInput] = useState('');
  const [choices, setChoices] = useState<WordData[]>([]);
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [focusedChoiceIndex, setFocusedChoiceIndex] = useState(0);
  const [isMobile, setIsMobile] = useState(false);
  const [isInputFocused, setIsInputFocused] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);

  const [inputMethod, setInputMethod] = useState<'MOUSE' | 'GAMEPAD'>('GAMEPAD');
  const lastMousePos = useRef({ x: 0, y: 0 });

  // Detect Mobile
  useEffect(() => {
    setIsMobile(/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent));
  }, []);

  // Input Method Tracking
  useEffect(() => {
      const handleMouseMove = (e: MouseEvent) => { 
          const dist = Math.abs(e.clientX - lastMousePos.current.x) + Math.abs(e.clientY - lastMousePos.current.y);
          if (dist > 5) {
             lastMousePos.current = { x: e.clientX, y: e.clientY };
             setInputMethod('MOUSE');
          }
      };
      const handleKeyDown = () => { setInputMethod('GAMEPAD'); };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('keydown', handleKeyDown);
      return () => {
          window.removeEventListener('mousemove', handleMouseMove);
          window.removeEventListener('keydown', handleKeyDown);
      };
  }, []);

  // Setup
  useEffect(() => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const selectedMode = modes[Math.floor(Math.random() * modes.length)];
    setMode(selectedMode);

    if (selectedMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (selectedMode === 'SPELL_FROM_AUDIO') {
      setTimeout(() => speakText(word.word), 300);
    }

    // Only auto-focus on Desktop to avoid sudden keyboard pop-up on mobile
    if (!/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)) {
        setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [word, allWords]);

  // Keyboard Support for Choices
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (mode === 'MEANING_FROM_WORD' && status === 'idle') {
            if (['ArrowUp', 'ArrowLeft', 'ArrowDown', 'ArrowRight', 'Enter', ' '].includes(e.key)) {
                setInputMethod('GAMEPAD');
            }
            if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
                 setFocusedChoiceIndex(prev => Math.max(0, prev - 1));
            }
            if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
                 setFocusedChoiceIndex(prev => Math.min(choices.length - 1, prev + 1));
            }
            if (e.key === 'Enter' || e.key === ' ') {
                if (choices[focusedChoiceIndex]) checkChoice(choices[focusedChoiceIndex].id);
            }
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [mode, status, choices, focusedChoiceIndex]);

  // Gamepad Polling
  useEffect(() => {
    if (mode !== 'MEANING_FROM_WORD' || status !== 'idle') return;
    let lastAxisY = 0; let lastAxisX = 0; let lastButtonState = false; let rafId: number;
    const pollGamepad = () => {
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const hasActivity = Math.abs(gp.axes[0]) > 0.5 || Math.abs(gp.axes[1]) > 0.5 || gp.buttons.some(b => b.pressed);
            if (hasActivity && inputMethod !== 'GAMEPAD') setInputMethod('GAMEPAD');
            const axisX = gp.axes[0]; const axisY = gp.axes[1];
            if ((axisX < -0.5 || gp.buttons[14]?.pressed) && lastAxisX >= -0.5) setFocusedChoiceIndex(prev => (prev % 2 === 1) ? prev - 1 : prev); 
            if ((axisX > 0.5 || gp.buttons[15]?.pressed) && lastAxisX <= 0.5) setFocusedChoiceIndex(prev => (prev % 2 === 0) ? Math.min(3, prev + 1) : prev);
            if ((axisY < -0.5 || gp.buttons[12]?.pressed) && lastAxisY >= -0.5) setFocusedChoiceIndex(prev => (prev >= 2) ? prev - 2 : prev);
            if ((axisY > 0.5 || gp.buttons[13]?.pressed) && lastAxisY <= 0.5) setFocusedChoiceIndex(prev => (prev < 2) ? prev + 2 : prev);
            lastAxisX = axisX; lastAxisY = axisY;
            if (gp.buttons[0]?.pressed && !lastButtonState && choices[focusedChoiceIndex]) checkChoice(choices[focusedChoiceIndex].id);
            lastButtonState = gp.buttons[0]?.pressed;
        }
        rafId = requestAnimationFrame(pollGamepad);
    };
    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [mode, status, focusedChoiceIndex, choices, inputMethod]);


  const handleCorrect = () => { setStatus('correct'); playSuccessSound(); speakText(word.word); setTimeout(() => onResult(true), 1200); };
  const handleIncorrect = () => { setStatus('incorrect'); playErrorSound(); speakText(word.word); setTimeout(() => onResult(false), 2000); };

  const checkSpelling = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim().toLowerCase() === word.word.toLowerCase()) handleCorrect();
    else handleIncorrect();
  };

  const checkChoice = (selectedId: string) => {
    if (selectedId === word.id) handleCorrect();
    else handleIncorrect();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm pointer-events-auto p-4">
      <div className={`bg-white rounded-2xl p-6 sm:p-8 w-full max-w-2xl shadow-2xl border-4 transform transition-all ${status === 'correct' ? 'border-green-500 scale-105' : status === 'incorrect' ? 'border-red-500 animate-shake' : 'border-indigo-500'}`}>

        <div className="text-center mb-6">
          <h2 className="text-xl sm:text-2xl font-black text-slate-800 uppercase tracking-widest mb-1">升级挑战</h2>
          <div className="text-slate-500 text-xs sm:text-sm">回答正确获得强力属性提升！</div>
        </div>

        <div className="mb-8 min-h-[100px] sm:min-h-[150px] flex flex-col justify-center items-center">
          {mode === 'SPELL_FROM_DEF' && (
             <>
               <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-[10px] font-bold mb-4 uppercase">看义拼词</span>
               <p className="text-xl sm:text-2xl font-bold text-slate-800 text-center">{word.definition}</p>
             </>
          )}

          {mode === 'SPELL_FROM_AUDIO' && (
            <>
              <span className="bg-pink-100 text-pink-700 px-3 py-1 rounded-full text-[10px] font-bold mb-4 uppercase">听音拼词</span>
              <button 
                onClick={() => speakText(word.word)}
                className="w-16 h-16 sm:w-20 sm:h-20 bg-indigo-500 rounded-full flex items-center justify-center text-white shadow-lg hover:bg-indigo-600 active:scale-95 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
              </button>
            </>
          )}

          {mode === 'MEANING_FROM_WORD' && (
             <h1 className="text-4xl sm:text-5xl font-black text-slate-800 mb-4 tracking-tight">{word.word}</h1>
          )}
        </div>

        <div className="w-full">
          {mode === 'MEANING_FROM_WORD' ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
              {choices.map((choice, index) => (
                <button
                  key={choice.id}
                  onClick={() => checkChoice(choice.id)}
                  onMouseEnter={() => inputMethod === 'MOUSE' && setFocusedChoiceIndex(index)}
                  disabled={status !== 'idle'}
                  className={`p-3 sm:p-4 rounded-xl font-bold text-sm sm:text-lg text-left transition-all border-b-4 active:border-b-0 active:translate-y-1 relative
                    ${inputMethod === 'GAMEPAD' ? 'pointer-events-none' : ''} 
                    ${status === 'correct' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id !== word.id ? 'bg-red-100 text-red-400 border-red-200' :
                      focusedChoiceIndex === index ? 'bg-indigo-50 border-indigo-500 ring-2 ring-indigo-300 text-indigo-700 scale-[1.02] z-10' :
                      'bg-slate-100 border-slate-300 hover:bg-indigo-50 hover:border-indigo-300 text-slate-700'}`}
                >
                  {choice.definition}
                </button>
              ))}
            </div>
          ) : (
            <form onSubmit={checkSpelling} className="relative">
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={e => setInput(e.target.value)}
                onFocus={() => setIsInputFocused(true)}
                onBlur={() => setIsInputFocused(false)}
                onKeyDown={(e) => e.stopPropagation()} 
                onKeyUp={(e) => e.stopPropagation()}
                disabled={status !== 'idle'}
                placeholder={isMobile ? "" : "输入单词..."}
                inputMode="text"
                enterKeyHint="done"
                className={`w-full text-center text-3xl sm:text-4xl font-mono font-bold py-4 border-b-4 bg-transparent outline-none transition-colors rounded-none
                  ${status === 'correct' ? 'border-green-500 text-green-600' : 
                    status === 'incorrect' ? 'border-red-500 text-red-500' : 'border-slate-300 focus:border-indigo-500 text-slate-800'}`}
                autoComplete="off"
                autoCapitalize="off"
              />

              {/* Mobile "Tap to Focus" Overlay */}
              {isMobile && !isInputFocused && input === '' && status === 'idle' && (
                  <div 
                    onClick={() => inputRef.current?.focus()}
                    className="absolute inset-0 flex items-center justify-center text-slate-400 font-bold text-lg pointer-events-auto cursor-pointer animate-pulse"
                  >
                    点击此处开始拼写...
                  </div>
              )}

              {status === 'incorrect' && (
                <div className="text-center mt-2 text-red-500 font-bold animate-fade-in text-sm">
                  正确答案: {word.word}
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

