    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Removed Mobile D-Pad Input
    // if (touchVectorRef.current.x !== 0 || touchVectorRef.current.y !== 0) {
    //     dx += touchVectorRef.current.x;
    //     dy += touchVectorRef.current.y;
    // }

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 120) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }
      if (e.burnTimer && e.burnTimer > 0) { e.burnTimer--; if (frameCountRef.current % 30 === 0) e.hp -= 1; }
      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { enemy.freezeTimer = 180; playIceHitSound(); }
              else if (p.element === 'FIRE') { enemy.burnTimer = 300; playFireHitSound(); }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, 5);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  enemiesRef.current.forEach(other => { if(other!==enemy && Math.hypot(other.x-enemy.x, other.y-enemy.y) < 250) { const a = Math.atan2(enemy.y-other.y, enemy.x-other.x); other.x += Math.cos(a)*20; other.y += Math.sin(a)*20; } });
                  stormEffectsRef.current.push({x:enemy.x, y:enemy.y, life:30, maxLife:30, angle:Math.random()*Math.PI*2});
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.hasLightning ? 'LIGHTNING' : (s.hasFire ? 'FIRE' : (s.hasIce ? 'ICE' : (s.hasWind ? 'WIND' : 'NORMAL')));
    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const opts = UPGRADES.filter(o => !(statsRef.current.hasFire || statsRef.current.hasIce || statsRef.current.hasLightning || statsRef.current.hasWind) || !['fire_shot', 'ice_shot', 'lightning_shot', 'wind_shot'].includes(o.id)).sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(opts); setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { statsRef.current = o.apply(statsRef.current); statsRef.current.level++; statsRef.current.xp = 0; statsRef.current.xpToNextLevel *= 2; setShowUpgrades(null); isPausedRef.current = false; };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });
    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  // Removed Mobile Touch Handling

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden">
      <div className="relative w-full h-full"> {/* Reverted from p-[env(...)] */}
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl" // Reverted scaling classes
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none"> {/* Reverted scaling */}
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg"> {/* Reverted sizes */}
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span> {/* Reverted text size */}
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md"> {/* Reverted sizes */}
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none"> {/* Reverted position */}
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>

          {/* Removed VIRTUAL D-PAD */}
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map(o => (
                          <button key={o.id} onClick={() => applyUpgrade(o)} className="p-6 bg-slate-800 border-4 border-slate-600 rounded-2xl hover:border-yellow-400 text-white flex flex-col items-center gap-2">
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>
                  <button onClick={() => window.location.reload()} className="w-full py-4 bg-slate-800 text-white font-bold rounded-xl mb-3">RETRY</button>
                  <button onClick={onExit} className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl">EXIT</button>
              </div>
          </div>
      )}
    </div>
  );
};

{
  "name": "每周词汇构建",
  "description": "一个专注于英语学习的应用。每周输入你的生词表，应用利用AI生成中文释义和例句，通过带有语音反馈的测验帮助你掌握单词。",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useRef } from 'react';
import { WordData } from '../types';
import { speakText, playSuccessSound, playErrorSound } from '../services/audioService';

interface GameQuizModalProps {
  word: WordData;
  allWords: WordData[];
  onResult: (correct: boolean) => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const GameQuizModal: React.FC<GameQuizModalProps> = ({ word, allWords, onResult }) => {
  const [mode, setMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [input, setInput] = useState('');
  const [choices, setChoices] = useState<WordData[]>([]);
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [focusedChoiceIndex, setFocusedChoiceIndex] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);

  // Track input method State to drive UI pointer-events
  const [inputMethod, setInputMethod] = useState<'MOUSE' | 'GAMEPAD'>('GAMEPAD');
  const lastMousePos = useRef({ x: 0, y: 0 });

  // Input Method Tracking
  useEffect(() => {
      const handleMouseMove = (e: MouseEvent) => { 
          // Filter out jitter/phantom moves
          const dist = Math.abs(e.clientX - lastMousePos.current.x) + Math.abs(e.clientY - lastMousePos.current.y);
          if (dist > 5) {
             lastMousePos.current = { x: e.clientX, y: e.clientY };
             setInputMethod('MOUSE');
          }
      };
      const handleKeyDown = () => { setInputMethod('GAMEPAD'); };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('keydown', handleKeyDown);
      return () => {
          window.removeEventListener('mousemove', handleMouseMove);
          window.removeEventListener('keydown', handleKeyDown);
      };
  }, []);

  // Setup
  useEffect(() => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const selectedMode = modes[Math.floor(Math.random() * modes.length)];
    setMode(selectedMode);

    if (selectedMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (selectedMode === 'SPELL_FROM_AUDIO') {
      setTimeout(() => speakText(word.word), 300);
    }

    // Auto focus
    setTimeout(() => inputRef.current?.focus(), 100);
  }, [word, allWords]);

  // Keyboard Support for Choices
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (mode === 'MEANING_FROM_WORD' && status === 'idle') {
            if (['ArrowUp', 'ArrowLeft', 'ArrowDown', 'ArrowRight', 'Enter', ' '].includes(e.key)) {
                setInputMethod('GAMEPAD');
            }

            if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
                 setFocusedChoiceIndex(prev => Math.max(0, prev - 1));
            }
            if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
                 setFocusedChoiceIndex(prev => Math.min(choices.length - 1, prev + 1));
            }
            if (e.key === 'Enter' || e.key === ' ') {
                if (choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [mode, status, choices, focusedChoiceIndex]);

  // Gamepad Polling for Multiple Choice
  useEffect(() => {
    if (mode !== 'MEANING_FROM_WORD' || status !== 'idle') return;

    let lastAxisY = 0;
    let lastAxisX = 0;
    let lastButtonState = false;
    let rafId: number;

    const pollGamepad = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            // Check for activity to switch input method
            const hasActivity = Math.abs(gp.axes[0]) > 0.5 || Math.abs(gp.axes[1]) > 0.5 || gp.buttons.some(b => b.pressed);
            if (hasActivity) {
                 if (inputMethod !== 'GAMEPAD') setInputMethod('GAMEPAD');
            }

            const axisX = gp.axes[0];
            const axisY = gp.axes[1];

            // Grid is 2x2. 0,1 top row. 2,3 bottom row.

            // Left/Right
            if ((axisX < -0.5 || gp.buttons[14]?.pressed) && lastAxisX >= -0.5) { // Left
                setFocusedChoiceIndex(prev => (prev % 2 === 1) ? prev - 1 : prev); 
            }
            if ((axisX > 0.5 || gp.buttons[15]?.pressed) && lastAxisX <= 0.5) { // Right
                setFocusedChoiceIndex(prev => (prev % 2 === 0) ? Math.min(3, prev + 1) : prev);
            }

            // Up/Down
            if ((axisY < -0.5 || gp.buttons[12]?.pressed) && lastAxisY >= -0.5) { // Up
                setFocusedChoiceIndex(prev => (prev >= 2) ? prev - 2 : prev);
            }
            if ((axisY > 0.5 || gp.buttons[13]?.pressed) && lastAxisY <= 0.5) { // Down
                setFocusedChoiceIndex(prev => (prev < 2) ? prev + 2 : prev);
            }

            lastAxisX = axisX;
            lastAxisY = axisY;

            // Select (Button 0 = A / Cross)
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                // Ensure choices exists and index is valid
                if (choices && choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }

        rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [mode, status, focusedChoiceIndex, choices, inputMethod]);


  const handleCorrect = () => {
    setStatus('correct');
    playSuccessSound();
    speakText(word.word);
    setTimeout(() => onResult(true), 1200);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    speakText(word.word); // Teach them
    setTimeout(() => onResult(false), 2000); // Longer delay to see answer
  };

  const checkSpelling = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim().toLowerCase() === word.word.toLowerCase()) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const checkChoice = (selectedId: string) => {
    if (selectedId === word.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm pointer-events-auto">
      <div className={`bg-white rounded-2xl p-8 w-full max-w-2xl shadow-2xl border-4 transform transition-all ${status === 'correct' ? 'border-green-500 scale-105' : status === 'incorrect' ? 'border-red-500 animate-shake' : 'border-indigo-500'}`}>

        {/* Header */}
        <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-widest mb-1">升级挑战</h2>
          <div className="text-slate-500 text-sm">回答正确获得强力属性提升！</div>
        </div>

        {/* Content */}
        <div className="mb-8 min-h-[150px] flex flex-col justify-center items-center">
          {mode === 'SPELL_FROM_DEF' && (
             <>
               <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold mb-4">看义拼词</span>
               <p className="text-2xl font-bold text-slate-800 text-center">{word.definition}</p>
             </>
          )}

          {mode === 'SPELL_FROM_AUDIO' && (
            <>
              <span className="bg-pink-100 text-pink-700 px-3 py-1 rounded-full text-xs font-bold mb-4">听音拼词</span>
              <button 
                onClick={() => speakText(word.word)}
                className="w-20 h-20 bg-indigo-500 rounded-full flex items-center justify-center text-white shadow-lg hover:bg-indigo-600 active:scale-95 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
              </button>
            </>
          )}

          {mode === 'MEANING_FROM_WORD' && (
             <h1 className="text-5xl font-black text-slate-800 mb-4">{word.word}</h1>
          )}
        </div>

        {/* Inputs */}
        <div className="w-full">
          {mode === 'MEANING_FROM_WORD' ? (
            <div className="grid grid-cols-2 gap-4">
              {choices.map((choice, index) => (
                <button
                  key={choice.id}
                  onClick={() => checkChoice(choice.id)}
                  onMouseEnter={() => {
                      if (inputMethod === 'MOUSE') {
                          setFocusedChoiceIndex(index);
                      }
                  }}
                  disabled={status !== 'idle'}
                  className={`p-4 rounded-xl font-bold text-lg text-left transition-all border-b-4 active:border-b-0 active:translate-y-1 relative
                    ${inputMethod === 'GAMEPAD' ? 'pointer-events-none' : ''} 
                    ${status === 'correct' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id !== word.id ? 'bg-red-100 text-red-400 border-red-200' :
                      focusedChoiceIndex === index ? 'bg-indigo-50 border-indigo-500 ring-2 ring-indigo-300 text-indigo-700 scale-105 z-10' :
                      'bg-slate-100 border-slate-300 hover:bg-indigo-50 hover:border-indigo-300 text-slate-700'}`}
                >
                  {choice.definition}
                  {focusedChoiceIndex === index && status === 'idle' && (
                      <div className="absolute top-1 right-2 text-indigo-400 text-xs font-bold">
                          {inputMethod === 'GAMEPAD' ? '[A]' : ''}
                      </div>
                  )}
                </button>
              ))}
            </div>
          ) : (
            <form onSubmit={checkSpelling}>
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={e => setInput(e.target.value)}
                // Removed onKeyDown/onKeyUp stopPropagation
                disabled={status !== 'idle'}
                placeholder="输入单词..."
                className={`w-full text-center text-4xl font-mono font-bold py-4 border-b-4 bg-transparent outline-none transition-colors
                  ${status === 'correct' ? 'border-green-500 text-green-600' : 
                    status === 'incorrect' ? 'border-red-500 text-red-500' : 'border-slate-300 focus:border-indigo-500 text-slate-800'}`}
                autoComplete="off"
              />
              {status === 'incorrect' && (
                <div className="text-center mt-2 text-red-500 font-bold animate-fade-in">
                  正确答案: {word.word}
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number;
}

const UPGRADES: UpgradeOption[] = [
  { id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) },
  { id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', apply: (s) => ({ ...s, speed: s.speed * 1.2 }) },
  { id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫', apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.85)) }) },
  { id: 'hp_up', name: '坚韧', description: '最大生命 +30 (当前+30)', icon: '❤️', apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.hp + 30 }) },
  { id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨', apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) },
  { id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲', apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) },
  { id: 'fire_shot', name: '火焰弹', description: '灼烧伤害', icon: '🔥', apply: (s) => ({ ...s, hasFire: true, hasIce: false, hasLightning: false, hasWind: false }) },
  { id: 'ice_shot', name: '冰冻弹', description: '减速敌人', icon: '❄️', apply: (s) => ({ ...s, hasFire: false, hasIce: true, hasLightning: false, hasWind: false }) },
  { id: 'lightning_shot', name: '闪电弹', description: '弹射伤害', icon: '⚡', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: true, hasWind: false }) },
  { id: 'wind_shot', name: '风暴弹', description: '聚拢敌人', icon: '🌀', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: false, hasWind: true }) }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    hasFire: false, hasIce: false, hasLightning: false, hasWind: false
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const gamepadButtonRef = useRef<{ button1: boolean }>({ button1: false });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { if (!isPausedRef.current) keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (gameResultRef.current !== 'PLAYING' || !areResourcesLoadedRef.current) return;
        if (!isPausedRef.current) update();
        draw();
        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded]);

  const update = () => {
    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }
    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 120) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }
      if (e.burnTimer && e.burnTimer > 0) { e.burnTimer--; if (frameCountRef.current % 30 === 0) e.hp -= 1; }
      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { enemy.freezeTimer = 180; playIceHitSound(); }
              else if (p.element === 'FIRE') { enemy.burnTimer = 300; playFireHitSound(); }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, 5);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  enemiesRef.current.forEach(other => { if(other!==enemy && Math.hypot(other.x-enemy.x, other.y-enemy.y) < 250) { const a = Math.atan2(enemy.y-other.y, enemy.x-other.x); other.x += Math.cos(a)*20; other.y += Math.sin(a)*20; } });
                  stormEffectsRef.current.push({x:enemy.x, y:enemy.y, life:30, maxLife:30, angle:Math.random()*Math.PI*2});
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.hasLightning ? 'LIGHTNING' : (s.hasFire ? 'FIRE' : (s.hasIce ? 'ICE' : (s.hasWind ? 'WIND' : 'NORMAL')));
    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const opts = UPGRADES.filter(o => !(statsRef.current.hasFire || statsRef.current.hasIce || statsRef.current.hasLightning || statsRef.current.hasWind) || !['fire_shot', 'ice_shot', 'lightning_shot', 'wind_shot'].includes(o.id)).sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(opts); setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { statsRef.current = o.apply(statsRef.current); statsRef.current.level++; statsRef.current.xp = 0; statsRef.current.xpToNextLevel *= 2; setShowUpgrades(null); isPausedRef.current = false; };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                ctx.drawImage(img, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });
    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map(o => (
                          <button key={o.id} onClick={() => applyUpgrade(o)} className="p-6 bg-slate-800 border-4 border-slate-600 rounded-2xl hover:border-yellow-400 text-white flex flex-col items-center gap-2">
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>
                  <button onClick={() => window.location.reload()} className="w-full py-4 bg-slate-800 text-white font-bold rounded-xl mb-3">RETRY</button>
                  <button onClick={onExit} className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl">EXIT</button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number;
}

const UPGRADES: UpgradeOption[] = [
  { id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) },
  { id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', apply: (s) => ({ ...s, speed: s.speed * 1.2 }) },
  { id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫', apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.85)) }) },
  { id: 'hp_up', name: '坚韧', description: '最大生命 +30 (当前+30)', icon: '❤️', apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.hp + 30 }) },
  { id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨', apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) },
  { id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲', apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) },
  { id: 'fire_shot', name: '火焰弹', description: '灼烧伤害', icon: '🔥', apply: (s) => ({ ...s, hasFire: true, hasIce: false, hasLightning: false, hasWind: false }) },
  { id: 'ice_shot', name: '冰冻弹', description: '减速敌人', icon: '❄️', apply: (s) => ({ ...s, hasFire: false, hasIce: true, hasLightning: false, hasWind: false }) },
  { id: 'lightning_shot', name: '闪电弹', description: '弹射伤害', icon: '⚡', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: true, hasWind: false }) },
  { id: 'wind_shot', name: '风暴弹', description: '聚拢敌人', icon: '🌀', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: false, hasWind: true }) }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    hasFire: false, hasIce: false, hasLightning: false, hasWind: false
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean }>({ 
      button0: false, button1: false, left: false, right: false 
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); // Default to middle option

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (gameResultRef.current !== 'PLAYING' || !areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex]); // Add upgradeFocusedIndex dependency for UI re-renders

  const update = () => {
    // 1. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 2. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 3. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }
      if (e.burnTimer && e.burnTimer > 0) { e.burnTimer--; if (frameCountRef.current % 30 === 0) e.hp -= 1; }
      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { enemy.freezeTimer = 180; playIceHitSound(); }
              else if (p.element === 'FIRE') { enemy.burnTimer = 300; playFireHitSound(); }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, 5);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  enemiesRef.current.forEach(other => { if(other!==enemy && Math.hypot(other.x-enemy.x, other.y-enemy.y) < 250) { const a = Math.atan2(enemy.y-other.y, enemy.x-other.x); other.x += Math.cos(a)*20; other.y += Math.sin(a)*20; } });
                  stormEffectsRef.current.push({x:enemy.x, y:enemy.y, life:30, maxLife:30, angle:Math.random()*Math.PI*2});
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.hasLightning ? 'LIGHTNING' : (s.hasFire ? 'FIRE' : (s.hasIce ? 'ICE' : (s.hasWind ? 'WIND' : 'NORMAL')));
    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const opts = UPGRADES.filter(o => !(statsRef.current.hasFire || statsRef.current.hasIce || statsRef.current.hasLightning || statsRef.current.hasWind) || !['fire_shot', 'ice_shot', 'lightning_shot', 'wind_shot'].includes(o.id)).sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(opts); setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });
    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>
                  <button onClick={() => window.location.reload()} className="w-full py-4 bg-slate-800 text-white font-bold rounded-xl mb-3">RETRY</button>
                  <button onClick={onExit} className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl">EXIT</button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number;
}

const UPGRADES: UpgradeOption[] = [
  { id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) },
  { id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', apply: (s) => ({ ...s, speed: s.speed * 1.2 }) },
  { id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫', apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.85)) }) },
  { id: 'hp_up', name: '坚韧', description: '最大生命 +30 (当前+30)', icon: '❤️', apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.hp + 30 }) },
  { id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨', apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) },
  { id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲', apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) },
  { id: 'fire_shot', name: '火焰弹', description: '灼烧伤害', icon: '🔥', apply: (s) => ({ ...s, hasFire: true, hasIce: false, hasLightning: false, hasWind: false }) },
  { id: 'ice_shot', name: '冰冻弹', description: '减速敌人', icon: '❄️', apply: (s) => ({ ...s, hasFire: false, hasIce: true, hasLightning: false, hasWind: false }) },
  { id: 'lightning_shot', name: '闪电弹', description: '弹射伤害', icon: '⚡', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: true, hasWind: false }) },
  { id: 'wind_shot', name: '风暴弹', description: '聚拢敌人', icon: '🌀', apply: (s) => ({ ...s, hasFire: false, hasIce: false, hasLightning: false, hasWind: true }) }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    hasFire: false, hasIce: false, hasLightning: false, hasWind: false
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 
  const [gameOverFocusedIndex, setGameOverFocusedIndex] = useState(0); // 0: Retry, 1: Exit

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex, gameOverFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisY = gp.axes[1]; 
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnUp = gp.buttons[12]?.pressed || axisY < -0.5;
            const btnDown = gp.buttons[13]?.pressed || axisY > 0.5;

            // Navigate Up
            if (btnUp && !gamepadButtonRef.current.up) {
                setGameOverFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Down
            if (btnDown && !gamepadButtonRef.current.down) {
                setGameOverFocusedIndex(prev => Math.min(1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (gameOverFocusedIndex === 0) {
                     window.location.reload();
                 } else {
                     onExit();
                 }
            }

            gamepadButtonRef.current.up = btnUp;
            gamepadButtonRef.current.down = btnDown;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }
      if (e.burnTimer && e.burnTimer > 0) { e.burnTimer--; if (frameCountRef.current % 30 === 0) e.hp -= 1; }
      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { enemy.freezeTimer = 180; playIceHitSound(); }
              else if (p.element === 'FIRE') { enemy.burnTimer = 300; playFireHitSound(); }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, 5);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  enemiesRef.current.forEach(other => { if(other!==enemy && Math.hypot(other.x-enemy.x, other.y-enemy.y) < 250) { const a = Math.atan2(enemy.y-other.y, enemy.x-other.x); other.x += Math.cos(a)*20; other.y += Math.sin(a)*20; } });
                  stormEffectsRef.current.push({x:enemy.x, y:enemy.y, life:30, maxLife:30, angle:Math.random()*Math.PI*2});
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.hasLightning ? 'LIGHTNING' : (s.hasFire ? 'FIRE' : (s.hasIce ? 'ICE' : (s.hasWind ? 'WIND' : 'NORMAL')));
    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const opts = UPGRADES.filter(o => !(statsRef.current.hasFire || statsRef.current.hasIce || statsRef.current.hasLightning || statsRef.current.hasWind) || !['fire_shot', 'ice_shot', 'lightning_shot', 'wind_shot'].includes(o.id)).sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(opts); setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });
    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* RETRY BUTTON */}
                  <button 
                    onClick={() => window.location.reload()} 
                    className={`w-full py-4 font-bold rounded-xl mb-3 transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 0 
                            ? 'bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    RETRY
                    {gameOverFocusedIndex === 0 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>

                  {/* EXIT BUTTON */}
                  <button 
                    onClick={onExit} 
                    className={`w-full py-4 font-bold rounded-xl transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 1 
                            ? 'bg-indigo-600 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    EXIT
                    {gameOverFocusedIndex === 1 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

export enum AppState {
  INPUT = 'INPUT',
  GAME = 'GAME'
}

export interface QuoteData {
  english: string;
  chinese: string;
}

export interface WordData {
  id: string;
  word: string;
  definition: string;
  exampleSentence: string;
  partOfSpeech: string;
  correctCount: number;
  lastPracticed?: string;
  imageUrl?: string;
  quote?: QuoteData; 
}

export interface QuizResult {
  wordId: string;
  correct: boolean;
}

export interface StoredData {
  cycleStart: number;
  words: WordData[];
}

// GAME SPECIFIC TYPES
export interface PlayerStats {
  hp: number;
  maxHp: number;
  speed: number;
  damage: number;
  attackSpeed: number; // Cooldown in frames
  projectileSpeed: number;
  pickupRange: number;
  projectileCount: number; // Number of bullets per shot
  level: number;
  xp: number;
  xpToNextLevel: number;

  // Elemental Logic (Mutually Exclusive)
  activeElement: 'NONE' | 'FIRE' | 'ICE' | 'LIGHTNING' | 'WIND';

  // Detailed Elemental Stats
  fireLevel: number;
  burnDamage: number; // Damage per tick

  iceLevel: number;
  freezeDuration: number; // In frames (60fps)

  lightningLevel: number;
  chainCount: number; // Number of bounces

  windLevel: number;
  windRadius: number; // Radius of effect
}

export interface SpriteSource {
  x: number;
  y: number;
  w: number;
  h: number;
}

export interface Entity {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  type: 'HERO' | 'MOB' | 'ELITE' | 'ELITE_RANGED' | 'BOSS' | 'XP' | 'PROJECTILE' | 'ENEMY_PROJECTILE';
  subtype?: number; // For different mob skins
  vx: number;
  vy: number;
  hp: number;
  maxHp: number;
  damage: number;
  spriteUrl?: string;
  spriteSource?: SpriteSource; // New: Coordinates on the sprite sheet
  angle?: number; // For rotation
  // Animation Fields
  direction?: 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
  animFrame?: number;
  lastAnimTime?: number;
  isMoving?: boolean;

  // Projectile Properties
  element?: 'NORMAL' | 'FIRE' | 'ICE' | 'LIGHTNING' | 'WIND';

  // Enemy Status Effects
  freezeTimer?: number;
  burnTimer?: number;
  burnDamageRef?: number; // Snapshot of burn damage to apply
}

export interface UpgradeOption {
  id: string;
  name: string;
  description: string;
  apply: (stats: PlayerStats) => PlayerStats;
  icon: string;
  weight?: number; // Used for probability calculation
}

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 
  const [gameOverFocusedIndex, setGameOverFocusedIndex] = useState(0); // 0: Retry, 1: Exit

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex, gameOverFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisY = gp.axes[1]; 
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnUp = gp.buttons[12]?.pressed || axisY < -0.5;
            const btnDown = gp.buttons[13]?.pressed || axisY > 0.5;

            // Navigate Up
            if (btnUp && !gamepadButtonRef.current.up) {
                setGameOverFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Down
            if (btnDown && !gamepadButtonRef.current.down) {
                setGameOverFocusedIndex(prev => Math.min(1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (gameOverFocusedIndex === 0) {
                     window.location.reload();
                 } else {
                     onExit();
                 }
            }

            gamepadButtonRef.current.up = btnUp;
            gamepadButtonRef.current.down = btnDown;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Use stats.windRadius
                  enemiesRef.current.forEach(other => { 
                      if(other!==enemy && Math.hypot(other.x-enemy.x, other.y-enemy.y) < stats.windRadius) { 
                          const a = Math.atan2(enemy.y-other.y, enemy.x-other.x); 
                          other.x += Math.cos(a)*20; 
                          other.y += Math.sin(a)*20; 
                      } 
                  });
                  stormEffectsRef.current.push({x:enemy.x, y:enemy.y, life:30, maxLife:30, angle:Math.random()*Math.PI*2, radius: stats.windRadius});
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // Draw Storm Effects (Beneath Enemies)
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);
        ctx.rotate(s.angle + (30-s.life)*0.2);
        ctx.globalAlpha = s.life / s.maxLife * 0.5;
        ctx.fillStyle = '#a5f3fc'; // Light Cyan

        // Draw spiral based on radius
        ctx.beginPath();
        // Use s.radius for drawing the effect size
        ctx.arc(0, 0, s.radius, 0, Math.PI*2);
        ctx.fill();

        // Swirl lines
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0,0);
        ctx.lineTo(s.radius, 0);
        ctx.stroke();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* RETRY BUTTON */}
                  <button 
                    onClick={() => window.location.reload()} 
                    className={`w-full py-4 font-bold rounded-xl mb-3 transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 0 
                            ? 'bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    RETRY
                    {gameOverFocusedIndex === 0 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>

                  {/* EXIT BUTTON */}
                  <button 
                    onClick={onExit} 
                    className={`w-full py-4 font-bold rounded-xl transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 1 
                            ? 'bg-indigo-600 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    EXIT
                    {gameOverFocusedIndex === 1 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 
  const [gameOverFocusedIndex, setGameOverFocusedIndex] = useState(0); // 0: Retry, 1: Exit

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex, gameOverFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisY = gp.axes[1]; 
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnUp = gp.buttons[12]?.pressed || axisY < -0.5;
            const btnDown = gp.buttons[13]?.pressed || axisY > 0.5;

            // Navigate Up
            if (btnUp && !gamepadButtonRef.current.up) {
                setGameOverFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Down
            if (btnDown && !gamepadButtonRef.current.down) {
                setGameOverFocusedIndex(prev => Math.min(1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (gameOverFocusedIndex === 0) {
                     window.location.reload();
                 } else {
                     onExit();
                 }
            }

            gamepadButtonRef.current.up = btnUp;
            gamepadButtonRef.current.down = btnDown;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC ===
    // Continuous pulling effect
    stormEffectsRef.current.forEach(storm => {
        // Find enemies in range
        enemiesRef.current.forEach(e => {
            if (e.hp <= 0) return;
            const dx = storm.x - e.x;
            const dy = storm.y - e.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Pull if within radius but not already at the center (avoid jitter)
            if (dist < storm.radius && dist > 15) {
                // Calculate normalized vector
                const factor = 1 / dist;
                // Pull strength (adjustable) - stronger closer to center?
                // Let's make it a constant strong suction
                const pullSpeed = 3.5; 

                e.x += (dx * factor) * pullSpeed;
                e.y += (dy * factor) * pullSpeed;
            }
        });

        // Rotate the storm
        storm.angle += 0.2;
    });

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Spawn a persistent storm entity
                  // Duration scales slightly with level, default ~3 seconds (180 frames)
                  const duration = 180 + (stats.windLevel * 30);

                  stormEffectsRef.current.push({
                      x: enemy.x, 
                      y: enemy.y, 
                      life: duration, 
                      maxLife: duration, 
                      angle: Math.random() * Math.PI * 2, 
                      radius: stats.windRadius
                  });
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { takeDamage(p.damage); hit = true; }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { statsRef.current.hp -= a; if (statsRef.current.hp <= 0) { setGameResult('DEFEAT'); isPausedRef.current = true; } };
  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // === NEW STORM DRAWING LOGIC (Tornado/Swirl) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);

        const opacity = s.life / s.maxLife; // Fade out
        const rotationSpeed = s.angle; 

        // Draw multiple "arms" to look like a tornado from top down
        const armCount = 3;

        for(let i = 0; i < armCount; i++) {
             ctx.rotate((Math.PI * 2 / armCount) + rotationSpeed * 0.1); // Add rotation speed

             // Draw a curved "arm"
             ctx.beginPath();
             ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
             ctx.lineWidth = 4;
             ctx.moveTo(10, 0);

             // Create a spiral path
             for (let r = 10; r < s.radius; r += 5) {
                 // Spiral equation: slight angle offset as radius increases
                 const spiralAngle = r * 0.1; 
                 const dx = Math.cos(spiralAngle) * r;
                 const dy = Math.sin(spiralAngle) * r;
                 ctx.lineTo(dx, dy);
             }
             ctx.stroke();

             // Add some particles/debris in the wind
             if (frameCountRef.current % 4 === 0) {
                 ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.6})`;
                 const r = Math.random() * s.radius;
                 const th = Math.random() * Math.PI * 2;
                 ctx.fillRect(Math.cos(th)*r, Math.sin(th)*r, 2, 2);
             }
        }

        // Center "Eye"
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);
    drawEnt(playerRef.current);
    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* RETRY BUTTON */}
                  <button 
                    onClick={() => window.location.reload()} 
                    className={`w-full py-4 font-bold rounded-xl mb-3 transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 0 
                            ? 'bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    RETRY
                    {gameOverFocusedIndex === 0 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>

                  {/* EXIT BUTTON */}
                  <button 
                    onClick={onExit} 
                    className={`w-full py-4 font-bold rounded-xl transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 1 
                            ? 'bg-indigo-600 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    EXIT
                    {gameOverFocusedIndex === 1 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // New: Invulnerability Timer for Player
  const playerInvulnTimerRef = useRef(0);

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 
  const [gameOverFocusedIndex, setGameOverFocusedIndex] = useState(0); // 0: Retry, 1: Exit

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex, gameOverFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisY = gp.axes[1]; 
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnUp = gp.buttons[12]?.pressed || axisY < -0.5;
            const btnDown = gp.buttons[13]?.pressed || axisY > 0.5;

            // Navigate Up
            if (btnUp && !gamepadButtonRef.current.up) {
                setGameOverFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Down
            if (btnDown && !gamepadButtonRef.current.down) {
                setGameOverFocusedIndex(prev => Math.min(1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (gameOverFocusedIndex === 0) {
                     window.location.reload();
                 } else {
                     onExit();
                 }
            }

            gamepadButtonRef.current.up = btnUp;
            gamepadButtonRef.current.down = btnDown;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    // Decrease invulnerability timer
    if (playerInvulnTimerRef.current > 0) {
        playerInvulnTimerRef.current--;
    }

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC ===
    // Continuous pulling effect
    stormEffectsRef.current.forEach(storm => {
        // Find enemies in range
        enemiesRef.current.forEach(e => {
            if (e.hp <= 0) return;
            const dx = storm.x - e.x;
            const dy = storm.y - e.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Pull if within radius but not already at the center (avoid jitter)
            if (dist < storm.radius && dist > 15) {
                // Calculate normalized vector
                const factor = 1 / dist;
                // Pull strength (adjustable) - stronger closer to center?
                // Let's make it a constant strong suction
                const pullSpeed = 3.5; 

                e.x += (dx * factor) * pullSpeed;
                e.y += (dy * factor) * pullSpeed;
            }
        });

        // Rotate the storm
        storm.angle += 0.2;
    });

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;

      // COLLISION LOGIC FIXED: Use takeDamage which now handles I-frames
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Spawn a persistent storm entity
                  // Duration scales slightly with level, default ~3 seconds (180 frames)
                  const duration = 180 + (stats.windLevel * 30);

                  stormEffectsRef.current.push({
                      x: enemy.x, 
                      y: enemy.y, 
                      life: duration, 
                      maxLife: duration, 
                      angle: Math.random() * Math.PI * 2, 
                      radius: stats.windRadius
                  });
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { 
          takeDamage(p.damage); 
          hit = true; 
      }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;
        xpGemsRef.current.push({ id: Math.random().toString(), x: e.x, y: e.y, width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.8) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { 
      // i-frame Check
      if (playerInvulnTimerRef.current > 0) return;

      // Apply Damage
      statsRef.current.hp -= a; 
      playErrorSound(); // Feedback sound

      // Set Invulnerability (30 frames = 0.5s)
      playerInvulnTimerRef.current = 30;

      // Update UI immediately
      setUiStats({...statsRef.current});

      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // === NEW STORM DRAWING LOGIC (Tornado/Swirl) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);

        const opacity = s.life / s.maxLife; // Fade out
        const rotationSpeed = s.angle; 

        // Draw multiple "arms" to look like a tornado from top down
        const armCount = 3;

        for(let i = 0; i < armCount; i++) {
             ctx.rotate((Math.PI * 2 / armCount) + rotationSpeed * 0.1); // Add rotation speed

             // Draw a curved "arm"
             ctx.beginPath();
             ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
             ctx.lineWidth = 4;
             ctx.moveTo(10, 0);

             // Create a spiral path
             for (let r = 10; r < s.radius; r += 5) {
                 // Spiral equation: slight angle offset as radius increases
                 const spiralAngle = r * 0.1; 
                 const dx = Math.cos(spiralAngle) * r;
                 const dy = Math.sin(spiralAngle) * r;
                 ctx.lineTo(dx, dy);
             }
             ctx.stroke();

             // Add some particles/debris in the wind
             if (frameCountRef.current % 4 === 0) {
                 ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.6})`;
                 const r = Math.random() * s.radius;
                 const th = Math.random() * Math.PI * 2;
                 ctx.fillRect(Math.cos(th)*r, Math.sin(th)*r, 2, 2);
             }
        }

        // Center "Eye"
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);

    // DRAW PLAYER (Handle Blinking if Invulnerable)
    if (playerInvulnTimerRef.current > 0) {
        // Blink every 100ms approx (6 frames)
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) {
            ctx.globalAlpha = 0.4;
        }
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; // Reset alpha

    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* RETRY BUTTON */}
                  <button 
                    onClick={() => window.location.reload()} 
                    className={`w-full py-4 font-bold rounded-xl mb-3 transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 0 
                            ? 'bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    RETRY
                    {gameOverFocusedIndex === 0 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>

                  {/* EXIT BUTTON */}
                  <button 
                    onClick={onExit} 
                    className={`w-full py-4 font-bold rounded-xl transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 1 
                            ? 'bg-indigo-600 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    EXIT
                    {gameOverFocusedIndex === 1 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // New: Invulnerability Timer for Player
  const playerInvulnTimerRef = useRef(0);

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 
  const [gameOverFocusedIndex, setGameOverFocusedIndex] = useState(0); // 0: Retry, 1: Exit

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex, gameOverFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisY = gp.axes[1]; 
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnUp = gp.buttons[12]?.pressed || axisY < -0.5;
            const btnDown = gp.buttons[13]?.pressed || axisY > 0.5;

            // Navigate Up
            if (btnUp && !gamepadButtonRef.current.up) {
                setGameOverFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Down
            if (btnDown && !gamepadButtonRef.current.down) {
                setGameOverFocusedIndex(prev => Math.min(1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (gameOverFocusedIndex === 0) {
                     window.location.reload();
                 } else {
                     onExit();
                 }
            }

            gamepadButtonRef.current.up = btnUp;
            gamepadButtonRef.current.down = btnDown;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    // Decrease invulnerability timer
    if (playerInvulnTimerRef.current > 0) {
        playerInvulnTimerRef.current--;
    }

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC ===
    // Continuous pulling effect
    stormEffectsRef.current.forEach(storm => {
        // Find enemies in range
        enemiesRef.current.forEach(e => {
            if (e.hp <= 0) return;
            const dx = storm.x - e.x;
            const dy = storm.y - e.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Pull if within radius but not already at the center (avoid jitter)
            if (dist < storm.radius && dist > 15) {
                // Calculate normalized vector
                const factor = 1 / dist;
                // Pull strength (adjustable) - stronger closer to center?
                // Let's make it a constant strong suction
                const pullSpeed = 3.5; 

                e.x += (dx * factor) * pullSpeed;
                e.y += (dy * factor) * pullSpeed;
            }
        });

        // Rotate the storm
        storm.angle += 0.2;
    });

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;

      // COLLISION LOGIC FIXED: Use takeDamage which now handles I-frames
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Spawn a persistent storm entity
                  // Duration scales slightly with level, default ~3 seconds (180 frames)
                  const duration = 180 + (stats.windLevel * 30);

                  stormEffectsRef.current.push({
                      x: enemy.x, 
                      y: enemy.y, 
                      life: duration, 
                      maxLife: duration, 
                      angle: Math.random() * Math.PI * 2, 
                      radius: stats.windRadius
                  });
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { 
          takeDamage(p.damage); 
          hit = true; 
      }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

        // XP DROP LOGIC UPDATED
        // Elite drops 5 gems, Boss drops 50 gems.
        const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);

        for (let i = 0; i < dropCount; i++) {
            xpGemsRef.current.push({ 
                id: Math.random().toString(), 
                // Add scatter so they don't stack perfectly
                x: e.x + (Math.random() * 30 - 15), 
                y: e.y + (Math.random() * 30 - 15), 
                width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 
            });
        }

        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          // ADJUSTED SPAWN RATE: Elite only spawns > 0.9 (10% chance), previously 20%
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { 
      // i-frame Check
      if (playerInvulnTimerRef.current > 0) return;

      // Apply Damage
      statsRef.current.hp -= a; 
      playErrorSound(); // Feedback sound

      // Set Invulnerability (30 frames = 0.5s)
      playerInvulnTimerRef.current = 30;

      // Update UI immediately
      setUiStats({...statsRef.current});

      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // === NEW STORM DRAWING LOGIC (Tornado/Swirl) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);

        const opacity = s.life / s.maxLife; // Fade out
        const rotationSpeed = s.angle; 

        // Draw multiple "arms" to look like a tornado from top down
        const armCount = 3;

        for(let i = 0; i < armCount; i++) {
             ctx.rotate((Math.PI * 2 / armCount) + rotationSpeed * 0.1); // Add rotation speed

             // Draw a curved "arm"
             ctx.beginPath();
             ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
             ctx.lineWidth = 4;
             ctx.moveTo(10, 0);

             // Create a spiral path
             for (let r = 10; r < s.radius; r += 5) {
                 // Spiral equation: slight angle offset as radius increases
                 const spiralAngle = r * 0.1; 
                 const dx = Math.cos(spiralAngle) * r;
                 const dy = Math.sin(spiralAngle) * r;
                 ctx.lineTo(dx, dy);
             }
             ctx.stroke();

             // Add some particles/debris in the wind
             if (frameCountRef.current % 4 === 0) {
                 ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.6})`;
                 const r = Math.random() * s.radius;
                 const th = Math.random() * Math.PI * 2;
                 ctx.fillRect(Math.cos(th)*r, Math.sin(th)*r, 2, 2);
             }
        }

        // Center "Eye"
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);

    // DRAW PLAYER (Handle Blinking if Invulnerable)
    if (playerInvulnTimerRef.current > 0) {
        // Blink every 100ms approx (6 frames)
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) {
            ctx.globalAlpha = 0.4;
        }
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; // Reset alpha

    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* RETRY BUTTON */}
                  <button 
                    onClick={() => window.location.reload()} 
                    className={`w-full py-4 font-bold rounded-xl mb-3 transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 0 
                            ? 'bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    RETRY
                    {gameOverFocusedIndex === 0 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>

                  {/* EXIT BUTTON */}
                  <button 
                    onClick={onExit} 
                    className={`w-full py-4 font-bold rounded-xl transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 1 
                            ? 'bg-indigo-600 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    EXIT
                    {gameOverFocusedIndex === 1 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // New: Invulnerability Timer for Player
  const playerInvulnTimerRef = useRef(0);

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 
  const [gameOverFocusedIndex, setGameOverFocusedIndex] = useState(0); // 0: Retry, 1: Exit

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex, gameOverFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisY = gp.axes[1]; 
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnUp = gp.buttons[12]?.pressed || axisY < -0.5;
            const btnDown = gp.buttons[13]?.pressed || axisY > 0.5;

            // Navigate Up
            if (btnUp && !gamepadButtonRef.current.up) {
                setGameOverFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Down
            if (btnDown && !gamepadButtonRef.current.down) {
                setGameOverFocusedIndex(prev => Math.min(1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (gameOverFocusedIndex === 0) {
                     window.location.reload();
                 } else {
                     onExit();
                 }
            }

            gamepadButtonRef.current.up = btnUp;
            gamepadButtonRef.current.down = btnDown;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    // Decrease invulnerability timer
    if (playerInvulnTimerRef.current > 0) {
        playerInvulnTimerRef.current--;
    }

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC ===
    // Continuous pulling effect
    stormEffectsRef.current.forEach(storm => {
        // Find enemies in range
        enemiesRef.current.forEach(e => {
            if (e.hp <= 0) return;
            const dx = storm.x - e.x;
            const dy = storm.y - e.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Pull if within radius but not already at the center (avoid jitter)
            if (dist < storm.radius && dist > 15) {
                // Calculate normalized vector
                const factor = 1 / dist;
                // Pull strength (adjustable) - stronger closer to center?
                // Let's make it a constant strong suction
                const pullSpeed = 3.5; 

                e.x += (dx * factor) * pullSpeed;
                e.y += (dy * factor) * pullSpeed;
            }
        });

        // Rotate the storm
        storm.angle += 0.2;
    });

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;

      // COLLISION LOGIC FIXED: Use takeDamage which now handles I-frames
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Spawn a persistent storm entity
                  // Duration scales slightly with level, default ~3 seconds (180 frames)
                  const duration = 180 + (stats.windLevel * 30);

                  stormEffectsRef.current.push({
                      x: enemy.x, 
                      y: enemy.y, 
                      life: duration, 
                      maxLife: duration, 
                      angle: Math.random() * Math.PI * 2, 
                      radius: stats.windRadius
                  });
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { 
          takeDamage(p.damage); 
          hit = true; 
      }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

        // XP DROP LOGIC UPDATED
        // Elite drops 5 gems, Boss drops 50 gems.
        const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);

        for (let i = 0; i < dropCount; i++) {
            xpGemsRef.current.push({ 
                id: Math.random().toString(), 
                // Add scatter so they don't stack perfectly
                x: e.x + (Math.random() * 30 - 15), 
                y: e.y + (Math.random() * 30 - 15), 
                width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 
            });
        }

        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          // ADJUSTED SPAWN RATE: Elite only spawns > 0.9 (10% chance), previously 20%
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { 
      // i-frame Check
      if (playerInvulnTimerRef.current > 0) return;

      // Apply Damage
      statsRef.current.hp -= a; 
      playErrorSound(); // Feedback sound

      // Set Invulnerability (30 frames = 0.5s)
      playerInvulnTimerRef.current = 30;

      // Update UI immediately
      setUiStats({...statsRef.current});

      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.damage += 1; // Auto-increment damage on level up
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // === NEW STORM DRAWING LOGIC (Tornado/Swirl) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);

        const opacity = s.life / s.maxLife; // Fade out
        const rotationSpeed = s.angle; 

        // Draw multiple "arms" to look like a tornado from top down
        const armCount = 3;

        for(let i = 0; i < armCount; i++) {
             ctx.rotate((Math.PI * 2 / armCount) + rotationSpeed * 0.1); // Add rotation speed

             // Draw a curved "arm"
             ctx.beginPath();
             ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
             ctx.lineWidth = 4;
             ctx.moveTo(10, 0);

             // Create a spiral path
             for (let r = 10; r < s.radius; r += 5) {
                 // Spiral equation: slight angle offset as radius increases
                 const spiralAngle = r * 0.1; 
                 const dx = Math.cos(spiralAngle) * r;
                 const dy = Math.sin(spiralAngle) * r;
                 ctx.lineTo(dx, dy);
             }
             ctx.stroke();

             // Add some particles/debris in the wind
             if (frameCountRef.current % 4 === 0) {
                 ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.6})`;
                 const r = Math.random() * s.radius;
                 const th = Math.random() * Math.PI * 2;
                 ctx.fillRect(Math.cos(th)*r, Math.sin(th)*r, 2, 2);
             }
        }

        // Center "Eye"
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);

    // DRAW PLAYER (Handle Blinking if Invulnerable)
    if (playerInvulnTimerRef.current > 0) {
        // Blink every 100ms approx (6 frames)
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) {
            ctx.globalAlpha = 0.4;
        }
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; // Reset alpha

    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-4 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* RETRY BUTTON */}
                  <button 
                    onClick={() => window.location.reload()} 
                    className={`w-full py-4 font-bold rounded-xl mb-3 transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 0 
                            ? 'bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    RETRY
                    {gameOverFocusedIndex === 0 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>

                  {/* EXIT BUTTON */}
                  <button 
                    onClick={onExit} 
                    className={`w-full py-4 font-bold rounded-xl transition-all pointer-events-none border-4
                        ${gameOverFocusedIndex === 1 
                            ? 'bg-indigo-600 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)]' 
                            : 'bg-slate-200 text-slate-500 border-transparent'}
                    `}
                  >
                    EXIT
                    {gameOverFocusedIndex === 1 && <span className="ml-2 text-xs text-yellow-400 animate-pulse">[ A ]</span>}
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 6, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // New: Invulnerability Timer for Player
  const playerInvulnTimerRef = useRef(0);

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 

  // Removed gameOverFocusedIndex as we only have one button now

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const btnA = gp.buttons[0]?.pressed; // Select

            // Select (A) - Always Exit/Retry to Title
            if (btnA && !gamepadButtonRef.current.button0) {
                 onExit();
            }

            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    // Decrease invulnerability timer
    if (playerInvulnTimerRef.current > 0) {
        playerInvulnTimerRef.current--;
    }

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC ===
    // Continuous pulling effect
    stormEffectsRef.current.forEach(storm => {
        // Find enemies in range
        enemiesRef.current.forEach(e => {
            if (e.hp <= 0) return;
            const dx = storm.x - e.x;
            const dy = storm.y - e.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Pull if within radius but not already at the center (avoid jitter)
            if (dist < storm.radius && dist > 15) {
                // Calculate normalized vector
                const factor = 1 / dist;
                // Pull strength (adjustable) - stronger closer to center?
                // Let's make it a constant strong suction
                const pullSpeed = 3.5; 

                e.x += (dx * factor) * pullSpeed;
                e.y += (dy * factor) * pullSpeed;
            }
        });

        // Rotate the storm
        storm.angle += 0.2;
    });

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;

      // COLLISION LOGIC FIXED: Use takeDamage which now handles I-frames
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Spawn a persistent storm entity
                  // Duration scales slightly with level, default ~3 seconds (180 frames)
                  const duration = 180 + (stats.windLevel * 30);

                  stormEffectsRef.current.push({
                      x: enemy.x, 
                      y: enemy.y, 
                      life: duration, 
                      maxLife: duration, 
                      angle: Math.random() * Math.PI * 2, 
                      radius: stats.windRadius
                  });
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { 
          takeDamage(p.damage); 
          hit = true; 
      }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

        // XP DROP LOGIC UPDATED
        // Elite drops 5 gems, Boss drops 50 gems.
        const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);

        for (let i = 0; i < dropCount; i++) {
            xpGemsRef.current.push({ 
                id: Math.random().toString(), 
                // Add scatter so they don't stack perfectly
                x: e.x + (Math.random() * 30 - 15), 
                y: e.y + (Math.random() * 30 - 15), 
                width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 
            });
        }

        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          // ADJUSTED SPAWN RATE: Elite only spawns > 0.9 (10% chance), previously 20%
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { 
      // i-frame Check
      if (playerInvulnTimerRef.current > 0) return;

      // Apply Damage
      statsRef.current.hp -= a; 
      playErrorSound(); // Feedback sound

      // Set Invulnerability (30 frames = 0.5s)
      playerInvulnTimerRef.current = 30;

      // Update UI immediately
      setUiStats({...statsRef.current});

      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.damage += 1; // Auto-increment damage on level up
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // === NEW STORM DRAWING LOGIC (Tornado/Swirl) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);

        const opacity = s.life / s.maxLife; // Fade out
        const rotationSpeed = s.angle; 

        // Draw multiple "arms" to look like a tornado from top down
        const armCount = 3;

        for(let i = 0; i < armCount; i++) {
             ctx.rotate((Math.PI * 2 / armCount) + rotationSpeed * 0.1); // Add rotation speed

             // Draw a curved "arm"
             ctx.beginPath();
             ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
             ctx.lineWidth = 4;
             ctx.moveTo(10, 0);

             // Create a spiral path
             for (let r = 10; r < s.radius; r += 5) {
                 // Spiral equation: slight angle offset as radius increases
                 const spiralAngle = r * 0.1; 
                 const dx = Math.cos(spiralAngle) * r;
                 const dy = Math.sin(spiralAngle) * r;
                 ctx.lineTo(dx, dy);
             }
             ctx.stroke();

             // Add some particles/debris in the wind
             if (frameCountRef.current % 4 === 0) {
                 ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.6})`;
                 const r = Math.random() * s.radius;
                 const th = Math.random() * Math.PI * 2;
                 ctx.fillRect(Math.cos(th)*r, Math.sin(th)*r, 2, 2);
             }
        }

        // Center "Eye"
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);

    // DRAW PLAYER (Handle Blinking if Invulnerable)
    if (playerInvulnTimerRef.current > 0) {
        // Blink every 100ms approx (6 frames)
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) {
            ctx.globalAlpha = 0.4;
        }
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; // Reset alpha

    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-8 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* SINGLE ACTION BUTTON */}
                  <button 
                    onClick={onExit} 
                    className="w-full py-6 font-black text-2xl rounded-2xl mb-3 transition-all border-4 bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)] hover:bg-slate-700 active:scale-95"
                  >
                    RETRY
                    <span className="ml-3 text-sm text-yellow-400 animate-pulse">[ A ]</span>
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

interface LightningChain {
    x1: number; y1: number; x2: number; y2: number; life: number;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, 
    attackSpeed: 15, // Doubled frequency (was 30)
    projectileSpeed: 3, // Halved speed (was 6)
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 150
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // New: Invulnerability Timer for Player
  const playerInvulnTimerRef = useRef(0);

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 

  // Removed gameOverFocusedIndex as we only have one button now

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startRockBGM();
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;

        // Always draw the scene (even when paused, so we see what's behind the menu)
        draw();

        // Logic updates
        update();

        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex]); 

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const btnA = gp.buttons[0]?.pressed; // Select

            // Select (A) - Always Exit/Retry to Title
            if (btnA && !gamepadButtonRef.current.button0) {
                 onExit();
            }

            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game logic
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        // === GAMEPAD MENU NAVIGATION ===
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; // Select
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            // Navigate Left
            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            // Navigate Right
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            // Select (A)
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }

            // Update debounce state
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return; // Stop game physics
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    // Decrease invulnerability timer
    if (playerInvulnTimerRef.current > 0) {
        playerInvulnTimerRef.current--;
    }

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        // Button 1 (B/Circle) for Fullscreen
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    // Anim Speed
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC ===
    // Continuous pulling effect
    stormEffectsRef.current.forEach(storm => {
        // Find enemies in range
        enemiesRef.current.forEach(e => {
            if (e.hp <= 0) return;
            const dx = storm.x - e.x;
            const dy = storm.y - e.y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            // Pull if within radius but not already at the center (avoid jitter)
            if (dist < storm.radius && dist > 15) {
                // Calculate normalized vector
                const factor = 1 / dist;
                // Pull strength (adjustable) - stronger closer to center?
                // Let's make it a constant strong suction
                const pullSpeed = 3.5; 

                e.x += (dx * factor) * pullSpeed;
                e.y += (dy * factor) * pullSpeed;
            }
        });

        // Rotate the storm
        storm.angle += 0.2;
    });

    spawnEnemies();
    enemiesRef.current.forEach(e => {
      const angle = Math.atan2(player.y - e.y, player.x - e.x);
      let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
      if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

      // Burn Damage Logic (Tick every 30 frames)
      if (e.burnTimer && e.burnTimer > 0) { 
          e.burnTimer--; 
          if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
              e.hp -= e.burnDamageRef; 
          }
      }

      e.x += Math.cos(angle) * speed; e.y += Math.sin(angle) * speed;

      // COLLISION LOGIC FIXED: Use takeDamage which now handles I-frames
      if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
         takeDamage(e.damage);
      }
    });

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width/2 + 10)) {
              enemy.hp -= p.damage;
              if (p.element === 'ICE') { 
                  enemy.freezeTimer = stats.freezeDuration; 
                  playIceHitSound(); 
              }
              else if (p.element === 'FIRE') { 
                  enemy.burnTimer = 300; 
                  enemy.burnDamageRef = stats.burnDamage;
                  playFireHitSound(); 
              }
              else if (p.element === 'LIGHTNING') {
                  const neighbors = enemiesRef.current.filter(e => e !== enemy && Math.hypot(e.x-enemy.x, e.y-enemy.y) < 400).slice(0, stats.chainCount);
                  neighbors.forEach(n => { n.hp -= Math.ceil(p.damage/2); lightningChainsRef.current.push({x1:enemy.x, y1:enemy.y, x2:n.x, y2:n.y, life:10}); });
                  playLightningHitSound();
              } else if (p.element === 'WIND') {
                  // Wind logic: Spawn a persistent storm entity
                  // Duration scales slightly with level, default ~3 seconds (180 frames)
                  const duration = 180 + (stats.windLevel * 30);

                  stormEffectsRef.current.push({
                      x: enemy.x, 
                      y: enemy.y, 
                      life: duration, 
                      maxLife: duration, 
                      angle: Math.random() * Math.PI * 2, 
                      radius: stats.windRadius
                  });
                  playWindHitSound();
              } else { playHitSound(); }
              hit = true; break;
            }
          }
      } else if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width/2 + 10)) { 
          takeDamage(p.damage); 
          hit = true; 
      }
      return !hit && p.x > 0 && p.x < GAME_WIDTH && p.y > 0 && p.y < GAME_HEIGHT;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
        killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

        // XP DROP LOGIC UPDATED
        // Elite drops 5 gems, Boss drops 50 gems.
        const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);

        for (let i = 0; i < dropCount; i++) {
            xpGemsRef.current.push({ 
                id: Math.random().toString(), 
                // Add scatter so they don't stack perfectly
                x: e.x + (Math.random() * 30 - 15), 
                y: e.y + (Math.random() * 30 - 15), 
                width: 24, height: 24, type: 'XP', vx:0, vy:0, hp:1, maxHp:1, damage:0 
            });
        }

        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const d = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (d < stats.pickupRange) { gem.x += (player.x - gem.x) * 0.15; gem.y += (player.y - gem.y) * 0.15; if (d < 30) { gainXp(1); return false; } }
      return true;
    });
    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(5, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));
      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          // ADJUSTED SPAWN RATE: Elite only spawns > 0.9 (10% chance), previously 20%
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    playShootSound();
    const p = playerRef.current; const s = statsRef.current;
    let el: any = s.activeElement; 
    // Map internal element enum to projectile type
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { 
      // i-frame Check
      if (playerInvulnTimerRef.current > 0) return;

      // Apply Damage
      statsRef.current.hp -= a; 
      playErrorSound(); // Feedback sound

      // Set Invulnerability (30 frames = 0.5s)
      playerInvulnTimerRef.current = 30;

      // Update UI immediately
      setUiStats({...statsRef.current});

      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];

      // 1. NEUTRAL UPGRADES (Always available)
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      // 2. ELEMENTAL UPGRADES (Mutually Exclusive Logic)
      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      // FIRE
      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }

      // ICE
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }

      // LIGHTNING
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }

      // WIND
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围翻倍` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 150 : s.windRadius * 2 }) 
          });
      }

      // SELECTION ALGORITHM based on weights
      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;

          // Calculate total weight
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); // Remove selected to avoid duplicates
                  break;
              }
          }
      }

      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); // Default focus to center
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.damage += 1; // Auto-increment damage on level up
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel *= 2; 
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // === FIX: HERO RENDERING (CROP) ===
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                // Calculate animation frame (0 or 1) based on time
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; // SVG is 128px wide, each frame is 64px

                // Draw only the specific frame
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }

        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };
    xpGemsRef.current.forEach(g => { ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); });

    // === NEW STORM DRAWING LOGIC (Tornado/Swirl) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);

        const opacity = s.life / s.maxLife; // Fade out
        const rotationSpeed = s.angle; 

        // Draw multiple "arms" to look like a tornado from top down
        const armCount = 3;

        for(let i = 0; i < armCount; i++) {
             ctx.rotate((Math.PI * 2 / armCount) + rotationSpeed * 0.1); // Add rotation speed

             // Draw a curved "arm"
             ctx.beginPath();
             ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
             ctx.lineWidth = 4;
             ctx.moveTo(10, 0);

             // Create a spiral path
             for (let r = 10; r < s.radius; r += 5) {
                 // Spiral equation: slight angle offset as radius increases
                 const spiralAngle = r * 0.1; 
                 const dx = Math.cos(spiralAngle) * r;
                 const dy = Math.sin(spiralAngle) * r;
                 ctx.lineTo(dx, dy);
             }
             ctx.stroke();

             // Add some particles/debris in the wind
             if (frameCountRef.current % 4 === 0) {
                 ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.6})`;
                 const r = Math.random() * s.radius;
                 const th = Math.random() * Math.PI * 2;
                 ctx.fillRect(Math.cos(th)*r, Math.sin(th)*r, 2, 2);
             }
        }

        // Center "Eye"
        ctx.beginPath();
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);

    // DRAW PLAYER (Handle Blinking if Invulnerable)
    if (playerInvulnTimerRef.current > 0) {
        // Blink every 100ms approx (6 frames)
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) {
            ctx.globalAlpha = 0.4;
        }
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; // Reset alpha

    projectilesRef.current.forEach(p => { ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); });
    lightningChainsRef.current = lightningChainsRef.current.filter(c => { if (c.life <= 0) return false; ctx.strokeStyle = `rgba(180, 230, 255, ${c.life / 10})`; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(c.x1, c.y1); ctx.lineTo(c.x2, c.y2); ctx.stroke(); c.life--; return true; });
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-8 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* SINGLE ACTION BUTTON */}
                  <button 
                    onClick={onExit} 
                    className="w-full py-6 font-black text-2xl rounded-2xl mb-3 transition-all border-4 bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)] hover:bg-slate-700 active:scale-95"
                  >
                    RETRY
                    <span className="ml-3 text-sm text-yellow-400 animate-pulse">[ A ]</span>
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

