// Unique Hero Color: Fuchsia-500 (#d946ef) - Distinct from all mobs
const HERO_COLOR = '#d946ef'; 
const HERO_FACE_COLOR = '#ffffff';

const createHeroSvg = (direction: 'FRONT' | 'BACK' | 'SIDE_LEFT' | 'SIDE_RIGHT'): string => {
  // 2 Frames of animation (0 and 1), each 64x64. Total width 128.
  // We use a 4x scale (16x16 logical grid -> 64x64 px)

  const drawFrame = (offsetX: number, frameIndex: number) => {
    let shapes = '';
    const bob = frameIndex === 1 ? 2 : 0; // Bobbing effect for walking

    // --- HEAD (Centered at x=20, y=4+bob) ---
    shapes += `<rect x="${20 + offsetX}" y="${4 + bob}" width="24" height="24" rx="4" fill="${HERO_COLOR}"/>`;

    if (direction === 'FRONT') {
        // Face
        shapes += `<rect x="${24 + offsetX}" y="${8 + bob}" width="16" height="12" rx="2" fill="${HERO_FACE_COLOR}"/>`;
        // Eyes
        shapes += `<rect x="${28 + offsetX}" y="${12 + bob}" width="2" height="4" fill="black"/>`;
        shapes += `<rect x="${34 + offsetX}" y="${12 + bob}" width="2" height="4" fill="black"/>`;
    } else if (direction === 'SIDE_LEFT') {
        // Face Profile Left
        shapes += `<rect x="${20 + offsetX}" y="${8 + bob}" width="10" height="12" rx="2" fill="${HERO_FACE_COLOR}"/>`;
        // Eye
        shapes += `<rect x="${22 + offsetX}" y="${12 + bob}" width="2" height="4" fill="black"/>`;
    } else if (direction === 'SIDE_RIGHT') {
        // Face Profile Right
        shapes += `<rect x="${34 + offsetX}" y="${8 + bob}" width="10" height="12" rx="2" fill="${HERO_FACE_COLOR}"/>`;
        // Eye
        shapes += `<rect x="${40 + offsetX}" y="${12 + bob}" width="2" height="4" fill="black"/>`;
    }
    // Back has no face

    // --- BODY (x=16, y=28+bob) ---
    shapes += `<rect x="${16 + offsetX}" y="${28 + bob}" width="32" height="20" rx="4" fill="${HERO_COLOR}"/>`;

    // --- ARMS ---
    if (direction === 'SIDE_LEFT' || direction === 'SIDE_RIGHT') {
        // Single arm visible/centered
        shapes += `<rect x="${26 + offsetX}" y="${30 + bob}" width="12" height="16" rx="3" fill="${HERO_COLOR}" stroke="rgba(0,0,0,0.2)" stroke-width="2"/>`;
    } else {
        // Two arms
        shapes += `<rect x="${4 + offsetX}" y="${30 + bob}" width="10" height="16" rx="3" fill="${HERO_COLOR}"/>`;
        shapes += `<rect x="${50 + offsetX}" y="${30 + bob}" width="10" height="16" rx="3" fill="${HERO_COLOR}"/>`;
    }

    // --- LEGS (x=20 & 34, y=48) ---
    // Animation: Move legs
    let ly = 48;
    if (frameIndex === 1) ly = 46; // Lift legs slightly in frame 2

    shapes += `<rect x="${20 + offsetX}" y="${ly}" width="10" height="14" rx="2" fill="${HERO_COLOR}"/>`;
    shapes += `<rect x="${34 + offsetX}" y="${ly}" width="10" height="14" rx="2" fill="${HERO_COLOR}"/>`;

    return shapes;
  };

  const svgContent = `
    <svg xmlns="http://www.w3.org/2000/svg" width="128" height="64" viewBox="0 0 128 64">
      ${drawFrame(0, 0)}
      ${drawFrame(64, 1)}
    </svg>
  `;

  return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svgContent.trim())}`;
};

