// ==========================================
// SPRITE SHEET LOGIC (PROCEDURAL GENERATION)
// ==========================================

const TILE_SIZE = 16; 

// Format: { row: number, cols: number[] }
const MOB_ROWS = [
    { row: 0, cols: [0, 1, 2, 3] }, // Green Goblins (Basic)
    { row: 2, cols: [0, 1] }, // Blue Slimes (Round)
    { row: 3, cols: [0, 1, 2] }, // Grey Skeletons (Tall)
    { row: 6, cols: [0, 1, 2, 3] }, // Purple Insects (Winged)
    { row: 7, cols: [0, 1, 2] }, // Brown Beasts (Wide)
];

const ELITE_ROWS = [
    { row: 1, cols: [0, 1] }, // Red Ogres (Big)
    { row: 5, cols: [0, 1] }, // Teal Wraiths (Ghostly)
];

const BOSS_ROWS = [
    { row: 9, cols: [0] }, // Big Gold Dragon
];

// Dynamically generate a pixel art sprite sheet so the user doesn't need to upload one
export const generateProceduralSpriteSheet = (): string => {
  const canvas = document.createElement('canvas');
  const size = 256;
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d');
  if (!ctx) return '';

  type ShapeType = 'BASIC' | 'SLIME' | 'SKELETON' | 'BAT' | 'GHOST' | 'BEAST' | 'OGRE';

  // Helper to draw a pixel mob with different shapes
  const drawMob = (row: number, col: number, color: string, eyes: string = 'white', shape: ShapeType = 'BASIC') => {
      const x = col * TILE_SIZE;
      const y = row * TILE_SIZE;

      ctx.fillStyle = color;

      if (shape === 'SLIME') {
        // Round bottom, smaller top
        ctx.fillRect(x + 3, y + 4, 10, 10);
        ctx.fillRect(x + 2, y + 8, 12, 6);
      } 
      else if (shape === 'SKELETON') {
        // Tall and thin, ribbed
        ctx.fillRect(x + 5, y + 2, 6, 13); // Spine
        ctx.fillRect(x + 4, y + 4, 8, 2); // Ribs
        ctx.fillRect(x + 4, y + 7, 8, 2);
        ctx.fillRect(x + 5, y + 2, 6, 4); // Skull
      }
      else if (shape === 'BAT') {
        // Wings
        ctx.fillRect(x + 6, y + 5, 4, 8); // Body
        ctx.fillStyle = color; // Wings same color or darker
        ctx.globalAlpha = 0.8;
        ctx.beginPath();
        ctx.moveTo(x + 6, y + 7); ctx.lineTo(x + 1, y + 4); ctx.lineTo(x + 6, y + 10);
        ctx.moveTo(x + 10, y + 7); ctx.lineTo(x + 15, y + 4); ctx.lineTo(x + 10, y + 10);
        ctx.fill();
        ctx.globalAlpha = 1.0;
      }
      else if (shape === 'GHOST') {
        // Round top, jagged bottom
        ctx.fillRect(x + 3, y + 2, 10, 10);
        ctx.fillRect(x + 3, y + 12, 2, 3);
        ctx.fillRect(x + 7, y + 12, 2, 3);
        ctx.fillRect(x + 11, y + 12, 2, 3);
      }
      else if (shape === 'OGRE') {
         // Big and bulky
         ctx.fillRect(x + 2, y + 2, 12, 13);
         ctx.fillRect(x + 1, y + 4, 14, 6); // Shoulders
      }
      else if (shape === 'BEAST') {
         // Wide, quadraped
         ctx.fillRect(x + 2, y + 6, 12, 8);
         ctx.fillRect(x + 1, y + 5, 4, 4); // Head
         ctx.fillRect(x + 2, y + 14, 2, 2); // Legs
         ctx.fillRect(x + 12, y + 14, 2, 2);
      }
      else {
        // BASIC box
        ctx.fillRect(x + 2, y + 2, 12, 12);
        // Detail/Shading
        ctx.fillStyle = 'rgba(0,0,0,0.2)';
        ctx.fillRect(x + 2, y + 10, 12, 4);
      }

      // Eyes
      ctx.fillStyle = eyes;
      if (shape === 'SLIME') {
        ctx.fillRect(x + 5, y + 6, 2, 2);
        ctx.fillRect(x + 9, y + 6, 2, 2);
      } else if (shape === 'SKELETON') {
        ctx.fillRect(x + 6, y + 3, 1, 1);
        ctx.fillRect(x + 9, y + 3, 1, 1);
      } else {
        ctx.fillRect(x + 4, y + 5, 2, 2);
        ctx.fillRect(x + 9, y + 5, 2, 2);
        // Pupils
        ctx.fillStyle = 'black';
        ctx.fillRect(x + 5, y + 5, 1, 1);
        ctx.fillRect(x + 10, y + 5, 1, 1);
      }
  };

  // 1. Goblins (Row 0) - Green - BASIC
  [0,1,2,3].forEach(c => drawMob(0, c, '#4ade80', 'white', 'BASIC'));

  // 2. Ogres (Row 1) - Red/Elite - OGRE
  [0,1].forEach(c => drawMob(1, c, '#f87171', '#fecaca', 'OGRE'));

  // 3. Slimes (Row 2) - Blue - SLIME
  [0,1].forEach(c => drawMob(2, c, '#60a5fa', 'white', 'SLIME'));

  // 4. Skeletons (Row 3) - Gray - SKELETON
  [0,1,2].forEach(c => drawMob(3, c, '#cbd5e1', '#0f172a', 'SKELETON'));

  // 5. Wraiths (Row 5) - Teal/Elite - GHOST
  [0,1].forEach(c => drawMob(5, c, '#2dd4bf', '#ccfbf1', 'GHOST'));

  // 6. Insects (Row 6) - Purple - BAT/WINGED
  [0,1,2,3].forEach(c => drawMob(6, c, '#a78bfa', 'red', 'BAT'));

  // 7. Beasts (Row 7) - Orange/Brown - BEAST
  [0,1,2].forEach(c => drawMob(7, c, '#fb923c', 'yellow', 'BEAST'));

  // 8. BOSS (Row 9) - Gold (Big 32x32 fake logic, spread over 2x2 tiles roughly)
  const drawBoss = () => {
      const x = 0; 
      const y = 9 * TILE_SIZE;
      ctx.fillStyle = '#facc15'; // Gold
      ctx.fillRect(x + 2, y + 2, 28, 28); // Big body
      ctx.fillStyle = 'rgba(0,0,0,0.3)';
      ctx.fillRect(x + 4, y + 20, 24, 8);

      // Big Eyes
      ctx.fillStyle = '#991b1b'; // Red eyes
      ctx.fillRect(x + 6, y + 8, 6, 6);
      ctx.fillRect(x + 20, y + 8, 6, 6);
      ctx.fillStyle = '#fff';
      ctx.fillRect(x + 8, y + 9, 2, 2);
      ctx.fillRect(x + 22, y + 9, 2, 2);
  }
  drawBoss();

  return canvas.toDataURL();
};

const getRandomFromConfig = (config: { row: number, cols: number[] }[]): SpriteSource => {
    const group = config[Math.floor(Math.random() * config.length)];
    const col = group.cols[Math.floor(Math.random() * group.cols.length)];

    return {
        x: col * TILE_SIZE,
        y: group.row * TILE_SIZE,
        w: TILE_SIZE,
        h: TILE_SIZE
    };
};

export const getRandomSprite = (type: 'MOB' | 'ELITE' | 'BOSS'): SpriteSource => {
  if (type === 'BOSS') {
    return { x: 0, y: 9 * TILE_SIZE, w: 32, h: 32 };
  } else if (type === 'ELITE') {
    return getRandomFromConfig(ELITE_ROWS);
  } else {
    return getRandomFromConfig(MOB_ROWS);
  }
};

// Singleton AudioContext to avoid hitting mobile browser limits
let audioCtx: AudioContext | null = null;
let bgmInterval: any = null;
let nextNoteTime = 0;
let beatCount = 0;
// VAPORWAVE TEMPO: Slow and chill
const TEMPO = 80; 
const LOOKAHEAD = 25.0; // How frequently to call scheduling function (in milliseconds)
const SCHEDULE_AHEAD_TIME = 0.1; // How far ahead to schedule audio (sec)

// 3 Minutes loop at 80 BPM = 240 Beats.
// 1 Beat = 4 x 16th notes.
// Total steps in loop = 240 * 4 = 960 steps.
const LOOP_LENGTH_STEPS = 960; 

const getAudioContext = () => {
  if (!audioCtx) {
    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    if (Ctx) {
      audioCtx = new Ctx();
    }
  }
  return audioCtx;
};

// Call this on user interaction (e.g. click) to unlock audio on iOS
export const resumeAudioContext = () => {
  const ctx = getAudioContext();
  if (ctx && ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Audio resume failed", e));
  }
};

// ==========================================
// VAPORWAVE INSTRUMENTS
// ==========================================

// 1. Gated/Retro Snare
const playVaporSnare = (time: number) => {
    if (!audioCtx) return;

    // Noise Burst (longer decay for that 80s splash)
    const bufferSize = audioCtx.sampleRate * 0.4; 
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1) * 0.8; // Reduce noise volume slightly
    }
    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;

    const noiseFilter = audioCtx.createBiquadFilter();
    noiseFilter.type = 'lowpass';
    noiseFilter.frequency.value = 3000; // Muffle the top end

    const noiseGain = audioCtx.createGain();
    noiseGain.gain.setValueAtTime(0.3, time);
    noiseGain.gain.exponentialRampToValueAtTime(0.01, time + 0.35); // Long tail

    noise.connect(noiseFilter);
    noiseFilter.connect(noiseGain);
    noiseGain.connect(audioCtx.destination);
    noise.start(time);

    // Body Tone (Low thud)
    const osc = audioCtx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(180, time);
    osc.frequency.exponentialRampToValueAtTime(100, time + 0.1);

    const oscGain = audioCtx.createGain();
    oscGain.gain.setValueAtTime(0.2, time);
    oscGain.gain.exponentialRampToValueAtTime(0.01, time + 0.15);

    osc.connect(oscGain);
    oscGain.connect(audioCtx.destination);
    osc.start(time);
};

// 2. Deep Soft Kick
const playVaporKick = (time: number) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.connect(gain);
    gain.connect(audioCtx.destination);

    // Very low sine sweep
    osc.frequency.setValueAtTime(120, time);
    osc.frequency.exponentialRampToValueAtTime(40, time + 0.4);

    gain.gain.setValueAtTime(0.6, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.4);

    osc.start(time);
    osc.stop(time + 0.4);
};

// 3. Soft Digital HiHat
const playVaporHiHat = (time: number) => {
    if (!audioCtx) return;
    const bufferSize = audioCtx.sampleRate * 0.05;
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 8000; // Very high sizzle

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.1, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    noise.start(time);
};

// 4. Lush Pad (The soul of Vaporwave)
// Plays a chord with slow attack and release, heavily filtered
const playVaporPad = (freqs: number[], time: number, duration: number) => {
    if (!audioCtx) return;

    const masterGain = audioCtx.createGain();
    masterGain.gain.value = 0.15; // Overall volume control

    // Lowpass filter for that underwater/muffled sound
    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(400, time);
    // Slight filter sweep
    filter.frequency.linearRampToValueAtTime(800, time + duration / 2);
    filter.frequency.linearRampToValueAtTime(400, time + duration);

    masterGain.connect(filter);
    filter.connect(audioCtx.destination);

    freqs.forEach((f, i) => {
        const osc = audioCtx!.createOscillator();
        osc.type = 'sawtooth';

        // Slight detune for chorus effect
        const detune = (Math.random() - 0.5) * 10; 
        osc.frequency.value = f;
        osc.detune.value = detune;

        const oscGain = audioCtx!.createGain();
        oscGain.gain.setValueAtTime(0, time);
        // Slow swell (Attack)
        oscGain.gain.linearRampToValueAtTime(0.3, time + duration * 0.3);
        // Slow fade (Release)
        oscGain.gain.linearRampToValueAtTime(0, time + duration);

        osc.connect(oscGain);
        oscGain.connect(masterGain);
        osc.start(time);
        osc.stop(time + duration);
    });
};

// 5. FM-Style Bass
const playVaporBass = (freq: number, time: number, duration: number) => {
    if (!audioCtx) return;

    const osc = audioCtx.createOscillator();
    osc.type = 'triangle'; // Smoother than saw, punchier than sine
    osc.frequency.value = freq;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(600, time);

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + duration); // Plucky decay

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    osc.start(time);
    osc.stop(time + duration);
};

// ==========================================
// COMPOSITION / SCHEDULER
// ==========================================

// Jazzy / Nostalgic Chords (Frequencies)
// Prog: Fmaj7 -> Em7 -> Dm7 -> Cmaj7 (Descending)
const CHORDS = [
    [349.23, 440.00, 523.25, 659.25], // Fmaj7 (F4, A4, C5, E5)
    [329.63, 392.00, 493.88, 587.33], // Em7 (E4, G4, B4, D5)
    [293.66, 349.23, 440.00, 523.25], // Dm7 (D4, F4, A4, C5)
    [261.63, 329.63, 392.00, 493.88], // Cmaj7 (C4, E4, G4, B4)
];
const BASS_NOTES = [
    87.31, // F2
    82.41, // E2
    73.42, // D2
    65.41  // C2
];

const scheduler = () => {
    if (!audioCtx) return;
    while (nextNoteTime < audioCtx.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleVaporwaveLayer(beatCount, nextNoteTime);
        nextNoteTime += 60.0 / TEMPO / 4; // 16th notes
        beatCount = (beatCount + 1) % LOOP_LENGTH_STEPS; // 3 Minute Loop
    }
};

const scheduleVaporwaveLayer = (step: number, time: number) => {
    // step is 16th note index (0 to 959)
    const beat = Math.floor(step / 4); // Quarter note index
    const bar = Math.floor(beat / 4); // Bar index (0 to 60)
    const stepInBar = step % 16; // 0-15

    // --- CHORDS (PADS) ---
    // Change chord every 2 bars (8 beats = 32 steps)
    // Progression length = 8 bars. 
    const chordIndex = Math.floor((bar % 8) / 2); // 0, 0, 1, 1, 2, 2, 3, 3...

    // Play pad on the '1' of every 2 bars, hold for 2 bars
    if (step % 32 === 0) {
        // Intro: Bars 0-4 (Fade in)
        // Main A: Bars 4-20
        // Main B: Bars 20-36
        // Breakdown: Bars 36-44 (No drums)
        // Outro: Bars 44-60

        // Calculate duration based on tempo (2 bars = 8 beats)
        const duration = (60 / TEMPO) * 8; 
        playVaporPad(CHORDS[chordIndex], time, duration);
    }

    // --- DRUMS ---
    // Simple Kick/Snare pattern (Kick on 1 & 3, Snare on 2 & 4)
    // But Vaporwave is often syncopated slightly or sparse.

    // Logic: Play drums only during Main A and Main B and Outro start
    const isDrumSection = (bar >= 4 && bar < 36) || (bar >= 44 && bar < 52);

    if (isDrumSection) {
        // Kick: 1, 3 (plus syncopation)
        if (stepInBar === 0 || stepInBar === 10) playVaporKick(time);

        // Snare: 4, 12 (Backbeat - on beat 2 and 4)
        if (stepInBar === 4 || stepInBar === 12) playVaporSnare(time);

        // HiHat: Every 8th note
        if (stepInBar % 2 === 0) playVaporHiHat(time);
    }

    // --- BASS ---
    // Enters at Bar 12, stays until Bar 44
    const isBassSection = bar >= 12 && bar < 44;

    if (isBassSection) {
        const root = BASS_NOTES[chordIndex];
        const noteLen = 60.0 / TEMPO / 4; // 16th note duration

        // Simple Groove: 1 . . . . . 2 . . 3 . . . . (Syncopated)
        if (stepInBar === 0) playVaporBass(root, time, noteLen * 3);
        if (stepInBar === 3) playVaporBass(root, time, noteLen * 2); // Syncopation
        if (stepInBar === 7) playVaporBass(root * 2, time, noteLen * 1); // Octave pop
        if (stepInBar === 14) playVaporBass(root, time, noteLen * 2);
    }
};

export const startRockBGM = () => {
    resumeAudioContext();
    const ctx = getAudioContext();
    if (!ctx) return;

    if (ctx.state === 'suspended') {
        ctx.resume();
    }

    if (bgmInterval) clearInterval(bgmInterval);

    nextNoteTime = ctx.currentTime + 0.1;
    beatCount = 0;

    bgmInterval = setInterval(scheduler, LOOKAHEAD);
};

export const stopBGM = () => {
    if (bgmInterval) {
        clearInterval(bgmInterval);
        bgmInterval = null;
    }
};

