  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startRockBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound,
  playHealSound
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 120; 
const BASE_XP_REQUIREMENT = 10;
