                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* SINGLE ACTION BUTTON */}
                  <button 
                    onClick={onExit} 
                    className="w-full py-6 font-black text-2xl rounded-2xl mb-3 transition-all border-4 bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)] hover:bg-slate-700 active:scale-95"
                  >
                    RETRY
                    <span className="ml-3 text-sm text-yellow-400 animate-pulse">[ A ]</span>
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

// Singleton AudioContext to avoid hitting mobile browser limits
let audioCtx: AudioContext | null = null;
let bgmInterval: any = null;
let nextNoteTime = 0;
let beatCount = 0;
// VAPORWAVE TEMPO: Slow and chill
const TEMPO = 80; 
const LOOKAHEAD = 25.0; // How frequently to call scheduling function (in milliseconds)
const SCHEDULE_AHEAD_TIME = 0.1; // How far ahead to schedule audio (sec)

// 3 Minutes loop at 80 BPM = 240 Beats.
// 1 Beat = 4 x 16th notes.
// Total steps in loop = 240 * 4 = 960 steps.
const LOOP_LENGTH_STEPS = 960; 

const getAudioContext = () => {
  if (!audioCtx) {
    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    if (Ctx) {
      audioCtx = new Ctx();
    }
  }
  return audioCtx;
};

// Call this on user interaction (e.g. click) to unlock audio on iOS
export const resumeAudioContext = () => {
  const ctx = getAudioContext();
  if (ctx && ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Audio resume failed", e));
  }
};

// ==========================================
// VAPORWAVE INSTRUMENTS
// ==========================================

// 1. Gated/Retro Snare
const playVaporSnare = (time: number) => {
    if (!audioCtx) return;

    // Noise Burst (longer decay for that 80s splash)
    const bufferSize = audioCtx.sampleRate * 0.4; 
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1) * 0.8; // Reduce noise volume slightly
    }
    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;

    const noiseFilter = audioCtx.createBiquadFilter();
    noiseFilter.type = 'lowpass';
    noiseFilter.frequency.value = 3000; // Muffle the top end

    const noiseGain = audioCtx.createGain();
    noiseGain.gain.setValueAtTime(0.3, time);
    noiseGain.gain.exponentialRampToValueAtTime(0.01, time + 0.35); // Long tail

    noise.connect(noiseFilter);
    noiseFilter.connect(noiseGain);
    noiseGain.connect(audioCtx.destination);
    noise.start(time);

    // Body Tone (Low thud)
    const osc = audioCtx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(180, time);
    osc.frequency.exponentialRampToValueAtTime(100, time + 0.1);

    const oscGain = audioCtx.createGain();
    oscGain.gain.setValueAtTime(0.2, time);
    oscGain.gain.exponentialRampToValueAtTime(0.01, time + 0.15);

    osc.connect(oscGain);
    oscGain.connect(audioCtx.destination);
    osc.start(time);
};

// 2. Deep Soft Kick
const playVaporKick = (time: number) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.connect(gain);
    gain.connect(audioCtx.destination);

    // Very low sine sweep
    osc.frequency.setValueAtTime(120, time);
    osc.frequency.exponentialRampToValueAtTime(40, time + 0.4);

    gain.gain.setValueAtTime(0.6, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.4);

    osc.start(time);
    osc.stop(time + 0.4);
};

// 3. Soft Digital HiHat
const playVaporHiHat = (time: number) => {
    if (!audioCtx) return;
    const bufferSize = audioCtx.sampleRate * 0.05;
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 8000; // Very high sizzle

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.1, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    noise.start(time);
};

// 4. Lush Pad (The soul of Vaporwave)
// Plays a chord with slow attack and release, heavily filtered
const playVaporPad = (freqs: number[], time: number, duration: number) => {
    if (!audioCtx) return;

    const masterGain = audioCtx.createGain();
    masterGain.gain.value = 0.15; // Overall volume control

    // Lowpass filter for that underwater/muffled sound
    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(400, time);
    // Slight filter sweep
    filter.frequency.linearRampToValueAtTime(800, time + duration / 2);
    filter.frequency.linearRampToValueAtTime(400, time + duration);

    masterGain.connect(filter);
    filter.connect(audioCtx.destination);

    freqs.forEach((f, i) => {
        const osc = audioCtx!.createOscillator();
        osc.type = 'sawtooth';

        // Slight detune for chorus effect
        const detune = (Math.random() - 0.5) * 10; 
        osc.frequency.value = f;
        osc.detune.value = detune;

        const oscGain = audioCtx!.createGain();
        oscGain.gain.setValueAtTime(0, time);
        // Slow swell (Attack)
        oscGain.gain.linearRampToValueAtTime(0.3, time + duration * 0.3);
        // Slow fade (Release)
        oscGain.gain.linearRampToValueAtTime(0, time + duration);

        osc.connect(oscGain);
        oscGain.connect(masterGain);
        osc.start(time);
        osc.stop(time + duration);
    });
};

// 5. FM-Style Bass
const playVaporBass = (freq: number, time: number, duration: number) => {
    if (!audioCtx) return;

    const osc = audioCtx.createOscillator();
    osc.type = 'triangle'; // Smoother than saw, punchier than sine
    osc.frequency.value = freq;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(600, time);

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + duration); // Plucky decay

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(audioCtx.destination);
    osc.start(time);
    osc.stop(time + duration);
};

// ==========================================
// COMPOSITION / SCHEDULER
// ==========================================

// Jazzy / Nostalgic Chords (Frequencies)
// Prog: Fmaj7 -> Em7 -> Dm7 -> Cmaj7 (Descending)
const CHORDS = [
    [349.23, 440.00, 523.25, 659.25], // Fmaj7 (F4, A4, C5, E5)
    [329.63, 392.00, 493.88, 587.33], // Em7 (E4, G4, B4, D5)
    [293.66, 349.23, 440.00, 523.25], // Dm7 (D4, F4, A4, C5)
    [261.63, 329.63, 392.00, 493.88], // Cmaj7 (C4, E4, G4, B4)
];
const BASS_NOTES = [
    87.31, // F2
    82.41, // E2
    73.42, // D2
    65.41  // C2
];

const scheduler = () => {
    if (!audioCtx) return;
    while (nextNoteTime < audioCtx.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleVaporwaveLayer(beatCount, nextNoteTime);
        nextNoteTime += 60.0 / TEMPO / 4; // 16th notes
        beatCount = (beatCount + 1) % LOOP_LENGTH_STEPS; // 3 Minute Loop
    }
};

const scheduleVaporwaveLayer = (step: number, time: number) => {
    // step is 16th note index (0 to 959)
    const beat = Math.floor(step / 4); // Quarter note index
    const bar = Math.floor(beat / 4); // Bar index (0 to 60)
    const stepInBar = step % 16; // 0-15

    // --- CHORDS (PADS) ---
    // Change chord every 2 bars (8 beats = 32 steps)
    // Progression length = 8 bars. 
    const chordIndex = Math.floor((bar % 8) / 2); // 0, 0, 1, 1, 2, 2, 3, 3...

    // Play pad on the '1' of every 2 bars, hold for 2 bars
    if (step % 32 === 0) {
        // Intro: Bars 0-4 (Fade in)
        // Main A: Bars 4-20
        // Main B: Bars 20-36
        // Breakdown: Bars 36-44 (No drums)
        // Outro: Bars 44-60

        // Calculate duration based on tempo (2 bars = 8 beats)
        const duration = (60 / TEMPO) * 8; 
        playVaporPad(CHORDS[chordIndex], time, duration);
    }

    // --- DRUMS ---
    // Simple Kick/Snare pattern (Kick on 1 & 3, Snare on 2 & 4)
    // But Vaporwave is often syncopated slightly or sparse.

    // Logic: Play drums only during Main A and Main B and Outro start
    const isDrumSection = (bar >= 4 && bar < 36) || (bar >= 44 && bar < 52);

    if (isDrumSection) {
        // Kick: 1, 3 (plus syncopation)
        if (stepInBar === 0 || stepInBar === 10) playVaporKick(time);

        // Snare: 4, 12 (Backbeat - on beat 2 and 4)
        if (stepInBar === 4 || stepInBar === 12) playVaporSnare(time);

        // HiHat: Every 8th note
        if (stepInBar % 2 === 0) playVaporHiHat(time);
    }

    // --- BASS ---
    // Enters at Bar 12, stays until Bar 44
    const isBassSection = bar >= 12 && bar < 44;

    if (isBassSection) {
        const root = BASS_NOTES[chordIndex];
        const noteLen = 60.0 / TEMPO / 4; // 16th note duration

        // Simple Groove: 1 . . . . . 2 . . 3 . . . . (Syncopated)
        if (stepInBar === 0) playVaporBass(root, time, noteLen * 3);
        if (stepInBar === 3) playVaporBass(root, time, noteLen * 2); // Syncopation
        if (stepInBar === 7) playVaporBass(root * 2, time, noteLen * 1); // Octave pop
        if (stepInBar === 14) playVaporBass(root, time, noteLen * 2);
    }
};

export const startRockBGM = () => {
    resumeAudioContext();
    const ctx = getAudioContext();
    if (!ctx) return;

    if (ctx.state === 'suspended') {
        ctx.resume();
    }

    if (bgmInterval) clearInterval(bgmInterval);

    nextNoteTime = ctx.currentTime + 0.1;
    beatCount = 0;

    bgmInterval = setInterval(scheduler, LOOKAHEAD);
};

export const stopBGM = () => {
    if (bgmInterval) {
        clearInterval(bgmInterval);
        bgmInterval = null;
    }
};

// ==========================================
// SFX (Existing)
// ==========================================

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  // Helper to play a bell-like note
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; // Sine wave for a pure bell tone
    osc.frequency.setValueAtTime(freq, startTime);

    // Envelope for bell sound: fast attack, exponential decay
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02); // Quick attack
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration); // Long decay

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // Play "Ding" (High Note, e.g., E5)
  playNote(659.25, now, 0.8);

  // Play "Dong" (Lower Note, e.g., C5) slightly later
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

export const playVictorySound = () => {
  stopBGM(); // Stop music on victory
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  const playNote = (freq: number, startTime: number, duration: number, type: OscillatorType = 'triangle') => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, startTime);

    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
    gain.gain.linearRampToValueAtTime(0, startTime + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // C Major Arpeggio fanfare
  playNote(523.25, now, 0.2);       // C5
  playNote(659.25, now + 0.15, 0.2); // E5
  playNote(783.99, now + 0.30, 0.2); // G5
  playNote(1046.50, now + 0.45, 0.8, 'sine'); // C6 (Long)

  // Confetti sound (noise burst)
  const bufferSize = ctx.sampleRate * 1; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;
  const noiseGain = ctx.createGain();
  noiseGain.gain.setValueAtTime(0.1, now + 0.45);
  noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  noise.connect(noiseGain);
  noiseGain.connect(ctx.destination);
  noise.start(now + 0.45);
};

export const playShootSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // Retro "Pew" sound: Square wave with fast frequency drop
  osc.type = 'square';
  osc.frequency.setValueAtTime(800, now);
  osc.frequency.exponentialRampToValueAtTime(100, now + 0.1);

  // Short, punchy envelope
  gain.gain.setValueAtTime(0.05, now);
  gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start(now);
  osc.stop(now + 0.1);
};

export const playHitSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const t = ctx.currentTime;

  // Impact noise (thud/splat)
  const bufferSize = ctx.sampleRate * 0.1; // 100ms
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;

  // Lowpass filter to make it sound like a solid hit rather than hiss
  const filter = ctx.createBiquadFilter();
  filter.type = 'lowpass';
  filter.frequency.setValueAtTime(1000, t);
  filter.frequency.linearRampToValueAtTime(100, t + 0.1);

  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0.2, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);

  noise.connect(filter);
  filter.connect(gain);
  gain.connect(ctx.destination);

  noise.start(t);
};

// NEW: Heal Sound (Rising magical chime)
export const playHealSound = () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    const t = ctx.currentTime;

    // 1. Rising Sine Arpeggio (Major Triad)
    const notes = [523.25, 659.25, 783.99, 1046.50]; // C, E, G, C

    notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, t + i * 0.05);

        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0, t + i * 0.05);
        gain.gain.linearRampToValueAtTime(0.1, t + i * 0.05 + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.05 + 0.3);

        osc.connect(gain);
        gain.connect(ctx.destination);

        osc.start(t + i * 0.05);
        osc.stop(t + i * 0.05 + 0.3);
    });

    // 2. Sparkle noise
    const bufferSize = ctx.sampleRate * 0.3;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1);
    }
    const noise = ctx.createBufferSource();
    noise.buffer = buffer;

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 4000;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.05, t);
    gain.gain.linearRampToValueAtTime(0, t + 0.3);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);
    noise.start(t);
};

export const speakText = (text: string, rate: number = 1.0) => {
  if (!('speechSynthesis' in window)) return;

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US';
  utterance.rate = rate; 

  // Adjust pitch slightly higher to sound "younger"
  utterance.pitch = 1.15; 

  const voices = window.speechSynthesis.getVoices();

  // Priority list for female-sounding voices
  // 'Samantha' (iOS/Mac), 'Google US English' (Android/Chrome), 'Microsoft Zira' (Windows), 'Jenny'
  const preferredNames = ['Samantha', 'Google US English', 'Zira', 'Jenny', 'Susan', 'Vicki', 'Kathy'];

  const femaleVoice = voices.find(v => 
    preferredNames.some(name => v.name.includes(name)) && v.lang.startsWith('en')
  );

  // Fallback: try to find any English voice
  const fallbackVoice = voices.find(v => v.lang.startsWith('en'));

  if (femaleVoice) {
    utterance.voice = femaleVoice;
  } else if (fallbackVoice) {
    utterance.voice = fallbackVoice;
  }

  window.speechSynthesis.speak(utterance);
};

