    const bufferSize = ctx.sampleRate * 0.1;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0); for (let i = 0; i < bufferSize; i++) data[i] = (Math.random() * 2 - 1);
    const noise = ctx.createBufferSource(); noise.buffer = buffer;
    const filter = ctx.createBiquadFilter(); filter.type = 'bandpass';
    filter.frequency.setValueAtTime(800, t); filter.Q.value = 1;
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.1, t); gain.gain.linearRampToValueAtTime(0, t + 0.1);
    noise.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
    noise.start(t);
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound,
  playHealSound,
  playFireShootSound,
  playIceShootSound,
  playLightningShootSound,
  playWindShootSound,
  setBgmTheme
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 100; // Slightly faster initial spawn
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// PERFORMANCE CAPS - Increased due to optimization
const MAX_ENEMIES = 350;      // Increased from 200
const MAX_XP_GEMS = 200;      // Increased from 150
const MAX_PROJECTILES = 150;  // Increased from 100
const MAX_LIGHTNING_CHAINS = 30; 
const MAX_STORM_EFFECTS = 8;     

// New Lightning Structures
interface LightningSegment {
    x1: number; y1: number;
    x2: number; y2: number;
}

interface LightningChain {
    segments: LightningSegment[];
    life: number;
    maxLife: number;
    colorOuter: string;
    colorInner: string;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, 
    attackSpeed: 15, // Doubled frequency (was 30)
    projectileSpeed: 3, // Halved speed (was 6)
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,

    activeElement: 'NONE',

    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, // 3 seconds (60fps)
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 75 // Reduced from 150 to 75
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  // New: Invulnerability Timer for Player
  const playerInvulnTimerRef = useRef(0);

  // Gamepad State Refs
  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startBGM(); // Start DEFAULT BGM
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;
        draw();
        update();
        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex]); 

  // --- LIGHTNING GENERATOR (OPTIMIZED) ---
  const createLightningBolt = (x1: number, y1: number, x2: number, y2: number): LightningSegment[] => {
      const segments: LightningSegment[] = [];
      const dist = Math.hypot(x2 - x1, y2 - y1);
      // OPTIMIZATION: Fewer steps. Approx 1 segment per 50px (was 30px)
      const steps = Math.max(3, Math.floor(dist / 50)); 

      let prevX = x1;
      let prevY = y1;

      for (let i = 1; i <= steps; i++) {
          const t = i / steps;
          let currX = x1 + (x2 - x1) * t;
          let currY = y1 + (y2 - y1) * t;

          // Add Jitter
          if (i !== steps) {
              const jitter = 25; 
              currX += (Math.random() - 0.5) * jitter;
              currY += (Math.random() - 0.5) * jitter;
          }

          segments.push({
              x1: prevX, y1: prevY,
              x2: currX, y2: currY,
          });

          prevX = currX;
          prevY = currY;
      }
      return segments;
  };

  const update = () => {
    // 1. Handle Game Over / Victory
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const btnA = gp.buttons[0]?.pressed; // Select
            if (btnA && !gamepadButtonRef.current.button0) {
                 onExit();
            }
            gamepadButtonRef.current.button0 = btnA;
        }
        return; 
    }

    // 2. Handle Quiz Pause
    if (quizWordRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        return;
    }

    // 3. Handle Upgrade Menu (Paused Logic)
    if (showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;

        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const axisX = gp.axes[0];
            const btnA = gp.buttons[0]?.pressed; 
            const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
            const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

            if (btnLeft && !gamepadButtonRef.current.left) {
                setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
            }
            if (btnRight && !gamepadButtonRef.current.right) {
                setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
            }
            if (btnA && !gamepadButtonRef.current.button0) {
                 if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                     applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                 }
            }
            gamepadButtonRef.current.left = btnLeft;
            gamepadButtonRef.current.right = btnRight;
            gamepadButtonRef.current.button0 = btnA;
        }
        return;
    }

    // 4. Main Game Loop (Unpaused)
    if (isPausedRef.current) isPausedRef.current = false;

    // PERFORMANCE CLEANUP - Using Splice instead of filter to avoid GC
    if (frameCountRef.current % 60 === 0) {
        if (xpGemsRef.current.length > MAX_XP_GEMS) {
             // Remove oldest gems
             xpGemsRef.current.splice(0, xpGemsRef.current.length - MAX_XP_GEMS);
        }
    }

    if (playerInvulnTimerRef.current > 0) {
        playerInvulnTimerRef.current--;
    }

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];

        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) {
             toggleFullscreen();
        }
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // === STORM / WIND PHYSICS LOGIC (OPTIMIZED) ===
    if (stormEffectsRef.current.length > 0) {
        const activeStorms = stormEffectsRef.current;
        const enemies = enemiesRef.current;

        for (let i = 0; i < activeStorms.length; i++) {
            const storm = activeStorms[i];
            storm.angle += 0.2;

            for (let j = 0; j < enemies.length; j++) {
                const e = enemies[j];
                if (e.hp <= 0) continue;

                const dx = storm.x - e.x;
                const dy = storm.y - e.y;
                // Pre-check Manhattan distance for speed
                if (Math.abs(dx) > storm.radius || Math.abs(dy) > storm.radius) continue;

                const distSq = dx * dx + dy * dy;
                if (distSq < storm.radius * storm.radius && distSq > 225) { 
                     const dist = Math.sqrt(distSq);
                     const factor = 3.5 / dist; 
                     e.x += dx * factor;
                     e.y += dy * factor;
                }
            }
        }
    }

    spawnEnemies();

    // OPTIMIZED ENEMY LOOP (In-place updates, backward iteration)
    // We avoid .filter() to prevent garbage collection spikes
    for (let i = enemiesRef.current.length - 1; i >= 0; i--) {
        const e = enemiesRef.current[i];

        // MOVEMENT
        const angle = Math.atan2(player.y - e.y, player.x - e.x);
        let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
        if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

        if (e.burnTimer && e.burnTimer > 0) { 
            e.burnTimer--; 
            if (frameCountRef.current % 30 === 0 && e.burnDamageRef) {
                e.hp -= e.burnDamageRef; 
            }
        }

        e.x += Math.cos(angle) * speed; 
        e.y += Math.sin(angle) * speed;

        // PLAYER COLLISION
        if (Math.abs(player.x - e.x) < 50 && Math.abs(player.y - e.y) < 50) { // Fast pre-check
            if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
                takeDamage(e.damage);
            }
        }

        // DEATH CHECK
        if (e.hp <= 0) {
            if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
            killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

            const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);
            for (let k = 0; k < dropCount; k++) {
                const isSnack = Math.random() < 0.05; 
                if (xpGemsRef.current.length < MAX_XP_GEMS) { 
                    xpGemsRef.current.push({ 
                        id: Math.random().toString(), 
                        x: e.x + (Math.random() * 30 - 15), 
                        y: e.y + (Math.random() * 30 - 15), 
                        width: 24, height: 24, 
                        type: isSnack ? 'SNACK' : 'XP', 
                        vx:0, vy:0, hp:1, maxHp:1, damage:0 
                    });
                }
            }
            // Remove from array efficiently
            enemiesRef.current.splice(i, 1);
        }
    }

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    // OPTIMIZED PROJECTILE LOOP (Backward iteration for safe removal)
    for (let i = projectilesRef.current.length - 1; i >= 0; i--) {
        const p = projectilesRef.current[i];
        p.x += p.vx; 
        p.y += p.vy;

        let hit = false;

        if (p.type === 'PROJECTILE') {
            // Check against enemies
            for (let j = 0; j < enemiesRef.current.length; j++) {
                const enemy = enemiesRef.current[j];
                const dx = p.x - enemy.x;
                const dy = p.y - enemy.y;

                // PERFORMANCE: Manhattan Distance Check first (avoid Sqrt)
                if (Math.abs(dx) > 40 || Math.abs(dy) > 40) continue;

                if (Math.hypot(dx, dy) < (enemy.width/2 + 10)) {
                    enemy.hp -= p.damage;

                    // Elemental Effects
                    if (p.element === 'ICE') { 
                        enemy.freezeTimer = stats.freezeDuration; 
                        playIceHitSound(); 
                    }
                    else if (p.element === 'FIRE') { 
                        enemy.burnTimer = 300; 
                        enemy.burnDamageRef = stats.burnDamage;
                        playFireHitSound(); 
                    }
                    else if (p.element === 'LIGHTNING') {
                        if (lightningChainsRef.current.length < MAX_LIGHTNING_CHAINS) {
                            // Find chain targets (simple loop)
                            let chains = 0;
                            for (let k=0; k < enemiesRef.current.length; k++) {
                                if (chains >= stats.chainCount) break;
                                const n = enemiesRef.current[k];
                                if (n !== enemy && Math.abs(n.x - enemy.x) < 400 && Math.abs(n.y - enemy.y) < 400) {
                                    n.hp -= Math.ceil(p.damage/2);
                                    const segments = createLightningBolt(enemy.x, enemy.y, n.x, n.y);
                                    lightningChainsRef.current.push({ 
                                        segments, life: 20, maxLife: 20,
                                        colorOuter: 'rgba(180, 230, 255, 0.4)', colorInner: '#ffffff'
                                    });
                                    chains++;
                                }
                            }
                        }
                        playLightningHitSound();
                    } 
                    else if (p.element === 'WIND') {
                        const duration = 180;
                        if (stormEffectsRef.current.length < MAX_STORM_EFFECTS) {
                            stormEffectsRef.current.push({
                                x: enemy.x, y: enemy.y, life: duration, maxLife: duration, 
                                angle: Math.random() * Math.PI * 2, radius: stats.windRadius
                            });
                        }
                        playWindHitSound();
                    } else { 
                        playHitSound(); 
                    }

                    hit = true; 
                    break; // Bullet hits one enemy
                }
            }
        }

        // Cleanup Bullet
        if (hit || p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT) {
            projectilesRef.current.splice(i, 1);
        }
    }

    // Cap Projectiles if they missed everything (Safety net)
    if (projectilesRef.current.length > MAX_PROJECTILES) {
        projectilesRef.current.splice(0, projectilesRef.current.length - MAX_PROJECTILES);
    }

    // XP GEMS LOOP (Backward)
    for (let i = xpGemsRef.current.length - 1; i >= 0; i--) {
        const gem = xpGemsRef.current[i];
        const dx = player.x - gem.x;
        const dy = player.y - gem.y;

        if (Math.abs(dx) < stats.pickupRange && Math.abs(dy) < stats.pickupRange) {
             const dist = Math.hypot(dx, dy);
             if (dist < stats.pickupRange) {
                 gem.x += dx * 0.15;
                 gem.y += dy * 0.15;

                 if (dist < 30) {
                     if (gem.type === 'SNACK') healPlayer(10);
                     else gainXp(1);
                     xpGemsRef.current.splice(i, 1);
                 }
             }
        }
    }

    // Throttle UI updates
    if (frameCountRef.current % 2 === 0) setUiStats({...statsRef.current});
  };

  const healPlayer = (amount: number) => {
      playHealSound();
      statsRef.current.hp = Math.min(statsRef.current.maxHp, statsRef.current.hp + amount);
      setUiStats({...statsRef.current}); 
  };

  const spawnEnemies = () => {
      // ENEMY CAP CHECK
      if (enemiesRef.current.length >= MAX_ENEMIES) return;

      const time = gameTimeRef.current;
      const level = statsRef.current.level;

      // Changed floor to 3 frames (Very Fast) to allow high density if performance allows
      let spawnRate = Math.max(3, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));

      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }
      const ent: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };
      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    const s = statsRef.current;
    if (s.activeElement === 'FIRE') playFireShootSound();
    else if (s.activeElement === 'ICE') playIceShootSound();
    else if (s.activeElement === 'LIGHTNING') playLightningShootSound();
    else if (s.activeElement === 'WIND') playWindShootSound();
    else playShootSound();

    const p = playerRef.current;
    let el: any = s.activeElement; 
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        const a = Math.random() * Math.PI * 2;
        projectilesRef.current.push({
            id: Math.random().toString(), x: p.x, y: p.y, width: 24, height: 24, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        });
    }
  };

  const takeDamage = (a: number) => { 
      if (playerInvulnTimerRef.current > 0) return;
      statsRef.current.hp -= a; 
      playErrorSound(); 
      playerInvulnTimerRef.current = 30;
      setUiStats({...statsRef.current});
      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({
          id: 'pickup_range', name: '致命磁场', description: '拾取范围 +50%', icon: '🧲', weight: 20,
          apply: (s) => ({ ...s, pickupRange: Math.ceil(s.pickupRange * 1.5) })
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围扩大` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 75 : Math.floor(s.windRadius * 1.5) }) 
          });
      }

      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); 
                  break;
              }
          }
      }
      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); 
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.damage += 1; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.6); 
      if (statsRef.current.activeElement !== 'NONE') {
         setBgmTheme(statsRef.current.activeElement);
      }
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; 
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }
        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };

    xpGemsRef.current.forEach(g => { 
        if (g.type === 'SNACK') {
            const img = spritesRef.current['SNACK'];
            if (img && img.complete) {
                ctx.drawImage(img, g.x - 12, g.y - 12, 24, 24);
            } else {
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill();
            }
        } else {
            const img = spritesRef.current['XP'];
            if (img && img.complete) {
                ctx.drawImage(img, g.x - 10, g.y - 10, 20, 20);
            } else {
                ctx.fillStyle = '#60a5fa'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); 
            }
        }
    });

    // === OPTIMIZED STORM DRAWING (Fewer ops) ===
    stormEffectsRef.current = stormEffectsRef.current.filter(s => {
        if (s.life <= 0) return false;
        ctx.save();
        ctx.translate(s.x, s.y);
        const opacity = s.life / s.maxLife;
        ctx.rotate(s.angle);

        ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
        ctx.lineWidth = 4;

        // Simple Concentric Rings instead of complex spiral paths for performance
        ctx.beginPath();
        ctx.arc(0, 0, s.radius * 0.3, 0, Math.PI * 2);
        ctx.stroke();

        ctx.beginPath();
        ctx.arc(0, 0, s.radius * 0.7, 0, Math.PI * 1.5);
        ctx.stroke();

        ctx.beginPath();
        ctx.arc(0, 0, s.radius, 1, Math.PI * 1.8);
        ctx.stroke();

        // Eye
        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.beginPath(); ctx.arc(0, 0, 15, 0, Math.PI * 2); ctx.fill();

        ctx.restore();
        s.life--;
        return true;
    });

    enemiesRef.current.forEach(drawEnt);

    if (playerInvulnTimerRef.current > 0) {
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) ctx.globalAlpha = 0.4;
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; 

    projectilesRef.current.forEach(p => { 
        let spriteKey = 'PROJ_NORMAL';
        if (p.element === 'FIRE') spriteKey = 'PROJ_FIRE';
        else if (p.element === 'ICE') spriteKey = 'PROJ_ICE';
        else if (p.element === 'LIGHTNING') spriteKey = 'PROJ_LIGHTNING';
        else if (p.element === 'WIND') spriteKey = 'PROJ_WIND';

        const img = spritesRef.current[spriteKey];
        if (img && img.complete) {
             ctx.save();
             ctx.translate(p.x, p.y);
             ctx.rotate(Math.atan2(p.vy, p.vx));
             ctx.drawImage(img, -p.width/2, -p.height/2, p.width, p.height);
             ctx.restore();
        } else {
            ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); 
            ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); 
        }
    });

    // === OPTIMIZED LIGHTNING DRAWING (BATCH + NO SHADOW BLUR) ===
    if (lightningChainsRef.current.length > 0) {
        const chains = lightningChainsRef.current.filter(c => c.life > 0);
        lightningChainsRef.current = chains; // Update ref

        if (chains.length > 0) {
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';

            // Pass 1: Outer Glow (Thick, low opacity)
            // Batch all segments into one path to reduce draw calls
            ctx.beginPath();
            ctx.lineWidth = 6; // Thicker line
            ctx.strokeStyle = chains[0].colorOuter; // Use first color for batch simplicity

            chains.forEach(c => {
                 c.segments.forEach(seg => {
                     ctx.moveTo(seg.x1, seg.y1);
                     ctx.lineTo(seg.x2, seg.y2);
                 });
                 c.life--;
            });
            ctx.stroke();

            // Pass 2: Inner Core (Thin, white)
            ctx.beginPath();
            ctx.lineWidth = 2;
            ctx.strokeStyle = '#ffffff';
            chains.forEach(c => {
                 c.segments.forEach(seg => {
                     ctx.moveTo(seg.x1, seg.y1);
                     ctx.lineTo(seg.x2, seg.y2);
                 });
            });
            ctx.stroke();
        }
    }
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-8 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* SINGLE ACTION BUTTON */}
                  <button 
                    onClick={onExit} 
                    className="w-full py-6 font-black text-2xl rounded-2xl mb-3 transition-all border-4 bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)] hover:bg-slate-700 active:scale-95"
                  >
                    RETRY
                    <span className="ml-3 text-sm text-yellow-400 animate-pulse">[ A ]</span>
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound,
  playHealSound,
  playFireShootSound,
  playIceShootSound,
  playLightningShootSound,
  playWindShootSound,
  setBgmTheme
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 100; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// PERFORMANCE CAPS
const MAX_ENEMIES = 400;      // Further increased cap supported by object pooling
const MAX_XP_GEMS = 250;      // Increased cap
const MAX_PROJECTILES = 200;  
const MAX_LIGHTNING_CHAINS = 20; 
const MAX_STORM_EFFECTS = 8;     

// SPATIAL GRID CONFIG
const GRID_CELL_SIZE = 150; // Size of collision cells
const GRID_COLS = Math.ceil(GAME_WIDTH / GRID_CELL_SIZE);
const GRID_ROWS = Math.ceil(GAME_HEIGHT / GRID_CELL_SIZE);

// New Lightning Structures
interface LightningSegment {
    x1: number; y1: number;
    x2: number; y2: number;
}

interface LightningChain {
    segments: LightningSegment[];
    life: number;
    maxLife: number;
    colorOuter: string;
    colorInner: string;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, 
    attackSpeed: 15, 
    projectileSpeed: 3, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    activeElement: 'NONE',
    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, 
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 75 
  });

  // ACTIVE ENTITY LISTS
  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);

  // OBJECT POOLS (To reduce GC)
  const enemyPoolRef = useRef<Entity[]>([]);
  const projectilePoolRef = useRef<Entity[]>([]);
  const gemPoolRef = useRef<Entity[]>([]);

  // SPATIAL GRID REFS (To optimize collision)
  // 3D Array: Col -> Row -> Array of indices in enemiesRef
  const spatialGridRef = useRef<number[][][]>([]);

  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  const playerInvulnTimerRef = useRef(0);

  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  // INITIALIZE SPATIAL GRID
  useEffect(() => {
    spatialGridRef.current = Array(GRID_COLS).fill(null).map(() => 
        Array(GRID_ROWS).fill(null).map(() => [])
    );
  }, []);

  // --- POOLING HELPERS ---
  const recycleEntity = (activeList: Entity[], pool: Entity[], index: number) => {
      const ent = activeList[index];
      // Reset critical fields to avoid stale state bugs
      ent.vx = 0; ent.vy = 0;
      ent.freezeTimer = 0; ent.burnTimer = 0;
      pool.push(ent);

      // FAST REMOVE (Swap & Pop) - O(1)
      const last = activeList[activeList.length - 1];
      activeList[index] = last;
      activeList.pop();
  };

  const spawnFromPool = (pool: Entity[], fallback: Entity): Entity => {
      if (pool.length > 0) {
          const ent = pool.pop()!;
          // Overwrite all properties of reused entity with fallback values
          return Object.assign(ent, fallback);
      }
      return fallback;
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startBGM(); 
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;
        draw();
        update();
        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex]); 

  // --- LIGHTNING GENERATOR ---
  const createLightningBolt = (x1: number, y1: number, x2: number, y2: number): LightningSegment[] => {
      const segments: LightningSegment[] = [];
      const dist = Math.hypot(x2 - x1, y2 - y1);
      const steps = Math.max(3, Math.floor(dist / 50)); 

      let prevX = x1;
      let prevY = y1;

      for (let i = 1; i <= steps; i++) {
          const t = i / steps;
          let currX = x1 + (x2 - x1) * t;
          let currY = y1 + (y2 - y1) * t;

          if (i !== steps) {
              const jitter = 25; 
              currX += (Math.random() - 0.5) * jitter;
              currY += (Math.random() - 0.5) * jitter;
          }

          segments.push({
              x1: prevX, y1: prevY,
              x2: currX, y2: currY,
          });
          prevX = currX;
          prevY = currY;
      }
      return segments;
  };

  const update = () => {
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const btnA = gp.buttons[0]?.pressed; 
            if (btnA && !gamepadButtonRef.current.button0) onExit();
            gamepadButtonRef.current.button0 = btnA;
        }
        return; 
    }

    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        // Gamepad handling for menus is done in effects or simple checks
        if (showUpgradesRef.current) handleUpgradeGamepad();
        return;
    }

    if (isPausedRef.current) isPausedRef.current = false;

    // POOL CLEANUP (If too large, trim pools to save RAM)
    if (frameCountRef.current % 300 === 0) {
        if (enemyPoolRef.current.length > 50) enemyPoolRef.current.length = 50;
        if (projectilePoolRef.current.length > 50) projectilePoolRef.current.length = 50;
    }

    // CAP CLEANUP (Remove oldest active if over cap)
    // We use swap-remove at index 0 (which replaces 0 with last), effectively random removal but keeps array packed
    // Actually, simple FIFO slice is better for caps, but creates GC. 
    // Let's use recycleEntity on index 0 until cap is met.
    while (xpGemsRef.current.length > MAX_XP_GEMS) {
         recycleEntity(xpGemsRef.current, gemPoolRef.current, 0);
    }

    if (playerInvulnTimerRef.current > 0) playerInvulnTimerRef.current--;

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // PLAYER MOVEMENT
    let dx = 0; let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) toggleFullscreen();
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        const length = Math.sqrt(dx * dx + dy * dy);
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    // Clamp Player
    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // ANIMATION TICK
    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }

    // --- CLEAR SPATIAL GRID ---
    for (let c = 0; c < GRID_COLS; c++) {
        for (let r = 0; r < GRID_ROWS; r++) {
            spatialGridRef.current[c][r].length = 0; // Clear without allocation
        }
    }

    // --- SPAWN LOGIC ---
    spawnEnemies();

    // --- ENEMY LOOP (Backward for safe swap-remove) ---
    for (let i = enemiesRef.current.length - 1; i >= 0; i--) {
        const e = enemiesRef.current[i];

        // MOVEMENT
        const angle = Math.atan2(player.y - e.y, player.x - e.x);
        let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
        if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

        if (e.burnTimer && e.burnTimer > 0) { 
            e.burnTimer--; 
            if (frameCountRef.current % 30 === 0 && e.burnDamageRef) e.hp -= e.burnDamageRef; 
        }

        e.x += Math.cos(angle) * speed; 
        e.y += Math.sin(angle) * speed;

        // REGISTER TO GRID
        const gx = Math.floor(e.x / GRID_CELL_SIZE);
        const gy = Math.floor(e.y / GRID_CELL_SIZE);
        if (gx >= 0 && gx < GRID_COLS && gy >= 0 && gy < GRID_ROWS) {
            spatialGridRef.current[gx][gy].push(i);
        }

        // PLAYER COLLISION (Simple Box Check)
        if (Math.abs(player.x - e.x) < 50 && Math.abs(player.y - e.y) < 50) {
            if (Math.hypot(player.x - e.x, player.y - e.y) < (player.width/2 + e.width/2)) {
                takeDamage(e.damage);
            }
        }

        // DEATH CHECK
        if (e.hp <= 0) {
            handleEnemyDeath(e);
            recycleEntity(enemiesRef.current, enemyPoolRef.current, i);
        }
    }

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    // --- PROJECTILE LOOP (Backward) ---
    for (let i = projectilesRef.current.length - 1; i >= 0; i--) {
        const p = projectilesRef.current[i];
        p.x += p.vx; 
        p.y += p.vy;

        let hit = false;

        if (p.type === 'PROJECTILE') {
            // SPATIAL GRID CHECK
            // Check current cell and immediate neighbors (3x3 area)
            const pcx = Math.floor(p.x / GRID_CELL_SIZE);
            const pcy = Math.floor(p.y / GRID_CELL_SIZE);

            // Iterate Neighbors
            neighborLoop:
            for (let ox = -1; ox <= 1; ox++) {
                for (let oy = -1; oy <= 1; oy++) {
                    const cx = pcx + ox;
                    const cy = pcy + oy;

                    if (cx >= 0 && cx < GRID_COLS && cy >= 0 && cy < GRID_ROWS) {
                        const cellEnemies = spatialGridRef.current[cx][cy];
                        // Check all enemies in this cell
                        for (let k = 0; k < cellEnemies.length; k++) {
                            const enemyIdx = cellEnemies[k];
                            const enemy = enemiesRef.current[enemyIdx];

                            // Already dead check (in case multiple bullets hit same frame)
                            if (!enemy || enemy.hp <= 0) continue; 

                            const dx = p.x - enemy.x;
                            const dy = p.y - enemy.y;

                            if (Math.abs(dx) < 40 && Math.abs(dy) < 40) { // Manhattan Pre-check
                                if (dx*dx + dy*dy < (enemy.width/2 + 10)**2) {
                                    applyHitEffect(enemy, p);
                                    hit = true; 
                                    break neighborLoop; // Bullet consumed
                                }
                            }
                        }
                    }
                }
            }
        }

        // Cleanup Bullet
        if (hit || p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT) {
            recycleEntity(projectilesRef.current, projectilePoolRef.current, i);
        }
    }

    // --- STORM LOGIC (Optimized with Grid too?) ---
    // Keeping O(N) check for storms is okay since storm count is low (8), but checking 400 enemies is 3200 checks.
    // Let's rely on Manhattan check inside loop.
    if (stormEffectsRef.current.length > 0) {
        for (let i = 0; i < stormEffectsRef.current.length; i++) {
            const storm = stormEffectsRef.current[i];
            storm.angle += 0.2;
            // Iterate all enemies (Grid optimization possible but maybe overkill for 8 storms)
            // Just use simple array for robustness here
            for (let j = 0; j < enemiesRef.current.length; j++) {
                const e = enemiesRef.current[j];
                const dx = storm.x - e.x;
                const dy = storm.y - e.y;
                if (Math.abs(dx) > storm.radius || Math.abs(dy) > storm.radius) continue;
                const distSq = dx*dx + dy*dy;
                if (distSq < storm.radius**2 && distSq > 225) { 
                     const dist = Math.sqrt(distSq);
                     const factor = 3.5 / dist; 
                     e.x += dx * factor; e.y += dy * factor;
                }
            }
        }
    }

    // --- GEM LOOP ---
    for (let i = xpGemsRef.current.length - 1; i >= 0; i--) {
        const gem = xpGemsRef.current[i];
        const dx = player.x - gem.x;
        const dy = player.y - gem.y;

        if (Math.abs(dx) < stats.pickupRange && Math.abs(dy) < stats.pickupRange) {
             const distSq = dx*dx + dy*dy;
             if (distSq < stats.pickupRange**2) {
                 gem.x += dx * 0.15;
                 gem.y += dy * 0.15;

                 if (distSq < 900) { // 30^2
                     if (gem.type === 'SNACK') healPlayer(10);
                     else gainXp(1);
                     recycleEntity(xpGemsRef.current, gemPoolRef.current, i);
                 }
             }
        }
    }

    if (frameCountRef.current % 2 === 0) setUiStats({...statsRef.current});
  };

  const handleUpgradeGamepad = () => {
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        const axisX = gp.axes[0];
        const btnA = gp.buttons[0]?.pressed; 
        const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
        const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

        if (btnLeft && !gamepadButtonRef.current.left) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        }
        if (btnRight && !gamepadButtonRef.current.right) {
            setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
        }
        if (btnA && !gamepadButtonRef.current.button0) {
                if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                    applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                }
        }
        gamepadButtonRef.current.left = btnLeft;
        gamepadButtonRef.current.right = btnRight;
        gamepadButtonRef.current.button0 = btnA;
    }
  };

  const applyHitEffect = (enemy: Entity, p: Entity) => {
      const stats = statsRef.current;
      enemy.hp -= p.damage;

      if (p.element === 'ICE') { 
          enemy.freezeTimer = stats.freezeDuration; 
          playIceHitSound(); 
      }
      else if (p.element === 'FIRE') { 
          enemy.burnTimer = 300; 
          enemy.burnDamageRef = stats.burnDamage;
          playFireHitSound(); 
      }
      else if (p.element === 'LIGHTNING') {
          if (lightningChainsRef.current.length < MAX_LIGHTNING_CHAINS) {
              // Simple chain logic
              let chains = 0;
              for (let k=0; k < enemiesRef.current.length; k++) {
                  if (chains >= stats.chainCount) break;
                  const n = enemiesRef.current[k];
                  if (n !== enemy && Math.abs(n.x - enemy.x) < 400 && Math.abs(n.y - enemy.y) < 400) {
                      n.hp -= Math.ceil(p.damage/2);
                      const segments = createLightningBolt(enemy.x, enemy.y, n.x, n.y);
                      lightningChainsRef.current.push({ 
                          segments, life: 20, maxLife: 20,
                          colorOuter: 'rgba(180, 230, 255, 0.4)', colorInner: '#ffffff'
                      });
                      chains++;
                  }
              }
          }
          playLightningHitSound();
      } 
      else if (p.element === 'WIND') {
          if (stormEffectsRef.current.length < MAX_STORM_EFFECTS) {
              stormEffectsRef.current.push({
                  x: enemy.x, y: enemy.y, life: 180, maxLife: 180, 
                  angle: Math.random() * Math.PI * 2, radius: stats.windRadius
              });
          }
          playWindHitSound();
      } else { 
          playHitSound(); 
      }
  };

  const handleEnemyDeath = (e: Entity) => {
      if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
      killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

      const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);
      for (let k = 0; k < dropCount; k++) {
          if (xpGemsRef.current.length >= MAX_XP_GEMS) break; // Hard cap check
          const isSnack = Math.random() < 0.05; 

          const drop = spawnFromPool(gemPoolRef.current, {
              id: '', // reused objects don't strict need id for rendering if key is index
              x: e.x + (Math.random() * 30 - 15),
              y: e.y + (Math.random() * 30 - 15),
              width: 24, height: 24,
              type: isSnack ? 'SNACK' : 'XP',
              vx:0, vy:0, hp:1, maxHp:1, damage:0
          });
          xpGemsRef.current.push(drop);
      }
  };

  const healPlayer = (amount: number) => {
      playHealSound();
      statsRef.current.hp = Math.min(statsRef.current.maxHp, statsRef.current.hp + amount);
      setUiStats({...statsRef.current}); 
  };

  const spawnEnemies = () => {
      if (enemiesRef.current.length >= MAX_ENEMIES) return;

      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(3, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));

      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      const fallback: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };

      const ent = spawnFromPool(enemyPoolRef.current, fallback);
      // Ensure key props are reset if recycled
      ent.x = x; ent.y = y; ent.hp = ent.maxHp; 
      ent.width = fallback.width; ent.height = fallback.height;
      ent.type = category as any;
      ent.spriteSource = fallback.spriteSource; 

      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    const s = statsRef.current;
    if (s.activeElement === 'FIRE') playFireShootSound();
    else if (s.activeElement === 'ICE') playIceShootSound();
    else if (s.activeElement === 'LIGHTNING') playLightningShootSound();
    else if (s.activeElement === 'WIND') playWindShootSound();
    else playShootSound();

    const p = playerRef.current;
    let el: any = s.activeElement; 
    if (el === 'NONE') el = 'NORMAL';

    for (let i = 0; i < s.projectileCount; i++) {
        if (projectilesRef.current.length >= MAX_PROJECTILES) break;
        const a = Math.random() * Math.PI * 2;

        const fallback: Entity = {
            id: Math.random().toString(), x: p.x, y: p.y, width: 24, height: 24, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        };
        const bullet = spawnFromPool(projectilePoolRef.current, fallback);
        // Reset recycled props
        bullet.x = p.x; bullet.y = p.y;
        bullet.vx = Math.cos(a) * s.projectileSpeed;
        bullet.vy = Math.sin(a) * s.projectileSpeed;
        bullet.element = el;
        bullet.damage = s.damage;

        projectilesRef.current.push(bullet);
    }
  };

  const takeDamage = (a: number) => { 
      if (playerInvulnTimerRef.current > 0) return;
      statsRef.current.hp -= a; 
      playErrorSound(); 
      playerInvulnTimerRef.current = 30;
      setUiStats({...statsRef.current});
      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({
          id: 'pickup_range', name: '致命磁场', description: '拾取范围 +50%', icon: '🧲', weight: 20,
          apply: (s) => ({ ...s, pickupRange: Math.ceil(s.pickupRange * 1.5) })
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围扩大` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 75 : Math.floor(s.windRadius * 1.5) }) 
          });
      }

      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); 
                  break;
              }
          }
      }
      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); 
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.damage += 1; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.6); 
      if (statsRef.current.activeElement !== 'NONE') {
         setBgmTheme(statsRef.current.activeElement);
      }
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; 
                ctx.drawImage(img, srcX, 0, 64, 64, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
                return;
            }
        }
        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };

    xpGemsRef.current.forEach(g => { 
        if (g.type === 'SNACK') {
            const img = spritesRef.current['SNACK'];
            if (img && img.complete) {
                ctx.drawImage(img, g.x - 12, g.y - 12, 24, 24);
            } else {
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill();
            }
        } else {
            const img = spritesRef.current['XP'];
            if (img && img.complete) {
                ctx.drawImage(img, g.x - 10, g.y - 10, 20, 20);
            } else {
                ctx.fillStyle = '#60a5fa'; ctx.beginPath(); ctx.arc(g.x, g.y, 8, 0, Math.PI*2); ctx.fill(); 
            }
        }
    });

    // === OPTIMIZED STORM DRAWING ===
    // Use for loop instead of filter to avoid array allocation
    for (let i = stormEffectsRef.current.length - 1; i >= 0; i--) {
        const s = stormEffectsRef.current[i];
        if (s.life <= 0) {
            // Fast remove
            const last = stormEffectsRef.current[stormEffectsRef.current.length - 1];
            stormEffectsRef.current[i] = last;
            stormEffectsRef.current.pop();
            continue;
        }

        ctx.save();
        ctx.translate(s.x, s.y);
        const opacity = s.life / s.maxLife;
        ctx.rotate(s.angle);

        ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
        ctx.lineWidth = 4;

        ctx.beginPath();
        ctx.arc(0, 0, s.radius * 0.3, 0, Math.PI * 2);
        ctx.stroke();

        ctx.beginPath();
        ctx.arc(0, 0, s.radius * 0.7, 0, Math.PI * 1.5);
        ctx.stroke();

        ctx.beginPath();
        ctx.arc(0, 0, s.radius, 1, Math.PI * 1.8);
        ctx.stroke();

        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.beginPath(); ctx.arc(0, 0, 15, 0, Math.PI * 2); ctx.fill();

        ctx.restore();
        s.life--;
    }

    enemiesRef.current.forEach(drawEnt);

    if (playerInvulnTimerRef.current > 0) {
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) ctx.globalAlpha = 0.4;
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; 

    projectilesRef.current.forEach(p => { 
        let spriteKey = 'PROJ_NORMAL';
        if (p.element === 'FIRE') spriteKey = 'PROJ_FIRE';
        else if (p.element === 'ICE') spriteKey = 'PROJ_ICE';
        else if (p.element === 'LIGHTNING') spriteKey = 'PROJ_LIGHTNING';
        else if (p.element === 'WIND') spriteKey = 'PROJ_WIND';

        const img = spritesRef.current[spriteKey];
        if (img && img.complete) {
             ctx.save();
             ctx.translate(p.x, p.y);
             ctx.rotate(Math.atan2(p.vy, p.vx));
             ctx.drawImage(img, -p.width/2, -p.height/2, p.width, p.height);
             ctx.restore();
        } else {
            ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); 
            ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill(); 
        }
    });

    // === OPTIMIZED LIGHTNING DRAWING ===
    // Use for loop logic for drawing and removal without allocations
    if (lightningChainsRef.current.length > 0) {
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        let hasActive = false;

        // Check if any chains are active before drawing setup
        if (lightningChainsRef.current.length > 0) {
            // Pass 1: Outer Glow
            ctx.beginPath();
            ctx.lineWidth = 6; 
            ctx.strokeStyle = 'rgba(180, 230, 255, 0.4)'; 

            for (let i = lightningChainsRef.current.length - 1; i >= 0; i--) {
                 const c = lightningChainsRef.current[i];
                 if (c.life <= 0) {
                     const last = lightningChainsRef.current[lightningChainsRef.current.length - 1];
                     lightningChainsRef.current[i] = last;
                     lightningChainsRef.current.pop();
                     continue;
                 }
                 hasActive = true;
                 for(let j=0; j<c.segments.length; j++) {
                     const seg = c.segments[j];
                     ctx.moveTo(seg.x1, seg.y1);
                     ctx.lineTo(seg.x2, seg.y2);
                 }
                 c.life--;
            }
            if (hasActive) ctx.stroke();

            // Pass 2: Inner Core
            if (hasActive) {
                ctx.beginPath();
                ctx.lineWidth = 2;
                ctx.strokeStyle = '#ffffff';
                for (let i = 0; i < lightningChainsRef.current.length; i++) {
                     const c = lightningChainsRef.current[i];
                     for(let j=0; j<c.segments.length; j++) {
                         const seg = c.segments[j];
                         ctx.moveTo(seg.x1, seg.y1);
                         ctx.lineTo(seg.x2, seg.y2);
                     }
                }
                ctx.stroke();
            }
        }
    }
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-8 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* SINGLE ACTION BUTTON */}
                  <button 
                    onClick={onExit} 
                    className="w-full py-6 font-black text-2xl rounded-2xl mb-3 transition-all border-4 bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)] hover:bg-slate-700 active:scale-95"
                  >
                    RETRY
                    <span className="ml-3 text-sm text-yellow-400 animate-pulse">[ A ]</span>
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { loadBasicAssets, generateProceduralSpriteSheet, getRandomSprite } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { 
  playShootSound, 
  playHitSound, 
  playVictorySound, 
  startBGM, 
  stopBGM,
  playFireHitSound,
  playIceHitSound,
  playLightningHitSound,
  playWindHitSound,
  playErrorSound,
  playHealSound,
  playFireShootSound,
  playIceShootSound,
  playLightningShootSound,
  playWindShootSound,
  setBgmTheme
} from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const SPAWN_RATE_INITIAL = 100; 
const BASE_XP_REQUIREMENT = 10;
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// PERFORMANCE CAPS
const MAX_ENEMIES = 400;      
const MAX_XP_GEMS = 250;      
const MAX_PROJECTILES = 200;  
const MAX_LIGHTNING_CHAINS = 20; 
const MAX_STORM_EFFECTS = 8;     

// SPATIAL GRID CONFIG
const GRID_CELL_SIZE = 150; 
const GRID_COLS = Math.ceil(GAME_WIDTH / GRID_CELL_SIZE);
const GRID_ROWS = Math.ceil(GAME_HEIGHT / GRID_CELL_SIZE);

// New Lightning Structures
interface LightningSegment {
    x1: number; y1: number;
    x2: number; y2: number;
}

interface LightningChain {
    segments: LightningSegment[];
    life: number;
    maxLife: number;
    colorOuter: string;
    colorInner: string;
}

interface StormEffect {
    x: number; y: number; life: number; maxLife: number; angle: number; radius: number;
}

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', x: GAME_WIDTH / 2, y: GAME_HEIGHT / 2, width: 64, height: 64, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10,
    direction: 'DOWN', animFrame: 0, isMoving: false
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, 
    attackSpeed: 15, 
    projectileSpeed: 3, 
    pickupRange: 120, projectileCount: 1, level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT,
    activeElement: 'NONE',
    fireLevel: 0, burnDamage: 1,
    iceLevel: 0, freezeDuration: 180, 
    lightningLevel: 0, chainCount: 3,
    windLevel: 0, windRadius: 75 
  });

  // ACTIVE ENTITY LISTS
  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const lightningChainsRef = useRef<LightningChain[]>([]);
  const stormEffectsRef = useRef<StormEffect[]>([]);

  // OBJECT POOLS
  const enemyPoolRef = useRef<Entity[]>([]);
  const projectilePoolRef = useRef<Entity[]>([]);
  const gemPoolRef = useRef<Entity[]>([]);

  // SPATIAL GRID REFS
  const spatialGridRef = useRef<number[][][]>([]);

  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});

  const playerInvulnTimerRef = useRef(0);

  const gamepadButtonRef = useRef<{ button0: boolean; button1: boolean; left: boolean; right: boolean; up: boolean; down: boolean }>({ 
      button0: false, button1: false, left: false, right: false, up: false, down: false
  });

  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});
  const spriteSheetRef = useRef<HTMLImageElement | null>(null);
  const areResourcesLoadedRef = useRef(false);
  const [areResourcesLoaded, setAreResourcesLoaded] = useState(false);
  const remainingWordsRef = useRef<WordData[]>([]);
  const bossSpawnedRef = useRef(false);
  const killCountsRef = useRef({ mobs: 0, elites: 0, bosses: 0 });

  const quizWordRef = useRef<WordData | null>(null);
  const showUpgradesRef = useRef<UpgradeOption[] | null>(null);

  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameResult, setGameResult] = useState<'PLAYING' | 'DEFEAT' | 'VICTORY'>('PLAYING');
  const gameResultRef = useRef(gameResult);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(1); 

  // Sync Refs
  useEffect(() => { quizWordRef.current = quizWord; }, [quizWord]);
  useEffect(() => { showUpgradesRef.current = showUpgrades; }, [showUpgrades]);
  useEffect(() => { gameResultRef.current = gameResult; }, [gameResult]);

  // INITIALIZE SPATIAL GRID
  useEffect(() => {
    spatialGridRef.current = Array(GRID_COLS).fill(null).map(() => 
        Array(GRID_ROWS).fill(null).map(() => [])
    );
  }, []);

  // --- POOLING HELPERS ---
  const recycleEntity = (activeList: Entity[], pool: Entity[], index: number) => {
      const ent = activeList[index];
      ent.vx = 0; ent.vy = 0;
      ent.freezeTimer = 0; ent.burnTimer = 0;
      pool.push(ent);

      const last = activeList[activeList.length - 1];
      activeList[index] = last;
      activeList.pop();
  };

  const spawnFromPool = (pool: Entity[], fallback: Entity): Entity => {
      if (pool.length > 0) {
          const ent = pool.pop()!;
          return Object.assign(ent, fallback);
      }
      return fallback;
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen().catch(() => {});
    }
  };

  useEffect(() => {
    startBGM(); 
    remainingWordsRef.current = [...words].sort(() => Math.random() - 0.5);
    const sheetDataUrl = generateProceduralSpriteSheet();
    const sheet = new Image();
    sheet.src = sheetDataUrl;
    sheet.onload = () => { spriteSheetRef.current = sheet; areResourcesLoadedRef.current = true; setAreResourcesLoaded(true); };
    loadBasicAssets((k, u) => { const img = new Image(); img.src = u; spritesRef.current[k] = img; });
    return () => { stopBGM(); cancelAnimationFrame(animationFrameId.current); };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => { window.removeEventListener('keydown', handleKeyDown); window.removeEventListener('keyup', handleKeyUp); };
  }, []);

  useEffect(() => {
    if (!areResourcesLoaded) return;
    const loop = () => {
        if (!areResourcesLoadedRef.current) return;
        draw();
        update();
        animationFrameId.current = requestAnimationFrame(loop);
    };
    animationFrameId.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [areResourcesLoaded, upgradeFocusedIndex]); 

  // --- LIGHTNING GENERATOR ---
  const createLightningBolt = (x1: number, y1: number, x2: number, y2: number): LightningSegment[] => {
      const segments: LightningSegment[] = [];
      // Optimization: No Sqrt here, just approx dist check? 
      // Need dist for steps. Hypotenuse is needed for visual quality.
      const dist = Math.hypot(x2 - x1, y2 - y1);
      const steps = Math.max(3, Math.floor(dist / 50)); 

      let prevX = x1;
      let prevY = y1;

      for (let i = 1; i <= steps; i++) {
          const t = i / steps;
          let currX = x1 + (x2 - x1) * t;
          let currY = y1 + (y2 - y1) * t;

          if (i !== steps) {
              const jitter = 25; 
              currX += (Math.random() - 0.5) * jitter;
              currY += (Math.random() - 0.5) * jitter;
          }

          segments.push({
              x1: prevX, y1: prevY,
              x2: currX, y2: currY,
          });
          prevX = currX;
          prevY = currY;
      }
      return segments;
  };

  const update = () => {
    if (gameResultRef.current !== 'PLAYING') {
        if (!isPausedRef.current) isPausedRef.current = true;
        const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
        if (gp) {
            const btnA = gp.buttons[0]?.pressed; 
            if (btnA && !gamepadButtonRef.current.button0) onExit();
            gamepadButtonRef.current.button0 = btnA;
        }
        return; 
    }

    if (quizWordRef.current || showUpgradesRef.current) {
        if (!isPausedRef.current) isPausedRef.current = true;
        if (showUpgradesRef.current) handleUpgradeGamepad();
        return;
    }

    if (isPausedRef.current) isPausedRef.current = false;

    // POOL CLEANUP
    if (frameCountRef.current % 300 === 0) {
        if (enemyPoolRef.current.length > 50) enemyPoolRef.current.length = 50;
        if (projectilePoolRef.current.length > 50) projectilePoolRef.current.length = 50;
    }

    while (xpGemsRef.current.length > MAX_XP_GEMS) {
         recycleEntity(xpGemsRef.current, gemPoolRef.current, 0);
    }

    if (playerInvulnTimerRef.current > 0) playerInvulnTimerRef.current--;

    const player = playerRef.current;
    const stats = statsRef.current;
    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // PLAYER MOVEMENT
    let dx = 0; let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        if (Math.abs(gp.axes[0]) > 0.2) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > 0.2) dy += gp.axes[1];
        if (gp.buttons[1]?.pressed && !gamepadButtonRef.current.button1) toggleFullscreen();
        gamepadButtonRef.current.button1 = gp.buttons[1]?.pressed;
    }

    if (dx !== 0 || dy !== 0) {
        player.isMoving = true;
        player.direction = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'RIGHT' : 'LEFT') : (dy > 0 ? 'DOWN' : 'UP');
        // Simple normalization without Sqrt for movement logic is hard, keep Sqrt for player only (1 entity)
        const length = Math.hypot(dx, dy); 
        const factor = length > 1 ? 1 / length : 1;
        player.x += dx * factor * stats.speed;
        player.y += dy * factor * stats.speed;
    } else { player.isMoving = false; }

    player.x = Math.max(32, Math.min(GAME_WIDTH - 32, player.x));
    player.y = Math.max(32, Math.min(GAME_HEIGHT - 32, player.y));

    // ANIMATION TICK
    const now = performance.now();
    if (!player.lastAnimTime || now - player.lastAnimTime > 200) {
        player.animFrame = (player.animFrame || 0) + 1;
        player.lastAnimTime = now;
    }

    // --- CLEAR SPATIAL GRID ---
    for (let c = 0; c < GRID_COLS; c++) {
        for (let r = 0; r < GRID_ROWS; r++) {
            spatialGridRef.current[c][r].length = 0; 
        }
    }

    spawnEnemies();

    // --- ENEMY LOOP ---
    for (let i = enemiesRef.current.length - 1; i >= 0; i--) {
        const e = enemiesRef.current[i];

        const angle = Math.atan2(player.y - e.y, player.x - e.x);
        let speed = e.type === 'BOSS' ? 1.2 : (e.type.includes('ELITE') ? 2.0 : 1.5);
        if (e.freezeTimer && e.freezeTimer > 0) { speed *= 0.5; e.freezeTimer--; }

        if (e.burnTimer && e.burnTimer > 0) { 
            e.burnTimer--; 
            if (frameCountRef.current % 30 === 0 && e.burnDamageRef) e.hp -= e.burnDamageRef; 
        }

        e.x += Math.cos(angle) * speed; 
        e.y += Math.sin(angle) * speed;

        // REGISTER TO GRID (Optimization: Math.floor is faster than parseInt)
        const gx = Math.floor(e.x / GRID_CELL_SIZE);
        const gy = Math.floor(e.y / GRID_CELL_SIZE);
        if (gx >= 0 && gx < GRID_COLS && gy >= 0 && gy < GRID_ROWS) {
            spatialGridRef.current[gx][gy].push(i);
        }

        // PLAYER COLLISION (Squared Distance)
        if (Math.abs(player.x - e.x) < 50 && Math.abs(player.y - e.y) < 50) {
            const hitDistSq = (player.width/2 + e.width/2)**2;
            const distSq = (player.x - e.x)**2 + (player.y - e.y)**2;
            if (distSq < hitDistSq) {
                takeDamage(e.damage);
            }
        }

        if (e.hp <= 0) {
            handleEnemyDeath(e);
            recycleEntity(enemiesRef.current, enemyPoolRef.current, i);
        }
    }

    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    // AUDIO THROTTLING FLAGS
    // Prevent 50 sounds playing in one frame if a shotgun blast hits a crowd
    const playedSoundsThisFrame = {
        NORMAL: false, FIRE: false, ICE: false, LIGHTNING: false, WIND: false
    };

    // --- PROJECTILE LOOP ---
    for (let i = projectilesRef.current.length - 1; i >= 0; i--) {
        const p = projectilesRef.current[i];
        p.x += p.vx; 
        p.y += p.vy;

        let hit = false;

        if (p.type === 'PROJECTILE') {
            const pcx = Math.floor(p.x / GRID_CELL_SIZE);
            const pcy = Math.floor(p.y / GRID_CELL_SIZE);

            // Search Neighbors
            neighborLoop:
            for (let ox = -1; ox <= 1; ox++) {
                for (let oy = -1; oy <= 1; oy++) {
                    const cx = pcx + ox;
                    const cy = pcy + oy;

                    if (cx >= 0 && cx < GRID_COLS && cy >= 0 && cy < GRID_ROWS) {
                        const cellEnemies = spatialGridRef.current[cx][cy];
                        for (let k = 0; k < cellEnemies.length; k++) {
                            const enemyIdx = cellEnemies[k];
                            const enemy = enemiesRef.current[enemyIdx];

                            if (!enemy || enemy.hp <= 0) continue; 

                            const dx = p.x - enemy.x;
                            const dy = p.y - enemy.y;

                            if (Math.abs(dx) < 40 && Math.abs(dy) < 40) { 
                                const hitRadiusSq = (enemy.width/2 + 10)**2;
                                if (dx*dx + dy*dy < hitRadiusSq) {
                                    // Apply Hit
                                    applyHitEffect(enemy, p, playedSoundsThisFrame);
                                    hit = true; 
                                    break neighborLoop; 
                                }
                            }
                        }
                    }
                }
            }
        }

        if (hit || p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT) {
            recycleEntity(projectilesRef.current, projectilePoolRef.current, i);
        }
    }

    // --- STORM LOGIC ---
    if (stormEffectsRef.current.length > 0) {
        for (let i = 0; i < stormEffectsRef.current.length; i++) {
            const storm = stormEffectsRef.current[i];
            storm.angle += 0.2;
            const stormRadSq = storm.radius**2;

            for (let j = 0; j < enemiesRef.current.length; j++) {
                const e = enemiesRef.current[j];
                const dx = storm.x - e.x;
                const dy = storm.y - e.y;
                if (Math.abs(dx) > storm.radius || Math.abs(dy) > storm.radius) continue;

                const distSq = dx*dx + dy*dy;
                if (distSq < stormRadSq && distSq > 225) { 
                     // Only use Sqrt here where physics accuracy matters for suction
                     const dist = Math.sqrt(distSq);
                     const factor = 3.5 / dist; 
                     e.x += dx * factor; e.y += dy * factor;
                }
            }
        }
    }

    // --- GEM LOOP ---
    for (let i = xpGemsRef.current.length - 1; i >= 0; i--) {
        const gem = xpGemsRef.current[i];
        const dx = player.x - gem.x;
        const dy = player.y - gem.y;

        if (Math.abs(dx) < stats.pickupRange && Math.abs(dy) < stats.pickupRange) {
             const distSq = dx*dx + dy*dy;
             if (distSq < stats.pickupRange**2) {
                 gem.x += dx * 0.15;
                 gem.y += dy * 0.15;

                 if (distSq < 900) { 
                     if (gem.type === 'SNACK') healPlayer(10);
                     else gainXp(1);
                     recycleEntity(xpGemsRef.current, gemPoolRef.current, i);
                 }
             }
        }
    }

    // THROTTLE UI UPDATES (Optimization: Only update React state every 15 frames/250ms)
    // React reconciliation is the #1 cause of stutter in canvas games
    if (frameCountRef.current % 15 === 0) setUiStats({...statsRef.current});
  };

  const handleUpgradeGamepad = () => {
    const gp = navigator.getGamepads ? navigator.getGamepads()[0] : null;
    if (gp) {
        const axisX = gp.axes[0];
        const btnA = gp.buttons[0]?.pressed; 
        const btnLeft = gp.buttons[14]?.pressed || axisX < -0.5;
        const btnRight = gp.buttons[15]?.pressed || axisX > 0.5;

        if (btnLeft && !gamepadButtonRef.current.left) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        }
        if (btnRight && !gamepadButtonRef.current.right) {
            setUpgradeFocusedIndex(prev => Math.min((showUpgradesRef.current?.length || 1) - 1, prev + 1));
        }
        if (btnA && !gamepadButtonRef.current.button0) {
                if (showUpgradesRef.current && showUpgradesRef.current[upgradeFocusedIndex]) {
                    applyUpgrade(showUpgradesRef.current[upgradeFocusedIndex]);
                }
        }
        gamepadButtonRef.current.left = btnLeft;
        gamepadButtonRef.current.right = btnRight;
        gamepadButtonRef.current.button0 = btnA;
    }
  };

  const applyHitEffect = (enemy: Entity, p: Entity, soundsPlayed: Record<string, boolean>) => {
      const stats = statsRef.current;
      enemy.hp -= p.damage;

      // AUDIO THROTTLING
      const playThrottled = (type: string, fn: () => void) => {
          if (!soundsPlayed[type]) {
              fn();
              soundsPlayed[type] = true;
          }
      };

      if (p.element === 'ICE') { 
          enemy.freezeTimer = stats.freezeDuration; 
          playThrottled('ICE', playIceHitSound);
      }
      else if (p.element === 'FIRE') { 
          enemy.burnTimer = 300; 
          enemy.burnDamageRef = stats.burnDamage;
          playThrottled('FIRE', playFireHitSound);
      }
      else if (p.element === 'LIGHTNING') {
          if (lightningChainsRef.current.length < MAX_LIGHTNING_CHAINS) {
              // Chain logic
              let chains = 0;
              for (let k=0; k < enemiesRef.current.length; k++) {
                  if (chains >= stats.chainCount) break;
                  const n = enemiesRef.current[k];
                  if (n !== enemy && Math.abs(n.x - enemy.x) < 400 && Math.abs(n.y - enemy.y) < 400) {
                      n.hp -= Math.ceil(p.damage/2);
                      const segments = createLightningBolt(enemy.x, enemy.y, n.x, n.y);
                      lightningChainsRef.current.push({ 
                          segments, life: 20, maxLife: 20,
                          colorOuter: 'rgba(180, 230, 255, 0.4)', colorInner: '#ffffff'
                      });
                      chains++;
                  }
              }
          }
          playThrottled('LIGHTNING', playLightningHitSound);
      } 
      else if (p.element === 'WIND') {
          if (stormEffectsRef.current.length < MAX_STORM_EFFECTS) {
              stormEffectsRef.current.push({
                  x: enemy.x, y: enemy.y, life: 180, maxLife: 180, 
                  angle: Math.random() * Math.PI * 2, radius: stats.windRadius
              });
          }
          playThrottled('WIND', playWindHitSound);
      } else { 
          playThrottled('NORMAL', playHitSound);
      }
  };

  const handleEnemyDeath = (e: Entity) => {
      if (e.type === 'BOSS') { setGameResult('VICTORY'); playVictorySound(); isPausedRef.current = true; }
      killCountsRef.current[e.type === 'BOSS' ? 'bosses' : (e.type.includes('ELITE') ? 'elites' : 'mobs')]++;

      const dropCount = e.type === 'BOSS' ? 50 : (e.type.includes('ELITE') ? 5 : 1);
      for (let k = 0; k < dropCount; k++) {
          if (xpGemsRef.current.length >= MAX_XP_GEMS) break; 
          const isSnack = Math.random() < 0.05; 

          const drop = spawnFromPool(gemPoolRef.current, {
              id: '', 
              x: e.x + (Math.random() * 30 - 15),
              y: e.y + (Math.random() * 30 - 15),
              width: 24, height: 24,
              type: isSnack ? 'SNACK' : 'XP',
              vx:0, vy:0, hp:1, maxHp:1, damage:0
          });
          xpGemsRef.current.push(drop);
      }
  };

  const healPlayer = (amount: number) => {
      playHealSound();
      statsRef.current.hp = Math.min(statsRef.current.maxHp, statsRef.current.hp + amount);
      setUiStats({...statsRef.current}); 
  };

  const spawnEnemies = () => {
      if (enemiesRef.current.length >= MAX_ENEMIES) return;

      const time = gameTimeRef.current;
      const level = statsRef.current.level;
      let spawnRate = Math.max(3, Math.floor(SPAWN_RATE_INITIAL / Math.pow(1.5, level - 1)));

      if (remainingWordsRef.current.length === 0 && !bossSpawnedRef.current && !quizWord) {
          spawnEntity('BOSS'); bossSpawnedRef.current = true; return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = (statsRef.current.level > 1 && time > 30 && r > 0.9) ? 'ELITE' : 'MOB';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      const fallback: Entity = {
          id: Math.random().toString(), x, y, vx: 0, vy: 0, 
          type: category as any, width: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          height: category === 'BOSS' ? 250 : (category === 'ELITE' ? 90 : 50),
          hp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          maxHp: category === 'BOSS' ? 1000 : (category === 'ELITE' ? 40 : 2),
          damage: category === 'BOSS' ? 10 : (category === 'ELITE' ? 5 : 1),
          spriteSource: getRandomSprite(category)
      };

      const ent = spawnFromPool(enemyPoolRef.current, fallback);
      // Ensure key props are reset if recycled
      ent.x = x; ent.y = y; ent.hp = ent.maxHp; 
      ent.width = fallback.width; ent.height = fallback.height;
      ent.type = category as any;
      ent.spriteSource = fallback.spriteSource; 

      enemiesRef.current.push(ent);
  };

  const fireBullet = () => {
    const s = statsRef.current;

    // SOUND THROTTLING FOR SHOOTING
    // No need to pass map here, just simple logic
    const p = playerRef.current;
    let el: any = s.activeElement; 
    if (el === 'NONE') el = 'NORMAL';

    if (s.activeElement === 'FIRE') playFireShootSound();
    else if (s.activeElement === 'ICE') playIceShootSound();
    else if (s.activeElement === 'LIGHTNING') playLightningShootSound();
    else if (s.activeElement === 'WIND') playWindShootSound();
    else playShootSound();

    for (let i = 0; i < s.projectileCount; i++) {
        if (projectilesRef.current.length >= MAX_PROJECTILES) break;
        const a = Math.random() * Math.PI * 2;

        const fallback: Entity = {
            id: Math.random().toString(), x: p.x, y: p.y, width: 24, height: 24, type: 'PROJECTILE',
            vx: Math.cos(a) * s.projectileSpeed, vy: Math.sin(a) * s.projectileSpeed,
            hp: 1, maxHp: 1, damage: s.damage, element: el
        };
        const bullet = spawnFromPool(projectilePoolRef.current, fallback);
        bullet.x = p.x; bullet.y = p.y;
        bullet.vx = Math.cos(a) * s.projectileSpeed;
        bullet.vy = Math.sin(a) * s.projectileSpeed;
        bullet.element = el;
        bullet.damage = s.damage;

        projectilesRef.current.push(bullet);
    }
  };

  const takeDamage = (a: number) => { 
      if (playerInvulnTimerRef.current > 0) return;
      statsRef.current.hp -= a; 
      playErrorSound(); 
      playerInvulnTimerRef.current = 30;
      setUiStats({...statsRef.current});
      if (statsRef.current.hp <= 0) { 
          setGameResult('DEFEAT'); 
          isPausedRef.current = true; 
      } 
  };

  const gainXp = (a: number) => { statsRef.current.xp += a; if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp(); };
  const triggerLevelUp = () => {
      isPausedRef.current = true; keysRef.current = {};
      const next = remainingWordsRef.current.pop();
      if (next) setQuizWord(next); else showUpgradeMenu();
  };

  const showUpgradeMenu = () => {
      isPausedRef.current = true;
      const s = statsRef.current;

      const potentialUpgrades: UpgradeOption[] = [];
      potentialUpgrades.push({ 
          id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪', weight: 20,
          apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
      });
      potentialUpgrades.push({ 
          id: 'spd_up', name: '疾风步', description: '移动速度 +20%', icon: '👟', weight: 20,
          apply: (s) => ({ ...s, speed: s.speed * 1.2 }) 
      });
      potentialUpgrades.push({ 
          id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +20%', icon: '🔫', weight: 20,
          apply: (s) => ({ ...s, attackSpeed: Math.max(5, Math.floor(s.attackSpeed * 0.8)) }) 
      });
      potentialUpgrades.push({
          id: 'pickup_range', name: '致命磁场', description: '拾取范围 +50%', icon: '🧲', weight: 20,
          apply: (s) => ({ ...s, pickupRange: Math.ceil(s.pickupRange * 1.5) })
      });
      potentialUpgrades.push({ 
          id: 'multishot', name: '多重射击', description: '额外子弹 +1', icon: '✨', weight: 10,
          apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
      });

      const isFireActive = s.activeElement === 'FIRE';
      const isIceActive = s.activeElement === 'ICE';
      const isLightningActive = s.activeElement === 'LIGHTNING';
      const isWindActive = s.activeElement === 'WIND';
      const hasAnyElement = isFireActive || isIceActive || isLightningActive || isWindActive;

      if (!hasAnyElement || isFireActive) {
          potentialUpgrades.push({ 
              id: 'fire_shot', 
              name: isFireActive ? `火焰强化 Lv.${s.fireLevel + 1}` : '火焰弹', 
              description: isFireActive ? `燃烧伤害翻倍 (${s.burnDamage} -> ${s.burnDamage*2})` : '攻击附带燃烧效果', 
              icon: '🔥', 
              weight: isFireActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'FIRE', fireLevel: s.fireLevel + 1, burnDamage: s.fireLevel === 0 ? 1 : s.burnDamage * 2 }) 
          });
      }
      if (!hasAnyElement || isIceActive) {
          potentialUpgrades.push({ 
              id: 'ice_shot', 
              name: isIceActive ? `冰冻强化 Lv.${s.iceLevel + 1}` : '冰冻弹', 
              description: isIceActive ? `冻结时间 +3秒 (${Math.floor(s.freezeDuration/60)}s -> ${Math.floor((s.freezeDuration+180)/60)}s)` : '攻击减速敌人', 
              icon: '❄️', 
              weight: isIceActive ? 30 : 10,
              apply: (s) => ({ ...s, activeElement: 'ICE', iceLevel: s.iceLevel + 1, freezeDuration: s.freezeDuration + 180 }) 
          });
      }
      if (!hasAnyElement || isLightningActive) {
          potentialUpgrades.push({ 
              id: 'lightning_shot', 
              name: isLightningActive ? `闪电强化 Lv.${s.lightningLevel + 1}` : '闪电弹', 
              description: isLightningActive ? `弹射数量翻倍 (${s.chainCount} -> ${s.chainCount*2})` : '攻击弹射敌人', 
              icon: '⚡', 
              weight: isLightningActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'LIGHTNING', lightningLevel: s.lightningLevel + 1, chainCount: s.lightningLevel === 0 ? 3 : s.chainCount * 2 }) 
          });
      }
      if (!hasAnyElement || isWindActive) {
          potentialUpgrades.push({ 
              id: 'wind_shot', 
              name: isWindActive ? `风暴强化 Lv.${s.windLevel + 1}` : '风暴弹', 
              description: isWindActive ? `风暴范围扩大` : '攻击聚拢敌人', 
              icon: '🌀', 
              weight: isWindActive ? 30 : 5,
              apply: (s) => ({ ...s, activeElement: 'WIND', windLevel: s.windLevel + 1, windRadius: s.windLevel === 0 ? 75 : Math.floor(s.windRadius * 1.5) }) 
          });
      }

      const selectedOpts: UpgradeOption[] = [];
      const needed = 3;

      for (let i = 0; i < needed; i++) {
          if (potentialUpgrades.length === 0) break;
          const totalWeight = potentialUpgrades.reduce((sum, item) => sum + (item.weight || 0), 0);
          let random = Math.random() * totalWeight;

          for (let j = 0; j < potentialUpgrades.length; j++) {
              random -= (potentialUpgrades[j].weight || 0);
              if (random <= 0) {
                  selectedOpts.push(potentialUpgrades[j]);
                  potentialUpgrades.splice(j, 1); 
                  break;
              }
          }
      }
      setShowUpgrades(selectedOpts); 
      setUpgradeFocusedIndex(1); 
  };

  const handleQuizResult = (c: boolean) => { setQuizWord(null); if (c) showUpgradeMenu(); else { statsRef.current.xp = 0; isPausedRef.current = false; } };
  const applyUpgrade = (o: UpgradeOption) => { 
      statsRef.current = o.apply(statsRef.current); 
      statsRef.current.level++; 
      statsRef.current.damage += 1; 
      statsRef.current.xp = 0; 
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.6); 
      if (statsRef.current.activeElement !== 'NONE') {
         setBgmTheme(statsRef.current.activeElement);
      }
      setShowUpgrades(null); 
      isPausedRef.current = false; 
  };

  const draw = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);
    ctx.strokeStyle = '#1e293b'; ctx.lineWidth = 1;
    for (let x=0; x<GAME_WIDTH; x+=100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke(); }
    for (let y=0; y<GAME_HEIGHT; y+=100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke(); }

    const drawEnt = (e: Entity) => {
        // OPTIMIZATION: Use Bitwise OR to force integer coordinates for faster rendering
        const drawX = (e.x - e.width/2) | 0;
        const drawY = (e.y - e.height/2) | 0;

        if (e.type === 'HERO') {
            let key = 'HERO_IDLE';
            if (e.isMoving) {
                if (e.direction === 'UP') key = 'HERO_UP';
                else if (e.direction === 'DOWN') key = 'HERO_DOWN';
                else if (e.direction === 'LEFT') key = 'HERO_LEFT';
                else if (e.direction === 'RIGHT') key = 'HERO_RIGHT';
            }
            const img = spritesRef.current[key];
            if (img && img.complete) {
                ctx.imageSmoothingEnabled = false;
                const frameIndex = (e.animFrame || 0) % 2;
                const srcX = frameIndex * 64; 
                ctx.drawImage(img, srcX, 0, 64, 64, drawX, drawY, e.width, e.height);
                return;
            }
        }
        if (e.spriteSource && spriteSheetRef.current?.complete) {
            ctx.imageSmoothingEnabled = false;
            ctx.drawImage(spriteSheetRef.current, e.spriteSource.x, e.spriteSource.y, e.spriteSource.w, e.spriteSource.h, drawX, drawY, e.width, e.height);
        } else {
            ctx.fillStyle = e.type === 'HERO' ? '#6366f1' : '#ef4444';
            ctx.fillRect(drawX, drawY, e.width, e.height);
        }
    };

    xpGemsRef.current.forEach(g => { 
        // Integer coords
        const gx = g.x | 0;
        const gy = g.y | 0;

        if (g.type === 'SNACK') {
            const img = spritesRef.current['SNACK'];
            if (img && img.complete) {
                ctx.drawImage(img, gx - 12, gy - 12, 24, 24);
            } else {
                ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(gx, gy, 8, 0, Math.PI*2); ctx.fill();
            }
        } else {
            const img = spritesRef.current['XP'];
            if (img && img.complete) {
                ctx.drawImage(img, gx - 10, gy - 10, 20, 20);
            } else {
                ctx.fillStyle = '#60a5fa'; ctx.beginPath(); ctx.arc(gx, gy, 8, 0, Math.PI*2); ctx.fill(); 
            }
        }
    });

    // === OPTIMIZED STORM DRAWING ===
    for (let i = stormEffectsRef.current.length - 1; i >= 0; i--) {
        const s = stormEffectsRef.current[i];
        if (s.life <= 0) {
            const last = stormEffectsRef.current[stormEffectsRef.current.length - 1];
            stormEffectsRef.current[i] = last;
            stormEffectsRef.current.pop();
            continue;
        }

        ctx.save();
        ctx.translate(s.x | 0, s.y | 0);
        const opacity = s.life / s.maxLife;
        ctx.rotate(s.angle);

        ctx.strokeStyle = `rgba(200, 240, 255, ${opacity * 0.4})`;
        ctx.lineWidth = 4;

        ctx.beginPath(); ctx.arc(0, 0, s.radius * 0.3, 0, Math.PI * 2); ctx.stroke();
        ctx.beginPath(); ctx.arc(0, 0, s.radius * 0.7, 0, Math.PI * 1.5); ctx.stroke();
        ctx.beginPath(); ctx.arc(0, 0, s.radius, 1, Math.PI * 1.8); ctx.stroke();

        ctx.fillStyle = `rgba(255, 255, 255, ${opacity * 0.2})`;
        ctx.beginPath(); ctx.arc(0, 0, 15, 0, Math.PI * 2); ctx.fill();

        ctx.restore();
        s.life--;
    }

    enemiesRef.current.forEach(drawEnt);

    if (playerInvulnTimerRef.current > 0) {
        if (Math.floor(frameCountRef.current / 4) % 2 === 0) ctx.globalAlpha = 0.4;
    }
    drawEnt(playerRef.current);
    ctx.globalAlpha = 1.0; 

    projectilesRef.current.forEach(p => { 
        let spriteKey = 'PROJ_NORMAL';
        if (p.element === 'FIRE') spriteKey = 'PROJ_FIRE';
        else if (p.element === 'ICE') spriteKey = 'PROJ_ICE';
        else if (p.element === 'LIGHTNING') spriteKey = 'PROJ_LIGHTNING';
        else if (p.element === 'WIND') spriteKey = 'PROJ_WIND';

        const img = spritesRef.current[spriteKey];
        if (img && img.complete) {
             ctx.save();
             ctx.translate(p.x | 0, p.y | 0);
             ctx.rotate(Math.atan2(p.vy, p.vx));
             ctx.drawImage(img, -p.width/2, -p.height/2, p.width, p.height);
             ctx.restore();
        } else {
            ctx.fillStyle = p.element === 'FIRE' ? '#ef4444' : (p.element === 'ICE' ? '#fff' : (p.element === 'LIGHTNING' ? '#3b82f6' : '#94a3b8')); 
            ctx.beginPath(); ctx.arc(p.x | 0, p.y | 0, p.width/2, 0, Math.PI*2); ctx.fill(); 
        }
    });

    // === OPTIMIZED LIGHTNING DRAWING ===
    if (lightningChainsRef.current.length > 0) {
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        let hasActive = false;

        if (lightningChainsRef.current.length > 0) {
            ctx.beginPath();
            ctx.lineWidth = 6; 
            ctx.strokeStyle = 'rgba(180, 230, 255, 0.4)'; 

            for (let i = lightningChainsRef.current.length - 1; i >= 0; i--) {
                 const c = lightningChainsRef.current[i];
                 if (c.life <= 0) {
                     const last = lightningChainsRef.current[lightningChainsRef.current.length - 1];
                     lightningChainsRef.current[i] = last;
                     lightningChainsRef.current.pop();
                     continue;
                 }
                 hasActive = true;
                 for(let j=0; j<c.segments.length; j++) {
                     const seg = c.segments[j];
                     ctx.moveTo(seg.x1 | 0, seg.y1 | 0);
                     ctx.lineTo(seg.x2 | 0, seg.y2 | 0);
                 }
                 c.life--;
            }
            if (hasActive) ctx.stroke();

            if (hasActive) {
                ctx.beginPath();
                ctx.lineWidth = 2;
                ctx.strokeStyle = '#ffffff';
                for (let i = 0; i < lightningChainsRef.current.length; i++) {
                     const c = lightningChainsRef.current[i];
                     for(let j=0; j<c.segments.length; j++) {
                         const seg = c.segments[j];
                         ctx.moveTo(seg.x1 | 0, seg.y1 | 0);
                         ctx.lineTo(seg.x2 | 0, seg.y2 | 0);
                     }
                }
                ctx.stroke();
            }
        }
    }
  };

  return (
    <div ref={containerRef} className="fixed inset-0 w-full h-full bg-slate-950 flex items-center justify-center overflow-hidden cursor-none">
      <div className="relative w-full h-full">
          <canvas 
            ref={canvasRef} width={GAME_WIDTH} height={GAME_HEIGHT}
            className="bg-slate-900 shadow-2xl"
          />

          {/* HUD (Top Left) */}
          <div className="absolute top-8 left-8 flex flex-col gap-2 pointer-events-none">
            <div className="w-96 h-10 bg-slate-800 rounded-full border-4 border-slate-600 overflow-hidden relative shadow-lg">
                 <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-lg font-black text-white drop-shadow-md">HP {Math.ceil(uiStats.hp)}</span>
            </div>
            <div className="w-96 h-6 bg-slate-800 rounded-full border-2 border-slate-600 overflow-hidden relative shadow-md">
                 <div className="h-full bg-blue-600" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
                 <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white">LVL {uiStats.level}</span>
            </div>
            <div className="flex gap-2">
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">⚔️ {uiStats.damage}</div>
                <div className="bg-slate-800/80 px-3 py-1 rounded-lg border border-slate-600 text-white text-xs font-bold">✨ {uiStats.projectileCount}</div>
            </div>
          </div>

          <div className="absolute top-8 right-8 text-xl font-mono text-white pointer-events-none">
            {Math.floor(gameTimeDisplay / 60)}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
          </div>
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
              <div className="w-full max-w-4xl text-center">
                  <h2 className="text-3xl sm:text-5xl font-black text-yellow-400 mb-8">LEVEL UP!</h2>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      {showUpgrades.map((o, index) => (
                          <div 
                              key={o.id} 
                              // Mouse is disabled via pointer-events-none
                              className={`p-6 bg-slate-800 border-4 rounded-2xl flex flex-col items-center gap-2 transition-transform duration-100 pointer-events-none
                                ${index === upgradeFocusedIndex ? 'border-yellow-400 scale-105 shadow-[0_0_30px_rgba(250,204,21,0.5)]' : 'border-slate-600 opacity-80'}
                              `}
                          >
                              <span className="text-4xl">{o.icon}</span>
                              <span className="font-bold text-white">{o.name}</span>
                              <span className="text-xs text-slate-400">{o.description}</span>
                              {index === upgradeFocusedIndex && (
                                  <div className="mt-2 text-xs text-yellow-400 font-bold animate-pulse">[ A ] SELECT</div>
                              )}
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameResult !== 'PLAYING' && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
              <div className="bg-white rounded-3xl p-8 max-w-sm w-full text-center">
                  <h1 className={`text-4xl font-black mb-8 ${gameResult === 'VICTORY' ? 'text-yellow-600' : 'text-red-600'}`}>
                      {gameResult === 'VICTORY' ? 'VICTORY!' : 'GAME OVER'}
                  </h1>

                  {/* SINGLE ACTION BUTTON */}
                  <button 
                    onClick={onExit} 
                    className="w-full py-6 font-black text-2xl rounded-2xl mb-3 transition-all border-4 bg-slate-800 text-white scale-105 border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.4)] hover:bg-slate-700 active:scale-95"
                  >
                    RETRY
                    <span className="ml-3 text-sm text-yellow-400 animate-pulse">[ A ]</span>
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

// Singleton AudioContext to avoid hitting mobile browser limits
let audioCtx: AudioContext | null = null;
let bgmInterval: any = null;
let nextNoteTime = 0;
let beatCount = 0;

// Distortion Curve Cache
let distortionCurve: Float32Array | null = null;

export type BgmTheme = 'DEFAULT' | 'FIRE' | 'ICE' | 'LIGHTNING' | 'WIND';
let currentTheme: BgmTheme = 'DEFAULT';

// UNIFIED ROCK TEMPO (132 BPM - Driving Energy)
const BPM = 132;
const THEME_TEMPOS: Record<BgmTheme, number> = {
    DEFAULT: BPM, FIRE: BPM, ICE: BPM, LIGHTNING: BPM, WIND: BPM
};

const LOOKAHEAD = 25.0; // ms
const SCHEDULE_AHEAD_TIME = 0.1; // sec

// 5 Minutes Loop Logic (approx 132BPM * 5min / 4 beats = ~165 bars)
const MAX_BARS = 164; 

const getAudioContext = () => {
  if (!audioCtx) {
    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    if (Ctx) {
      audioCtx = new Ctx();
    }
  }
  return audioCtx;
};

export const resumeAudioContext = () => {
  const ctx = getAudioContext();
  if (ctx && ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Audio resume failed", e));
  }
};

export const setBgmTheme = (theme: BgmTheme) => {
    if (currentTheme !== theme) {
        currentTheme = theme;
    }
};

// ==========================================
// AUDIO UTILS
// ==========================================

const getDistortionCurve = (amount: number = 50) => {
    if (distortionCurve) return distortionCurve;
    const k = amount;
    const n_samples = 44100;
    const curve = new Float32Array(n_samples);
    const deg = Math.PI / 180;
    for (let i = 0; i < n_samples; ++i) {
        const x = i * 2 / n_samples - 1;
        curve[i] = (3 + k) * x * 20 * deg / (Math.PI + k * Math.abs(x));
    }
    distortionCurve = curve;
    return curve;
};

// ==========================================
// ROCK INSTRUMENTS
// ==========================================

const playRockKick = (time: number, vol = 1.0) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();

    // Punchy attack
    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(40, time + 0.1);

    gain.gain.setValueAtTime(vol, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.3);

    osc.connect(gain);
    gain.connect(audioCtx.destination);
    osc.start(time); osc.stop(time + 0.3);
};

const playRockSnare = (time: number, vol = 0.8) => {
    if (!audioCtx) return;
    // 1. Tonal body
    const osc = audioCtx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(250, time);
    const oscGain = audioCtx.createGain();
    oscGain.gain.setValueAtTime(vol * 0.5, time);
    oscGain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);

    // 2. Noise snap
    const bufferSize = audioCtx.sampleRate * 0.2;
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) data[i] = (Math.random() * 2 - 1);

    const noise = audioCtx.createBufferSource();
    noise.buffer = buffer;
    const noiseFilter = audioCtx.createBiquadFilter();
    noiseFilter.type = 'highpass';
    noiseFilter.frequency.value = 1000;

    const noiseGain = audioCtx.createGain();
    noiseGain.gain.setValueAtTime(vol, time);
    noiseGain.gain.exponentialRampToValueAtTime(0.01, time + 0.2);

    osc.connect(oscGain); oscGain.connect(audioCtx.destination);
    noise.connect(noiseFilter); noiseFilter.connect(noiseGain); noiseGain.connect(audioCtx.destination);

    osc.start(time); osc.stop(time + 0.2);
    noise.start(time);
};

const playHiHat = (time: number, open = false, vol = 0.3) => {
    if (!audioCtx) return;
    const bufferSize = audioCtx.sampleRate * (open ? 0.3 : 0.05);
    const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;

    const noise = audioCtx.createBufferSource(); noise.buffer = buffer;
    const filter = audioCtx.createBiquadFilter(); 
    filter.type = 'highpass'; filter.frequency.value = 8000;

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(vol, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + (open ? 0.2 : 0.05));

    noise.connect(filter); filter.connect(gain); gain.connect(audioCtx.destination);
    noise.start(time);
};

// SIMULATED ELECTRIC GUITAR (Power Chords)
const playDistortedGuitar = (rootFreq: number, time: number, duration: number, vol = 0.3) => {
    if (!audioCtx) return;

    const masterGain = audioCtx.createGain();
    masterGain.gain.value = vol;

    // Distortion Stage
    const shaper = audioCtx.createWaveShaper();
    shaper.curve = getDistortionCurve(400); // Heavy distortion
    shaper.oversample = '4x';

    // Cabinet Simulation (Lowpass)
    const cabFilter = audioCtx.createBiquadFilter();
    cabFilter.type = 'lowpass';
    cabFilter.frequency.value = 3000;

    // Oscillators (Root + Fifth + Octave)
    const freqs = [rootFreq, rootFreq * 1.5, rootFreq * 2];

    freqs.forEach((f, i) => {
        const osc = audioCtx!.createOscillator();
        osc.type = 'sawtooth';
        osc.frequency.value = f;
        // Slight detune for thickness
        if (i === 0) osc.detune.value = -5;
        if (i === 1) osc.detune.value = 5;

        const oscGain = audioCtx!.createGain();
        oscGain.gain.setValueAtTime(0.5, time);
        // Palm mute effect: Short decay if duration is short
        const release = duration > 0.2 ? duration : 0.1;
        oscGain.gain.exponentialRampToValueAtTime(0.01, time + release);

        osc.connect(oscGain);
        oscGain.connect(shaper);
        osc.start(time);
        osc.stop(time + release);
    });

    shaper.connect(cabFilter);
    cabFilter.connect(masterGain);
    masterGain.connect(audioCtx.destination);
};

const playRockBass = (freq: number, time: number, duration: number, vol = 0.5) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    osc.type = 'sawtooth'; // Sawtooth for grit
    osc.frequency.value = freq;

    const filter = audioCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(800, time);
    filter.frequency.exponentialRampToValueAtTime(200, time + 0.1); // Pluck effect

    const gain = audioCtx.createGain();
    gain.gain.setValueAtTime(vol, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + duration);

    osc.connect(filter); filter.connect(gain); gain.connect(audioCtx.destination);
    osc.start(time); osc.stop(time + duration);
};

const playLeadSynth = (freq: number, time: number, duration: number, theme: BgmTheme) => {
    if (!audioCtx) return;
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    const filter = audioCtx.createBiquadFilter();

    // Theme-based timbre modification
    switch (theme) {
        case 'FIRE': 
            osc.type = 'sawtooth'; // Harsh
            filter.type = 'bandpass';
            filter.Q.value = 2;
            break;
        case 'ICE':
            osc.type = 'square'; // Hollow
            filter.type = 'lowpass';
            break;
        case 'LIGHTNING':
            osc.type = 'sawtooth';
            // Simple FM
            const lfo = audioCtx.createOscillator();
            lfo.frequency.value = 50;
            const lfoGain = audioCtx.createGain();
            lfoGain.gain.value = 500;
            lfo.connect(lfoGain);
            lfoGain.connect(osc.frequency);
            lfo.start(time); lfo.stop(time + duration);
            filter.type = 'highpass';
            break;
        case 'WIND':
            osc.type = 'triangle'; // Smooth
            filter.type = 'lowpass';
            break;
        default:
            osc.type = 'square'; // Classic
            filter.type = 'lowpass';
            break;
    }

    osc.frequency.setValueAtTime(freq, time);
    // Slide/Legato effect
    osc.frequency.exponentialRampToValueAtTime(freq, time + 0.05);

    filter.frequency.setValueAtTime(2000, time);

    gain.gain.setValueAtTime(0.15, time);
    gain.gain.linearRampToValueAtTime(0.1, time + duration * 0.8);
    gain.gain.linearRampToValueAtTime(0, time + duration);

    osc.connect(filter); filter.connect(gain); gain.connect(audioCtx.destination);
    osc.start(time); osc.stop(time + duration);
};

// ==========================================
// 5-MINUTE ELECTRONIC ROCK COMPOSITION
// ==========================================

// Scales (E Minor Pentatonic / Natural Minor)
const NOTE_E2 = 82.41;
const NOTE_G2 = 98.00;
const NOTE_A2 = 110.00;
const NOTE_B2 = 123.47;
const NOTE_D3 = 146.83;
const NOTE_E3 = 164.81;
const NOTE_G3 = 196.00;
const NOTE_A3 = 220.00;
const NOTE_B3 = 246.94;
const NOTE_D4 = 293.66;
const NOTE_E4 = 329.63;

const scheduler = () => {
    if (!audioCtx) return;
    const tempo = THEME_TEMPOS['DEFAULT']; // Unified Tempo
    const secondsPerStep = 60.0 / tempo / 4; // 16th note

    while (nextNoteTime < audioCtx.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleElectronicRock(beatCount, nextNoteTime, secondsPerStep);
        nextNoteTime += secondsPerStep;
        beatCount++; 
    }
};

const scheduleElectronicRock = (totalStep: number, time: number, stepDur: number) => {
    // 16 steps per bar
    const bar = Math.floor(totalStep / 16) % MAX_BARS;
    const step = totalStep % 16;

    // === SONG STRUCTURE ===
    // 0-16: Intro (Synth Arp building)
    // 16-32: Verse 1 (Bass + Drums + Light Guitar)
    // 32-48: Pre-Chorus (Rising tension)
    // 48-64: Chorus 1 (Full Power)
    // 64-80: Verse 2 (Variation)
    // 80-96: Chorus 2
    // 96-120: Bridge (Atmospheric, Breakdown)
    // 120-136: Solo (High energy lead)
    // 136-152: Final Chorus (Max intensity)
    // 152-164: Outro (Fade out)

    const isChorus = (bar >= 48 && bar < 64) || (bar >= 80 && bar < 96) || (bar >= 136 && bar < 152);
    const isBridge = (bar >= 96 && bar < 120);
    const isSolo = (bar >= 120 && bar < 136);
    const isIntro = (bar < 16);
    const isOutro = (bar >= 152);
    const isVerse = !isChorus && !isBridge && !isSolo && !isIntro && !isOutro;

    // --- DRUMS ---
    if (!isIntro && !isOutro) {
        // KICK
        if (step === 0 || step === 10) playRockKick(time);
        if (isChorus && step === 2) playRockKick(time); // More driving kick in chorus

        // SNARE
        if (step === 4 || step === 12) {
             // Heavier snare in chorus
             playRockSnare(time, isChorus ? 1.0 : 0.7);
        }

        // HI-HAT
        if (step % 2 === 0) playHiHat(time, step === 2 || step === 14, 0.2); // Open hat accents
        if (isSolo || isChorus) {
            if (step % 2 !== 0) playHiHat(time, false, 0.1); // 16th notes in intense parts
        }
    } else if (isIntro && bar > 8) {
        // Intro build up drums
        if (step % 4 === 0) playRockKick(time);
    }

    // --- BASS ---
    // Root notes progression: E - G - A - C/D
    let root = NOTE_E2;
    if (bar % 8 >= 4) root = NOTE_G2; // Change chord
    if (bar % 8 >= 6) root = NOTE_A2;

    if (!isIntro && !isOutro) {
        if (isChorus) {
             // Straight 8ths driving bass
             if (step % 2 === 0) playRockBass(root, time, stepDur * 2);
        } else if (isVerse) {
             // Funky/Rhythmic bass
             if (step === 0 || step === 3 || step === 6 || step === 10) playRockBass(root, time, stepDur);
        } else if (isBridge) {
             // Long sustained bass
             if (step === 0) playRockBass(root / 2, time, stepDur * 16);
        }
    }

    // --- GUITAR (Power Chords) ---
    if (isChorus || isSolo || (isVerse && bar % 2 === 1)) {
        // Chord progression logic
        let chordRoot = NOTE_E3;
        if (bar % 4 === 1) chordRoot = NOTE_G3;
        if (bar % 4 === 2) chordRoot = NOTE_A3;
        if (bar % 4 === 3) chordRoot = NOTE_D3; // Turnaround

        if (isChorus) {
            // Sustained chords
            if (step === 0) playDistortedGuitar(chordRoot, time, stepDur * 8);
            if (step === 8) playDistortedGuitar(chordRoot, time, stepDur * 8); // Restrum
        } else if (isVerse) {
            // Palm mutes (Chugs)
            if (step === 0 || step === 2 || step === 4) playDistortedGuitar(chordRoot, time, stepDur * 0.5, 0.2);
        }
    }

    // --- LEAD SYNTH / SOLO ---
    // Use currentTheme to color the solo
    if (isSolo || (isChorus && step % 4 === 0)) {
        // Solo Scale: E Minor Pentatonic
        const scale = [NOTE_E4, NOTE_G4, NOTE_A4, NOTE_B4, NOTE_D5, NOTE_E5];

        // Procedural melody based on bar hash to keep it consistent but pseudo-random
        const seed = (bar * 16 + step) * 9301 + 49297;
        const rnd = (seed % 233280) / 233280;

        if (step % 2 === 0 && rnd > 0.3) {
            const noteIdx = Math.floor(rnd * scale.length);
            // Higher octave for solo
            const note = scale[noteIdx] * (isSolo ? 1.5 : 1); 
            playLeadSynth(note, time, stepDur * 2, currentTheme);
        }
    }

    // --- ARPEGGIATOR (Background texture) ---
    if (isIntro || isBridge || isOutro) {
        if (step % 2 === 0) {
            const arpNotes = [NOTE_E3, NOTE_G3, NOTE_B3, NOTE_E4];
            // Up and down pattern
            const idx = (step / 2) % 4;
            playLeadSynth(arpNotes[idx], time, stepDur, 'DEFAULT');
        }
    }
};

// Helper constants for solo
const NOTE_G4 = 392.00;
const NOTE_A4 = 440.00;
const NOTE_B4 = 493.88;
const NOTE_D5 = 587.33;
const NOTE_E5 = 659.25;

export const startBGM = () => {
    resumeAudioContext();
    const ctx = getAudioContext();
    if (!ctx) return;

    if (ctx.state === 'suspended') {
        ctx.resume();
    }

    if (bgmInterval) clearInterval(bgmInterval);

    nextNoteTime = ctx.currentTime + 0.1;
    beatCount = 0; // Always start from beginning for the full 5-min journey

    bgmInterval = setInterval(scheduler, LOOKAHEAD);
};

export const stopBGM = () => {
    if (bgmInterval) {
        clearInterval(bgmInterval);
        bgmInterval = null;
    }
};

// ==========================================
// SFX (Existing)
// ==========================================

export const playSuccessSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;
  const now = ctx.currentTime;
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator(); const gain = ctx.createGain();
    osc.type = 'sine'; osc.frequency.setValueAtTime(freq, startTime);
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
    osc.connect(gain); gain.connect(ctx.destination);
    osc.start(startTime); osc.stop(startTime + duration);
  };
  playNote(659.25, now, 0.8);
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;
  const osc = ctx.createOscillator(); const gain = ctx.createGain();
  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);
  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);
  osc.connect(gain); gain.connect(ctx.destination);
  osc.start(); osc.stop(ctx.currentTime + 0.3);
};

export const playVictorySound = () => {
  stopBGM(); 
  const ctx = getAudioContext();
  if (!ctx) return;
  const now = ctx.currentTime;
  const playNote = (freq: number, startTime: number, duration: number, type: OscillatorType = 'triangle') => {
    const osc = ctx.createOscillator(); const gain = ctx.createGain();
    osc.type = type; osc.frequency.setValueAtTime(freq, startTime);
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
    gain.gain.linearRampToValueAtTime(0, startTime + duration);
    osc.connect(gain); gain.connect(ctx.destination);
    osc.start(startTime); osc.stop(startTime + duration);
  };
  playNote(523.25, now, 0.2);
  playNote(659.25, now + 0.15, 0.2);
  playNote(783.99, now + 0.30, 0.2);
  playNote(1046.50, now + 0.45, 0.8, 'sine');

  const bufferSize = ctx.sampleRate * 1; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0); for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
  const noise = ctx.createBufferSource(); noise.buffer = buffer;
  const noiseGain = ctx.createGain();
  noiseGain.gain.setValueAtTime(0.1, now + 0.45);
  noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  noise.connect(noiseGain); noiseGain.connect(ctx.destination);
  noise.start(now + 0.45);
};

export const playShootSound = () => {
  const ctx = getAudioContext(); if (!ctx) return;
  const now = ctx.currentTime;
  const osc = ctx.createOscillator(); const gain = ctx.createGain();
  osc.type = 'square'; osc.frequency.setValueAtTime(800, now);
  osc.frequency.exponentialRampToValueAtTime(100, now + 0.1);
  gain.gain.setValueAtTime(0.05, now); gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);
  osc.connect(gain); gain.connect(ctx.destination);
  osc.start(now); osc.stop(now + 0.1);
};

export const playHitSound = () => {
  const ctx = getAudioContext(); if (!ctx) return;
  const t = ctx.currentTime;
  const bufferSize = ctx.sampleRate * 0.1;
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0); for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
  const noise = ctx.createBufferSource(); noise.buffer = buffer;
  const filter = ctx.createBiquadFilter(); filter.type = 'lowpass';
  filter.frequency.setValueAtTime(1000, t); filter.frequency.linearRampToValueAtTime(100, t + 0.1);
  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0.2, t); gain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);
  noise.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
  noise.start(t);
};

export const playHealSound = () => {
    const ctx = getAudioContext(); if (!ctx) return;
    const t = ctx.currentTime;
    const notes = [523.25, 659.25, 783.99, 1046.50]; 
    notes.forEach((freq, i) => {
        const osc = ctx.createOscillator(); osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, t + i * 0.05);
        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0, t + i * 0.05);
        gain.gain.linearRampToValueAtTime(0.1, t + i * 0.05 + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.05 + 0.3);
        osc.connect(gain); gain.connect(ctx.destination);
        osc.start(t + i * 0.05); osc.stop(t + i * 0.05 + 0.3);
    });
};

export const speakText = (text: string, rate: number = 1.0) => {
  if (!('speechSynthesis' in window)) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US'; utterance.rate = rate; utterance.pitch = 1.15; 
  const voices = window.speechSynthesis.getVoices();
  const preferredNames = ['Samantha', 'Google US English', 'Zira', 'Jenny', 'Susan', 'Vicki', 'Kathy'];
  const femaleVoice = voices.find(v => preferredNames.some(name => v.name.includes(name)) && v.lang.startsWith('en'));
  const fallbackVoice = voices.find(v => v.lang.startsWith('en'));
  if (femaleVoice) { utterance.voice = femaleVoice; } else if (fallbackVoice) { utterance.voice = fallbackVoice; }
  window.speechSynthesis.speak(utterance);
};

