  HERO: 'HERO',
  HERO_IDLE: 'HERO_IDLE',
  HERO_DOWN: 'HERO_DOWN',
  HERO_UP: 'HERO_UP',
  HERO_LEFT: 'HERO_LEFT',
  HERO_RIGHT: 'HERO_RIGHT',
  XP: 'XP',
  SNACK: 'SNACK',
  // Bullet Types
  PROJ_NORMAL: 'PROJ_NORMAL',
  PROJ_FIRE: 'PROJ_FIRE',
  PROJ_ICE: 'PROJ_ICE',
  PROJ_LIGHTNING: 'PROJ_LIGHTNING',
